import type { Item } from './index';

// Catálogo B — "IA en tu software" (100 blueprints). Teaser gratis (beneficio+alcance);
// blueprint completo de pago (1,99 € suelto o en equipo a 3,99 €).
// Reescrito en lenguaje de beneficio de negocio a partir del catálogo técnico original.
export const SOFTWARE: Item[] = [
  {"id":"sw01","catalogo":"software","grupo":"Auditoría de tu software","tema":"Arquitectura e Inspección de Estructuras","titulo":"Un mapa completo de cómo está construido tu software","beneficio":"Sabrás qué patrón de arquitectura sigue tu sistema (o si no sigue ninguno de forma consistente) sin depender de que el desarrollador que lo construyó te lo explique de memoria. Sirve para hablar con nuevos proveedores o candidatos técnicos con un documento común.","alcance":"Documenta la estructura de carpetas y las relaciones de módulos tal como existen hoy; no evalúa si esa arquitectura es la más adecuada para tu negocio ni sustituye una auditoría de un arquitecto humano si el sistema es muy grande o usa microservicios distribuidos en varios repositorios.","precio":1.99,"blueprint":{"quePuedeHacer":"Un agente de código puede recorrer recursivamente el árbol de directorios, identificar convenciones de nombres (controllers/, services/, domain/, infrastructure/), detectar si hay separación por capas (arquitectura limpia/hexagonal) o por funcionalidad (feature-based), y cruzar esa evidencia con los imports reales entre carpetas para confirmar o descartar el patrón aparente.","modo":"Análisis de solo lectura","pasos":["Listar recursivamente la estructura de directorios del repositorio, ignorando node_modules, vendor, dist y carpetas de build.","Clasificar cada carpeta de primer y segundo nivel según convenciones conocidas (MVC, hexagonal, limpia, feature-based, monolito sin capas).","Muestrear los imports/requires de un subconjunto de archivos por carpeta para verificar si las dependencias van en la dirección esperada por el patrón detectado.","Señalar las carpetas que rompen el patrón dominante (por ejemplo, un controlador que importa directamente el driver de base de datos).","Redactar un documento en Markdown con el diagrama de carpetas, el patrón identificado y las excepciones encontradas."],"reglas":["No modificar ni mover ningún archivo del repositorio; el resultado es exclusivamente un documento.","Si la evidencia es mixta o insuficiente para determinar un patrón único, decirlo explícitamente en vez de forzar una clasificación.","No analizar el contenido de archivos de configuración con credenciales; limitarse a nombres de archivo y estructura de imports."],"prompt":"Actúa como arquitecto de software auditando un repositorio que no conoces. Recorre la estructura de directorios completa del proyecto (excluyendo node_modules, vendor, dist, build y .git) y documenta: 1) el árbol de carpetas de primer y segundo nivel con una frase que describa la responsabilidad de cada una, 2) el patrón arquitectónico dominante que reconoces (MVC, arquitectura limpia, hexagonal, feature-based u otro) con la evidencia concreta que lo respalda (rutas de ejemplo, imports característicos), 3) una lista de archivos o carpetas que contradicen el patrón dominante, con la ruta exacta y por qué rompen la convención, y 4) un nivel de confianza (alto/medio/bajo) sobre la clasificación. Entrega el resultado como un documento Markdown titulado 'Mapa de arquitectura' que un desarrollador nuevo en el equipo pueda leer en menos de diez minutos. No propongas cambios ni refactorices nada: este es un ejercicio de documentación, no de intervención."}},
  {"id":"sw02","catalogo":"software","grupo":"Auditoría de tu software","tema":"Arquitectura e Inspección de Estructuras","titulo":"Encuentra dónde arranca realmente tu sistema","beneficio":"Tendrás identificado, con evidencia, el archivo o comando exacto que pone en marcha tu aplicación en cada entorno (desarrollo, producción, tareas en segundo plano), algo básico para cualquier auditoría técnica, migración de proveedor o incidente que requiera reiniciar el servicio con confianza.","alcance":"Identifica los puntos de entrada declarados en la configuración del proyecto (package.json, go.mod, Cargo.toml, Dockerfile, Procfile, etc.); si el proyecto tiene procesos de arranque no documentados en ningún archivo de configuración estándar, el análisis puede no detectarlos y requiere revisión manual.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede leer los archivos de manifiesto del proyecto (package.json 'main'/'scripts', go.mod y su main.go, Cargo.toml '[[bin]]', Dockerfile CMD/ENTRYPOINT, Procfile) y cruzarlos con los archivos reales a los que apuntan para confirmar que existen y trazar la primera cadena de imports que se ejecuta al arrancar.","modo":"Auditoría estática de configuración","pasos":["Identificar el lenguaje/runtime principal del proyecto a partir de los archivos de manifiesto presentes en la raíz.","Leer package.json (scripts 'start'/'dev'/'build'), go.mod junto al archivo con func main(), Cargo.toml, o el manifiesto equivalente.","Revisar Dockerfile, docker-compose.yml y Procfile si existen, para ver si el punto de entrada en producción difiere del de desarrollo.","Verificar que los archivos referenciados existen realmente en el repositorio y abrir las primeras líneas para confirmar que son el arranque real.","Documentar, para cada entorno detectado, el comando exacto y el archivo donde comienza la ejecución."],"reglas":["No ejecutar ningún comando de arranque; el análisis es de lectura de configuración y código, no de ejecución del sistema.","Distinguir explícitamente entre el punto de entrada de desarrollo y el de producción si son distintos.","Si hay múltiples puntos de entrada (por ejemplo, API + worker + cron), listarlos todos por separado, sin asumir que solo hay uno."],"prompt":"Necesito identificar todos los puntos de entrada de este repositorio. Revisa package.json (o el manifiesto equivalente según el lenguaje: go.mod, Cargo.toml, requirements.txt + main), Dockerfile, docker-compose.yml y Procfile si existen. Para cada punto de entrada que encuentres (desarrollo, producción, workers en segundo plano, tareas programadas), indica: el comando exacto que lo lanza, el archivo fuente donde arranca la ejecución, y las primeras dependencias que ese archivo importa. Si detectas que el comando de arranque referencia un archivo que no existe en el repositorio, señálalo como una inconsistencia. Entrega el resultado como una tabla Markdown con columnas: Entorno | Comando | Archivo de arranque | Primeras dependencias importadas | Observaciones. No ejecutes ningún comando, es un análisis puramente de lectura."}},
  {"id":"sw03","catalogo":"software","grupo":"Auditoría de tu software","tema":"Arquitectura e Inspección de Estructuras","titulo":"Localiza los archivos que, si fallan, arrastran a todo el sistema","beneficio":"Identificarás qué módulos concentran tantas dependencias entrantes que un error o un cambio mal hecho ahí podría afectar a gran parte del sistema. Es información clave para decidir dónde poner más cuidado (tests, revisiones) antes de tocar código.","alcance":"Mide concentración de importaciones entrantes dentro del propio código fuente (acoplamiento estructural); no mide disponibilidad de infraestructura (servidores caídos, redes) ni sustituye un análisis de resiliencia en producción.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede construir un grafo de dependencias a partir de las sentencias import/require de todo el código fuente, contar cuántos archivos distintos importan cada módulo (fan-in) y ordenar los resultados para señalar los archivos con mayor concentración de dependientes, es decir, los de mayor acoplamiento estructural.","modo":"Análisis estático de dependencias","pasos":["Recorrer todos los archivos de código fuente y extraer sus sentencias de import/require, incluyendo la ruta resuelta del módulo importado.","Construir un grafo dirigido donde cada arista va del archivo que importa al archivo importado.","Calcular, para cada archivo, el número de archivos distintos que lo importan (fan-in).","Ordenar los archivos de mayor a menor fan-in y quedarse con el percentil superior como candidatos a punto único de fallo.","Para cada candidato, listar ejemplos concretos de los archivos que dependen de él, para dar contexto de impacto."],"reglas":["El resultado es una lista de candidatos ordenada por evidencia de acoplamiento, no una afirmación de que el sistema 'fallará'.","No incluir archivos de configuración, tipos compartidos o constantes triviales como puntos de fallo salvo que concentren lógica real.","No proponer refactorizaciones automáticas; el entregable es diagnóstico, no una intervención en el código."],"prompt":"Analiza este repositorio para encontrar posibles puntos únicos de fallo (single points of failure) a nivel de acoplamiento de código. Recorre todos los archivos fuente, extrae sus imports/requires y construye un conteo de cuántos archivos distintos dependen de cada módulo (fan-in). Dame una lista ordenada de los 10-15 archivos con mayor fan-in, y para cada uno: la ruta del archivo, el número de archivos que lo importan, tres ejemplos concretos de esos archivos dependientes, y una frase explicando qué tipo de lógica concentra (por ejemplo: 'utilidad de formateo de fechas' o 'cliente de base de datos compartido'). No incluyas archivos de constantes o tipos triviales que no tengan lógica real. Este análisis es solo diagnóstico: no modifiques ni refactorices ningún archivo."}},
  {"id":"sw04","catalogo":"software","grupo":"Auditoría de tu software","tema":"Arquitectura e Inspección de Estructuras","titulo":"Antes de tocar una función, entérate de todo lo que se vería afectado","beneficio":"Antes de pedirle a un desarrollador (interno o externo) que cambie la firma de una función, sabrás cuántos archivos y qué partes del sistema dependen de ella. Reduce el riesgo de encargar un cambio que parece pequeño y termina rompiendo otras partes del software.","alcance":"Calcula el impacto por trazabilidad estática de imports y llamadas (quién usa esa función y quién usa a esos, en cascada); no ejecuta el código ni detecta efectos en tiempo de ejecución (por ejemplo, código que llama a la función de forma dinámica o mediante reflexión).","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede localizar todas las llamadas directas a una función o método específico, identificar los archivos que las contienen, y repetir el proceso de forma recursiva sobre esos archivos para estimar cuántos niveles de cascada alcanza un cambio en la firma.","modo":"Análisis de solo lectura sobre un punto de cambio específico","pasos":["Recibir el nombre de la función y el archivo donde está definida.","Buscar en todo el repositorio las llamadas directas a esa función, con la ruta y línea exacta de cada uso.","Para cada archivo que la llama, identificar si el resultado de la llamada se usa de una forma que dependería de la firma actual (número de argumentos, tipo de retorno).","Repetir la búsqueda un nivel más: quién importa a los archivos que llaman a la función, para estimar la cascada de segundo grado.","Producir un informe con el radio de impacto directo (nivel 1) y el impacto indirecto estimado (nivel 2), sin asumir niveles más profundos."],"reglas":["Limitar el análisis de cascada a un máximo de dos niveles de profundidad para mantener el informe verificable a mano; no extrapolar más allá.","Señalar explícitamente las llamadas dinámicas o indirectas (por reflexión, callbacks pasados como variable) que el análisis estático no puede confirmar con certeza.","No modificar la función ni sus llamadas: el entregable es el informe de impacto, la decisión de cambiarla la toma el equipo humano."],"prompt":"Quiero evaluar el 'blast radius' de cambiar la firma de la función [NOMBRE_DE_LA_FUNCION] definida en [RUTA_DEL_ARCHIVO]. Busca en todo el repositorio cada lugar donde se llama a esta función, indicando archivo y número de línea exacto. Para cada llamada, dime si el resultado se usa de una forma que se rompería si cambiara el número de argumentos o el tipo de retorno. Después, para los archivos que llaman directamente a la función, busca quién los importa a ellos, para estimar el impacto de segundo nivel. Entrega un informe con dos secciones: 'Impacto directo' (llamadas de primer nivel) e 'Impacto indirecto estimado' (segundo nivel), y una tercera sección 'Casos que no puedo confirmar con certeza' donde listes llamadas dinámicas, por reflexión o pasadas como callback que no se pueden rastrear de forma estática. No cambies el código, solo genera el informe."}},
  {"id":"sw05","catalogo":"software","grupo":"Auditoría de tu software","tema":"Arquitectura e Inspección de Estructuras","titulo":"Comprueba que ninguna variable secreta falta antes de desplegar","beneficio":"Detectarás variables de entorno que el código espera encontrar en tiempo de ejecución pero que no están documentadas en el archivo de ejemplo del proyecto (o viceversa), evitando el clásico fallo de 'funciona en mi máquina pero no en producción' por una variable olvidada.","alcance":"Compara lo que el código realmente lee (process.env, os.Getenv, os.environ, etc.) contra el archivo .env.example o equivalente; no verifica los valores reales de las variables en cada entorno (eso requeriría acceso a los secretos de producción, fuera del alcance de un análisis de solo código).","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede buscar en todo el código fuente los patrones de acceso a variables de entorno propios del lenguaje (process.env.X en Node, os.Getenv en Go, os.environ.get en Python, System.getenv en Java), extraer los nombres de variable usados, y contrastar esa lista contra las claves declaradas en el archivo .env.example, .env.sample o equivalente del repositorio.","modo":"Auditoría estática de variables de entorno","pasos":["Detectar el patrón de acceso a variables de entorno propio del lenguaje/framework del proyecto.","Buscar en todo el código fuente ese patrón y extraer el nombre literal de cada variable referenciada, junto al archivo y línea donde se usa.","Leer el archivo .env.example (o el equivalente que exista en el repositorio) y extraer la lista de claves declaradas ahí.","Calcular la diferencia en ambas direcciones: variables usadas en código que no están en el archivo de ejemplo, y variables en el archivo de ejemplo que ya no se usan en ningún lugar del código.","Entregar ambas listas con la ruta y línea de cada referencia, para que el equipo pueda decidir si documentar o limpiar."],"reglas":["No mostrar ni inferir el valor real de ninguna variable, solo su nombre y dónde se referencia; nunca leer archivos .env reales con valores de producción.","Distinguir variables con valores por defecto en el propio código (fallback) de las que no lo tienen, porque su ausencia es más crítica.","Si el proyecto no tiene ningún archivo de ejemplo de entorno, indicarlo como hallazgo en sí mismo en vez de fallar silenciosamente."],"prompt":"Audita las variables de entorno de este repositorio. Primero, busca en todo el código fuente los accesos a variables de entorno (según el lenguaje: process.env.X en JavaScript/TypeScript, os.Getenv/os.LookupEnv en Go, os.environ/os.getenv en Python, System.getenv en Java, u otros equivalentes) y construye una lista de cada variable referenciada con su archivo y línea. Segundo, lee el archivo .env.example, .env.sample o equivalente en la raíz del repositorio y extrae las claves que declara. Tercero, compara ambas listas y dame: (a) variables usadas en el código que NO aparecen en el archivo de ejemplo (riesgo de que falten en un despliegue nuevo), y (b) variables que están en el archivo de ejemplo pero ya no se usan en ningún archivo (candidatas a limpieza). Para cada variable del grupo (a), indica si el código tiene un valor por defecto de respaldo o si su ausencia rompería la aplicación. No leas ni muestres el archivo .env real si existe, solo el .env.example; no reveles valores, solo nombres de variables."}},
  {"id":"sw06","catalogo":"software","grupo":"Auditoría de tu software","tema":"Flujo de Datos y Trazabilidad","titulo":"Sigue el camino exacto de cada petición que recibe tu web","beneficio":"Podrás ver, paso a paso, qué ocurre desde que un usuario hace clic hasta que la base de datos responde: qué middlewares se ejecutan, en qué orden, y dónde se valida o transforma el dato. Útil para entender por qué una petición se comporta de forma inesperada o para explicarle el flujo a un nuevo desarrollador.","alcance":"Reconstruye el camino declarado en el código (rutas, middlewares, controladores, capa de acceso a datos) para una ruta HTTP concreta que indiques; no mide tiempos de ejecución reales ni sustituye herramientas de trazado en producción (APM) si el problema es de rendimiento en vivo.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede localizar la definición de una ruta HTTP concreta en el router, identificar la cadena de middlewares registrados (globales y específicos de esa ruta) en el orden en que se ejecutan, seguir la llamada hasta el controlador, y desde ahí hasta la función de acceso a datos o el ORM que toca la base de datos.","modo":"Trazado estático de código","pasos":["Recibir el método HTTP y la ruta a trazar (por ejemplo, POST /api/pedidos).","Localizar la definición de esa ruta en el archivo de enrutamiento del framework usado.","Listar los middlewares que se aplican a esa ruta, distinguiendo los globales de los específicos, en el orden real de ejecución.","Seguir la llamada desde el middleware final hasta la función controladora correspondiente.","Rastrear, dentro del controlador, la primera llamada a la capa de datos (repositorio, ORM, query directa) y el modelo o tabla que toca.","Producir un diagrama de secuencia en texto (paso a paso numerado) con archivo y línea de cada eslabón."],"reglas":["El trazado sigue únicamente el camino síncrono declarado en el código; si hay lógica condicional que bifurca el flujo, documentar ambas ramas por separado en vez de elegir una arbitrariamente.","No ejecutar la petición real ni levantar el servidor: el trazado es por lectura de código, no por observación en tiempo de ejecución.","Si algún eslabón de la cadena no se puede resolver estáticamente (por ejemplo, un middleware cargado dinámicamente por nombre), señalarlo como punto ciego en vez de inventar el resto de la cadena."],"prompt":"Traza el ciclo de vida completo de la petición [MÉTODO] [RUTA] (por ejemplo, POST /api/pedidos) en este repositorio. Localiza dónde se define esta ruta en el router, lista en orden de ejecución todos los middlewares que se le aplican (globales y específicos), sigue la cadena hasta el controlador o handler que la atiende, y desde ahí identifica la primera llamada a la capa de datos (repositorio, ORM o query SQL directa) incluyendo qué tabla o modelo toca. Entrega el resultado como una lista numerada paso a paso, cada paso con la ruta del archivo y el número de línea donde ocurre. Si el flujo se bifurca por una condición (por ejemplo, autenticado vs. no autenticado), documenta ambas ramas por separado. Si algún eslabón no se puede seguir de forma estática (carga dinámica, middleware registrado por nombre en tiempo de ejecución), indícalo explícitamente como un punto ciego en vez de asumir cómo continúa. No ejecutes el servidor ni la petición, es un análisis de código."}},
  {"id":"sw07","catalogo":"software","grupo":"Auditoría de tu software","tema":"Flujo de Datos y Trazabilidad","titulo":"Descubre qué partes de tu código cambian datos por su cuenta","beneficio":"Encontrarás variables globales o compartidas que distintas partes del sistema modifican de forma directa, fuera de los flujos habituales de la aplicación. Este tipo de mutaciones ocultas suele ser la causa de bugs difíciles de reproducir ('a veces pasa, a veces no'), y tenerlas localizadas ayuda mucho a cualquier desarrollador que intente diagnosticarlos.","alcance":"Detecta mutaciones de variables globales, módulos singleton o estado compartido a nivel de código estático; no detecta condiciones de carrera en tiempo de ejecución ni problemas de concurrencia que solo aparecen bajo carga real (para eso hace falta perfilado en producción).","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede localizar declaraciones de variables a nivel de módulo, objetos singleton o estado exportado compartido entre archivos, y luego buscar en todo el código los puntos donde ese estado se reasigna o muta directamente (fuera de una función que lo encapsule con una interfaz clara de lectura/escritura).","modo":"Análisis estático de estado compartido","pasos":["Identificar variables, objetos o módulos que se declaran una vez y se importan/comparten entre múltiples archivos (candidatos a estado global).","Para cada candidato, buscar en todo el repositorio los puntos donde se le asigna un nuevo valor o se mutan sus propiedades directamente.","Clasificar cada mutación según si ocurre dentro de una función/método diseñado para ese propósito (mutación controlada) o de forma dispersa en código no relacionado (mutación oculta).","Priorizar las mutaciones ocultas que ocurren en más de un archivo distinto, porque son las de mayor riesgo de inconsistencia.","Documentar cada hallazgo con la variable, los archivos que la mutan y una recomendación de encapsularla si aplica."],"reglas":["No modificar el código para encapsular el estado; el entregable es la lista de hallazgos, la decisión de refactorizar es del equipo.","Distinguir claramente estado de configuración inmutable (cargado una vez al arranque) de estado que cambia durante la ejecución normal; solo el segundo es relevante para este análisis.","Si el lenguaje/framework usa gestión de estado explícita (Redux, Vuex, un contenedor de dependencias), evaluar las mutaciones dentro de esos sistemas por separado, ya que ahí la mutación es esperada y no oculta."],"prompt":"Busca mutaciones de estado ocultas en este repositorio. Identifica variables, objetos o módulos que se declaran una sola vez pero se comparten (se importan) entre varios archivos distintos: candidatos a estado global o compartido. Para cada uno, encuentra todos los puntos del código donde se le reasigna un valor o se mutan directamente sus propiedades, e indica el archivo y línea de cada mutación. Clasifica cada mutación en dos grupos: 'controlada' (ocurre dentro de una función clara diseñada para modificar ese estado) u 'oculta' (ocurre de forma dispersa en código que no está relacionado directamente con la gestión de ese estado). Prioriza en tu informe las mutaciones ocultas que ocurren desde más de un archivo, porque son las más propensas a causar bugs intermitentes. Si el proyecto usa un gestor de estado explícito (Redux, Vuex, un contenedor de dependencias, etc.), analiza las mutaciones dentro de ese sistema aparte, ya que ahí son parte del diseño y no una anomalía. No modifiques ningún archivo, solo entrega el informe de hallazgos."}},
  {"id":"sw08","catalogo":"software","grupo":"Auditoría de tu software","tema":"Flujo de Datos y Trazabilidad","titulo":"Desata los nudos de dependencias que traban tu código","beneficio":"Localizarás los bucles donde el archivo A depende del B, que depende del C, que vuelve a depender del A. Estos ciclos son una causa habitual de errores de compilación intermitentes, imports que se resuelven como 'undefined' y dificultad para dividir el proyecto en piezas más pequeñas en el futuro.","alcance":"Detecta ciclos de importación a nivel de archivo/módulo mediante análisis estático de imports; no evalúa si un ciclo concreto está causando un bug específico en producción (para eso hace falta reproducir el error real), solo confirma su existencia y su ruta exacta.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede construir el grafo dirigido de imports de todo el código fuente y aplicar detección de ciclos sobre ese grafo (por ejemplo, mediante búsqueda en profundidad) para listar cada bucle de dependencias encontrado con el camino exacto de archivos que lo componen.","modo":"Análisis estático de dependencias","pasos":["Recorrer el código fuente y extraer las sentencias de import/require de cada archivo, resolviendo las rutas a archivos reales del proyecto.","Construir un grafo dirigido de dependencias entre archivos.","Ejecutar un algoritmo de detección de ciclos sobre el grafo para encontrar todos los bucles existentes.","Para cada ciclo, listar la cadena completa de archivos en el orden en que se importan entre sí.","Clasificar los ciclos por tamaño (cuántos archivos involucra) y señalar los más cortos (2-3 archivos) como los de intervención más sencilla."],"reglas":["Reportar únicamente ciclos confirmados por el grafo de imports reales, no relaciones de dependencia inferidas o supuestas.","No romper ni modificar ningún import para 'arreglar' el ciclo; el entregable es el diagnóstico, no la corrección automática.","Si el lenguaje resuelve algunos ciclos de forma segura en tiempo de ejecución (por ejemplo, imports diferidos o lazy), indicarlo para no generar alarma innecesaria sobre ciclos ya mitigados."],"prompt":"Detecta dependencias circulares en este repositorio. Recorre el código fuente, extrae las sentencias de import/require de cada archivo resolviendo la ruta real a la que apuntan, y construye el grafo de dependencias entre archivos. Aplica detección de ciclos sobre ese grafo y lista cada bucle encontrado mostrando la cadena completa de archivos (A importa a B, B importa a C, C importa de nuevo a A). Ordena los resultados de los ciclos más cortos (2-3 archivos, más fáciles de resolver) a los más largos. Si detectas que algún ciclo ya está mitigado en el propio código (por ejemplo, mediante un import diferido, dynamic import o lazy loading), indícalo para no reportarlo como un problema urgente. Entrega el resultado como una lista de ciclos con la cadena de archivos de cada uno y una nota de severidad (corto/largo, mitigado/no mitigado). No modifiques ningún archivo ni intentes romper los ciclos, solo diagnostica."}},
  {"id":"sw09","catalogo":"software","grupo":"Auditoría de tu software","tema":"Flujo de Datos y Trazabilidad","titulo":"Ve exactamente qué datos expone tu API al mundo exterior","beneficio":"Tendrás un listado claro de qué estructura de datos recibe y devuelve cada endpoint de tu API, lo cual es esencial antes de contratar a alguien para construir una app móvil, integrar un partner, o simplemente para saber qué información de tus clientes sale realmente por la red.","alcance":"Extrae la forma de los datos (nombres de campos y tipos) tal como está definida en el código (interfaces, clases DTO, esquemas de validación); no verifica en tiempo real qué se envía en cada petición HTTP real ni detecta campos añadidos dinámicamente en tiempo de ejecución que no estén declarados en el tipo.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede localizar las interfaces, clases o esquemas de validación (DTOs, tipos de request/response, esquemas de Zod/Joi/Pydantic/class-validator) asociados a cada endpoint de la API, extraer sus campos y tipos, y organizarlos endpoint por endpoint.","modo":"Extracción estática de esquemas","pasos":["Identificar el framework de la API y su convención para definir tipos de entrada/salida (interfaces TypeScript, esquemas Zod/Joi, clases con decoradores, serializers, etc.).","Recorrer los archivos de rutas/controladores para listar cada endpoint expuesto (método + ruta).","Para cada endpoint, localizar el DTO o esquema asociado a la petición (request) y a la respuesta (response).","Extraer los campos declarados en cada esquema, con su nombre, tipo y si es obligatorio u opcional.","Consolidar todo en una tabla por endpoint, separando claramente los datos de entrada de los de salida."],"reglas":["Reportar solo los campos declarados explícitamente en el código; si un endpoint construye la respuesta de forma dinámica sin un tipo formal, indicarlo como 'sin esquema declarado' en vez de adivinar los campos.","No incluir valores de ejemplo con datos reales de producción; usar solo nombres y tipos de campo.","Distinguir los campos marcados como sensibles (contraseñas, tokens) si el propio esquema los señala, para que destaquen en el informe."],"prompt":"Extrae los esquemas de datos (DTOs) que expone la API de este repositorio. Recorre los archivos de rutas o controladores para listar cada endpoint (método HTTP + ruta). Para cada uno, localiza el tipo, interfaz o esquema de validación asociado tanto a la petición de entrada como a la respuesta de salida (por ejemplo, interfaces TypeScript, esquemas Zod/Joi, clases con class-validator, serializers de Django/DRF, structs de Go con tags json, etc.), y extrae los campos con su nombre, tipo y si son obligatorios u opcionales. Entrega el resultado como una tabla por endpoint: Endpoint | Campos de entrada (nombre: tipo, oblig/opcional) | Campos de salida (nombre: tipo). Si algún endpoint no tiene un esquema formal declarado y construye la respuesta de forma dinámica en el código, indícalo explícitamente como 'sin esquema declarado' en vez de inventar los campos. Marca visualmente cualquier campo que parezca sensible (contraseña, token, clave) para que destaque en el informe."}},
  {"id":"sw10","catalogo":"software","grupo":"Auditoría de tu software","tema":"Flujo de Datos y Trazabilidad","titulo":"Conecta los hilos invisibles entre las partes de tu sistema","beneficio":"Cuando una parte de tu sistema 'avisa' a otra mediante un evento (por ejemplo, 'pedido creado' dispara el envío de un email), muchas veces esa conexión no es obvia con solo mirar un archivo. Este blueprint conecta quién emite cada evento con quién lo escucha, para que nadie tenga que adivinar el flujo completo leyendo todo el código.","alcance":"Rastrea emisores y receptores de eventos declarados explícitamente en el código (EventEmitter, pub/sub, colas de mensajes con nombre de evento identificable); si los nombres de evento se construyen dinámicamente en tiempo de ejecución (por ejemplo, concatenando variables), el rastreo estático puede no encontrar la conexión y debe señalarse como incierto.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede buscar en el código los patrones de emisión de eventos (emit, publish, dispatch) y de suscripción (on, subscribe, listen, consumer) propios de las librerías de eventos o colas usadas en el proyecto, extraer el nombre literal del evento en cada caso, y emparejar emisores con receptores que comparten el mismo nombre.","modo":"Trazado estático de eventos","pasos":["Identificar qué mecanismo de eventos usa el proyecto (EventEmitter nativo, un bus de eventos propio, una cola como RabbitMQ/SQS/Kafka, WebSockets).","Buscar en todo el código las llamadas que emiten o publican un evento, extrayendo el nombre literal usado y el archivo/línea de origen.","Buscar en todo el código las suscripciones o consumidores que escuchan eventos, extrayendo el nombre literal escuchado y el archivo/línea.","Emparejar cada emisor con su(s) receptor(es) por coincidencia exacta del nombre del evento.","Listar por separado los eventos emitidos sin ningún receptor conocido, y los receptores que escuchan un evento que nunca se emite en el código analizado."],"reglas":["Solo emparejar eventos por coincidencia literal y verificable del nombre; si el nombre se construye dinámicamente (por ejemplo, evento_ + tipo), reportarlo aparte como 'no verificable de forma estática' en vez de adivinar el emparejamiento.","No asumir que un evento sin receptor detectado es necesariamente un error: puede ser manejado por un servicio externo fuera del repositorio analizado; señalarlo como hallazgo a confirmar, no como bug confirmado.","No modificar el código de emisión ni de suscripción; el entregable es el mapa de conexiones."],"prompt":"Traza los eventos asíncronos de este repositorio. Identifica primero qué mecanismo de eventos se usa (EventEmitter de Node, un bus de eventos propio, una cola de mensajes como RabbitMQ/SQS/Kafka, WebSockets u otro). Busca en todo el código: (a) cada punto donde se emite/publica un evento, con el nombre literal del evento y la ruta/línea de origen, y (b) cada punto donde se escucha/consume un evento, con el nombre literal escuchado y la ruta/línea. Empareja los emisores con sus receptores cuando el nombre del evento coincide exactamente. Entrega tres listas: 'Eventos conectados' (emisor -> receptor(es), con archivos y líneas de ambos lados), 'Eventos emitidos sin receptor detectado en este repositorio' (posiblemente consumidos por un servicio externo, indícalo como algo a confirmar, no como error), y 'Eventos escuchados que nunca se emiten en el código analizado'. Si el nombre de algún evento se construye de forma dinámica (concatenación de variables) y no se puede verificar con certeza, ponlo en una cuarta lista aparte de 'no verificable de forma estática'. No modifiques el código."}},
  {"id":"sw11","catalogo":"software","grupo":"Auditoría de tu software","tema":"Ingeniería Inversa y Configuración","titulo":"Un listado completo de cada servicio externo del que depende tu negocio","beneficio":"Sabrás, con evidencia del código, de qué proveedores externos depende tu operación (pasarela de pago, proveedor de email, nube, servicios de analítica) sin tener que confiar en la memoria de nadie. Es el primer documento que necesitas antes de negociar con proveedores, hacer una migración o evaluar riesgo de dependencia de terceros.","alcance":"Localiza integraciones visibles en el código fuente (llamadas a SDKs, URLs de API, claves de configuración con nombre reconocible); no detecta integraciones contratadas a nivel de negocio que no dejan rastro en el código (por ejemplo, un seguro o un proveedor puramente administrativo).","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede buscar en el código las importaciones de SDKs conocidos de terceros (Stripe, PayPal, SendGrid, Twilio, AWS SDK, Google Cloud, etc.), las URLs de API externas embebidas en el código o configuración, y los nombres de variables de entorno que delatan un proveedor concreto (por ejemplo STRIPE_SECRET_KEY), consolidando todo en un inventario.","modo":"Descubrimiento estático de dependencias externas","pasos":["Revisar el archivo de dependencias del proyecto (package.json, go.mod, requirements.txt, Gemfile) para identificar SDKs de terceros conocidos por su nombre de paquete.","Buscar en el código las importaciones de esos paquetes y los puntos donde se instancian o configuran (claves de API, endpoints base).","Buscar además URLs de dominios externos embebidas directamente en el código, aunque no vengan de un SDK instalado.","Revisar nombres de variables de entorno que identifiquen un proveedor concreto por su patrón de nomenclatura.","Consolidar todo en un inventario por categoría: pagos, comunicaciones (email/SMS), nube/infraestructura, analítica, otros."],"reglas":["No mostrar ni intentar leer el valor real de ninguna clave o token de API, solo el nombre de la variable y el proveedor al que corresponde.","Diferenciar integraciones activas en el código de las que están importadas pero no se usan en ningún punto (código muerto), señalando estas últimas aparte.","Si un servicio se usa mediante una URL genérica sin SDK identificable, reportarlo igualmente pero marcado como 'proveedor a confirmar manualmente'."],"prompt":"Haz un inventario de todas las integraciones con servicios de terceros en este repositorio. Primero, revisa el archivo de dependencias (package.json, go.mod, requirements.txt, Gemfile u otro) y marca los paquetes que correspondan a SDKs de proveedores externos conocidos (pasarelas de pago, email/SMS, nube, analítica, autenticación, etc.). Segundo, busca en el código dónde se importan y configuran esos SDKs, y extrae el proveedor y el propósito (por ejemplo, 'Stripe: cobro de suscripciones'). Tercero, busca también URLs de dominios externos embebidas directamente en el código que no vengan de un SDK instalado. Cuarto, revisa los nombres de las variables de entorno usadas para ver cuáles delatan un proveedor concreto por su nomenclatura. Entrega el inventario como una tabla: Proveedor | Categoría (pagos/comunicaciones/nube/analítica/otro) | Dónde se usa (archivo) | Variable de entorno asociada | ¿Se usa activamente o parece código muerto?. No muestres ni intentes deducir el valor real de ninguna clave o token, solo los nombres de las variables."}},
  {"id":"sw12","catalogo":"software","grupo":"Auditoría de tu software","tema":"Ingeniería Inversa y Configuración","titulo":"Revisa que tu aplicación esté empaquetada de forma coherente y segura","beneficio":"Verificarás si la configuración de contenedores de tu aplicación (Docker) tiene inconsistencias básicas: puertos que no coinciden, volúmenes mal definidos, variables de entorno que faltan entre el Dockerfile y el docker-compose. Es una revisión rápida antes de confiar el despliegue a un nuevo proveedor de hosting o a un desarrollador nuevo.","alcance":"Revisa la configuración declarada en Dockerfile y docker-compose.yml en busca de inconsistencias estructurales; no evalúa el rendimiento real de los contenedores en producción ni sustituye un escaneo de vulnerabilidades de la imagen base (para eso se necesita una herramienta especializada de seguridad de contenedores).","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede leer el Dockerfile y el/los docker-compose.yml del proyecto, extraer los puertos expuestos, volúmenes montados, redes definidas y variables de entorno referenciadas en cada uno, y contrastarlos entre sí para detectar discrepancias (por ejemplo, un puerto que la app usa internamente pero que no está expuesto en compose).","modo":"Auditoría estática de configuración de contenedores","pasos":["Leer el Dockerfile y extraer: imagen base, puertos con EXPOSE, variables de entorno con ENV/ARG, y el comando de arranque (CMD/ENTRYPOINT).","Leer cada docker-compose.yml presente y extraer los servicios definidos, sus puertos mapeados, volúmenes, redes y variables de entorno (incluyendo las referenciadas desde un archivo .env).","Contrastar el puerto que la aplicación usa según su código o configuración interna contra el puerto expuesto/mapeado en Docker.","Verificar que las variables de entorno que el Dockerfile o compose declaran como necesarias coincidan con las que el código realmente usa (ver también el blueprint de auditoría de variables de entorno).","Revisar los volúmenes montados para detectar si hay rutas que probablemente deberían persistir datos (bases de datos, uploads) pero no tienen volumen asociado.","Documentar cada inconsistencia encontrada con la línea exacta del archivo de configuración implicado."],"reglas":["No evaluar la seguridad de la imagen base (vulnerabilidades conocidas del sistema operativo o paquetes); eso requiere una herramienta de escaneo de imágenes, fuera de este alcance.","No ejecutar docker build ni docker-compose up; el análisis es de lectura de los archivos de configuración.","Señalar por separado las inconsistencias que impedirían el arranque (crítico) de las que son solo buenas prácticas no aplicadas (recomendación)."],"prompt":"Audita la configuración de Docker de este repositorio. Lee el Dockerfile y extrae: imagen base, puertos con EXPOSE, variables ENV/ARG, y el comando de arranque. Lee también cada docker-compose.yml presente y extrae los servicios, puertos mapeados, volúmenes, redes y variables de entorno (incluyendo las que vengan de un archivo .env referenciado). Contrasta: (a) si el puerto que la aplicación usa según su código coincide con el expuesto/mapeado en Docker, (b) si las variables de entorno que el código necesita (según sus llamadas a variables de entorno) están todas declaradas en el compose o en el .env de ejemplo, y (c) si hay rutas que probablemente necesiten persistencia (carpetas de base de datos, uploads de usuarios) pero no tienen un volumen montado. Entrega el resultado como dos listas separadas: 'Inconsistencias críticas' (probablemente impiden que la app arranque o funcione correctamente) y 'Recomendaciones' (buenas prácticas no aplicadas, como falta de un usuario no-root o falta de healthcheck). Cita la línea exacta del archivo para cada hallazgo. No ejecutes ningún comando de Docker, solo lee los archivos de configuración."}},
  {"id":"sw13","catalogo":"software","grupo":"Auditoría de tu software","tema":"Ingeniería Inversa y Configuración","titulo":"Entiende qué hace cada comando que usan tus desarrolladores a diario","beneficio":"Tendrás traducido a lenguaje llano qué hace cada comando de automatización que tu equipo técnico usa (compilar, testear, desplegar), sin necesidad de leer scripts de shell o Makefiles tú mismo. Útil para entender qué pasos exactos sigue el equipo antes de lanzar algo a producción.","alcance":"Explica lo que los scripts declaran hacer, leyendo su contenido; no verifica que esos scripts se ejecuten correctamente en la práctica ni detecta si el equipo realmente los usa (para eso haría falta revisar el historial de uso o preguntar directamente).","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede leer el Makefile, los scripts de package.json, o carpetas de scripts (scripts/, bin/) del proyecto, y traducir cada tarea definida a una explicación en lenguaje llano de qué hace, qué herramientas invoca y en qué orden.","modo":"Documentación automática de scripts","pasos":["Localizar todos los archivos de automatización del proyecto: Makefile, sección 'scripts' de package.json, carpeta scripts/ o bin/, archivos de tareas de otros gestores (Taskfile, justfile).","Listar cada tarea/comando definido con su nombre exacto tal como se invoca.","Leer el contenido de cada tarea y descomponerla en los pasos que ejecuta en orden (por ejemplo: 'instala dependencias, luego compila TypeScript, luego copia assets estáticos').","Identificar qué herramientas externas invoca cada tarea (compiladores, linters, frameworks de test, CLIs de despliegue).","Agrupar las tareas por propósito (desarrollo local, testing, build, despliegue, mantenimiento) para facilitar la lectura."],"reglas":["Describir únicamente lo que el script declara hacer según su contenido; no asumir que se ejecuta con éxito ni que está actualizado respecto al resto del proyecto.","Si una tarea invoca a otra tarea internamente, seguir la cadena y explicarla completa en vez de detenerse en el primer nivel.","No ejecutar ninguno de los scripts durante el análisis; el objetivo es documentación, no verificación en vivo."],"prompt":"Documenta en lenguaje llano todos los scripts de automatización de este repositorio. Localiza el Makefile, la sección 'scripts' de package.json, y cualquier carpeta scripts/ o bin/, así como archivos Taskfile o justfile si existen. Para cada tarea o comando definido, explica en una o dos frases qué hace, qué herramientas externas invoca (compilador, linter, test runner, CLI de despliegue, etc.) y en qué orden ejecuta sus pasos internos. Si una tarea llama internamente a otra tarea, sigue la cadena completa y explícala también. Agrupa el resultado en categorías: 'Desarrollo local', 'Testing', 'Build/compilación', 'Despliegue' y 'Mantenimiento/otros'. Entrega el resultado como un documento Markdown con el nombre exacto de cada comando (tal como se invoca, por ejemplo make build o npm run test) seguido de su explicación. No ejecutes ninguno de los scripts, solo léelos y documenta lo que declaran hacer."}},
  {"id":"sw14","catalogo":"software","grupo":"Auditoría de tu software","tema":"Ingeniería Inversa y Configuración","titulo":"Descubre si tu sistema te avisaría a tiempo cuando algo falla","beneficio":"Sabrás qué partes de tu aplicación registran información (logs) cuando algo pasa y cuáles son una 'caja negra' silenciosa. Esto es clave para saber si, ante un problema en producción, tu equipo podrá diagnosticarlo rápido o tendrá que adivinar a ciegas.","alcance":"Evalúa la densidad y ubicación de las instrucciones de registro (logging) presentes en el código; no mide si esos logs realmente se están recolectando y revisando en producción (para eso se necesita acceso al sistema de monitorización real, como un dashboard de logs).","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede buscar en el código las llamadas a funciones de logging (console.log, logger.info/warn/error, log.Println, logging.getLogger, etc.) y contarlas por módulo, prestando atención especial a si los bloques que manejan errores (catch, except, if err != nil) registran algo o simplemente los ignoran o los propagan en silencio.","modo":"Auditoría estática de logging","pasos":["Identificar la librería o mecanismo de logging que usa el proyecto (nativo del lenguaje o una librería como winston, pino, zap, logrus, logging de Python).","Contar las llamadas de logging por carpeta/módulo para tener una idea de la densidad relativa de instrumentación.","Localizar todos los bloques de manejo de errores (try/catch, except, comprobaciones de error explícitas) del código.","Para cada bloque de manejo de errores, verificar si registra el error (con detalle suficiente para diagnosticar) o si lo descarta/propaga sin dejar rastro.","Señalar las rutas críticas (autenticación, pagos, escritura a base de datos) que tengan baja densidad de logging o manejo de errores silencioso, como prioridad de revisión."],"reglas":["No inventar un umbral numérico de 'cuántos logs son suficientes'; el informe describe la situación relativa (módulos con más o menos instrumentación que el resto del proyecto) sin fijar una cifra objetivo arbitraria.","Distinguir logs de depuración temporal (que probablemente deberían eliminarse) de logs estructurados pensados para producción.","No añadir ni modificar ninguna instrucción de logging en el código; el entregable es el diagnóstico."],"prompt":"Audita la observabilidad de este repositorio a través de sus logs. Identifica qué mecanismo de logging usa el proyecto (console.log nativo, o una librería como winston, pino, zap, logrus, el módulo logging de Python, etc.). Cuenta las llamadas de logging por carpeta o módulo para ver dónde hay más y menos instrumentación relativa. Después, localiza todos los bloques de manejo de errores (try/catch, except, comprobaciones explícitas de error) y verifica para cada uno si registra el error con detalle suficiente para diagnosticarlo, o si lo descarta o propaga en silencio sin dejar rastro. Señala especialmente las rutas relacionadas con autenticación, pagos o escritura a base de datos que tengan manejo de errores silencioso, ya que son las de mayor riesgo si fallan sin dejar evidencia. Entrega el resultado como: (1) un resumen de densidad de logging por módulo, (2) una lista de bloques de manejo de errores que no registran nada, con archivo y línea, ordenados por criticidad del área que afectan, y (3) una nota distinguiendo logs que parecen de depuración temporal (candidatos a limpiar) de logs estructurados para producción. No modifiques el código, solo diagnostica."}},
  {"id":"sw15","catalogo":"software","grupo":"Auditoría de tu software","tema":"Ingeniería Inversa y Configuración","titulo":"Aísla las reglas reales de tu negocio, separadas del código técnico","beneficio":"Podrás ver, en un solo documento, cuáles son las reglas de negocio puras de tu empresa (cómo se calcula un descuento, cuándo se aprueba un crédito, qué hace que un pedido sea válido) sin el ruido del código técnico de infraestructura (conexiones a base de datos, manejo de servidores). Es la forma más rápida de auditar si la lógica de tu negocio está bien reflejada en el software.","alcance":"Identifica y extrae funciones/módulos que contienen reglas de negocio con poca o ninguna dependencia de infraestructura; en sistemas donde la lógica de negocio está mezclada de forma profunda con el código de acceso a datos (sin ninguna separación), la extracción será parcial y debe presentarse como tal, no como una lista exhaustiva.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede recorrer el código buscando funciones y clases que no importan directamente clientes de base de datos, frameworks web o SDKs de infraestructura, y que en cambio operan sobre estructuras de datos ya cargadas en memoria aplicando condiciones, cálculos o validaciones; esas son candidatas a lógica de dominio pura.","modo":"Extracción estática de reglas de negocio","pasos":["Recorrer el código fuente e identificar qué archivos importan directamente drivers de base de datos, frameworks HTTP o SDKs de servicios externos (candidatos a capa de infraestructura).","Por descarte, identificar los archivos/funciones que no tienen esas dependencias directas y que manipulan datos ya en memoria con condicionales, cálculos o validaciones (candidatos a lógica de dominio).","Para cada candidato de dominio, extraer un resumen en lenguaje llano de la regla de negocio que implementa (por ejemplo: 'un pedido se considera urgente si supera cierto monto o el cliente tiene el plan premium').","Señalar los casos donde la lógica de negocio está mezclada directamente con código de infraestructura (por ejemplo, un cálculo de descuento dentro de la misma función que hace la consulta SQL), como área de atención.","Consolidar el resultado en un catálogo de reglas de negocio agrupado por área funcional (pedidos, usuarios, pagos, etc.)."],"reglas":["Presentar el catálogo como lo que es: una extracción basada en separación estructural del código, no una certificación de que ahí están todas las reglas de negocio de la empresa (puede haber reglas en la cabeza de las personas que nunca se codificaron).","Cuando la lógica de negocio esté mezclada con infraestructura sin separación clara, decirlo explícitamente en vez de forzar una extracción limpia que no existe en el código real.","No modificar ni reorganizar el código para separar la lógica; el entregable es el catálogo de lo que existe hoy."],"prompt":"Extrae el catálogo de lógica de negocio (dominio) de este repositorio, separándola del código de infraestructura. Primero, identifica qué archivos importan directamente drivers de base de datos, frameworks HTTP o SDKs externos (código de infraestructura). Por descarte, identifica funciones y módulos que no dependen directamente de eso y que en cambio aplican condiciones, cálculos o validaciones sobre datos ya en memoria (candidatos a lógica de dominio pura). Para cada candidato relevante, escribe en una frase la regla de negocio que implementa en lenguaje llano, con la ruta del archivo. Agrupa el catálogo resultante por área funcional del negocio (por ejemplo: pedidos, usuarios, pagos, inventario). Señala aparte, en una sección 'Lógica mezclada con infraestructura', los casos donde detectes una regla de negocio (cálculo, validación, condición) escrita dentro de la misma función que hace una consulta a base de datos o una llamada HTTP, sin separación. Sé honesto si la separación entre dominio e infraestructura es débil en este proyecto: en ese caso, dilo explícitamente en vez de forzar un catálogo artificialmente limpio. No modifiques ni reorganices el código."}},
  {"id":"sw16","catalogo":"software","grupo":"Auditoría de tu software","tema":"Documentación Automatizada de Código","titulo":"Una documentación de tu API que coincide de verdad con tu código","beneficio":"En vez de mantener una documentación de API separada del código (que casi siempre queda desactualizada), tendrás una generada directamente leyendo los controladores reales: qué endpoints existen, qué reciben y qué devuelven, tal como están hoy en el software.","alcance":"Documenta los endpoints tal como están implementados en el código analizado en el momento del análisis; no sustituye una especificación OpenAPI mantenida y versionada de forma continua, y quedará desactualizada en cuanto el código cambie si no se vuelve a ejecutar.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede recorrer los archivos de rutas/controladores de la API, extraer método HTTP, ruta, parámetros esperados (query, path, body), el esquema de respuesta cuando existe, y los códigos de estado HTTP que la función puede devolver según su propio código, para producir una referencia de API legible.","modo":"Documentación automática de API","pasos":["Recorrer los archivos de rutas/controladores y extraer cada endpoint con su método HTTP y ruta.","Para cada endpoint, identificar los parámetros que espera (de la URL, de query string, y del cuerpo de la petición), con su tipo si está declarado.","Identificar el esquema o tipo de la respuesta exitosa, y los distintos códigos de estado HTTP que el propio código puede llegar a devolver (incluyendo casos de error).","Detectar si el endpoint requiere autenticación revisando si pasa por un middleware de auth conocido.","Redactar una entrada de documentación por endpoint en un formato de referencia estándar (similar a una página de OpenAPI/Swagger en texto)."],"reglas":["Basar la documentación exclusivamente en lo que el código realmente implementa hoy, no en comentarios o documentación previa que pueda estar desactualizada respecto al código.","Marcar explícitamente que el documento es una fotografía del momento del análisis y debe regenerarse tras cambios relevantes en la API, no un documento vivo automático.","Si un endpoint tiene lógica de respuesta muy dinámica que no permite determinar un esquema fijo, describirlo como 'respuesta variable' en vez de inventar una forma fija."],"prompt":"Genera documentación de referencia de la API de este repositorio, leyendo directamente el código de las rutas/controladores (no comentarios ni documentación previa que puedan estar desactualizados). Para cada endpoint, extrae: método HTTP y ruta, parámetros esperados (de la URL, query string y cuerpo de la petición) con su tipo si está declarado, si requiere autenticación (revisa si pasa por un middleware de auth conocido), el esquema de la respuesta exitosa, y los distintos códigos de estado HTTP que el código puede devolver (incluyendo casos de error, con la condición que los provoca). Entrega el resultado en formato de referencia de API (un bloque Markdown por endpoint, con secciones claras: Método y ruta / Autenticación / Parámetros / Respuesta / Códigos de estado posibles). Si un endpoint construye su respuesta de forma tan dinámica que no se puede fijar un esquema estable, indícalo como 'respuesta variable' en vez de inventar una forma fija. Añade al inicio del documento una nota indicando la fecha de generación y que refleja el estado del código en ese momento, no un contrato garantizado a futuro."}},
  {"id":"sw17","catalogo":"software","grupo":"Auditoría de tu software","tema":"Documentación Automatizada de Código","titulo":"Rellena los huecos de documentación que nadie tuvo tiempo de escribir","beneficio":"Las funciones más complejas de tu software (las que tienen varios parámetros, tipos anidados o lógica poco obvia) recibirán una explicación clara de qué hace cada parámetro y qué devuelven, sin que tengas que esperar a que un desarrollador encuentre tiempo para documentarlas manualmente.","alcance":"Genera comentarios de documentación (docstrings/JSDoc) inferidos a partir de la firma y el cuerpo real de la función; la calidad de la explicación depende de que el nombre de variables y la lógica sean razonablemente claros. Sobre código muy confuso o mal nombrado, el resultado puede necesitar revisión humana antes de darlo por bueno.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede identificar funciones con firmas complejas (múltiples parámetros, tipos genéricos, objetos anidados) que carecen de comentario de documentación, leer su cuerpo para entender qué hace cada parámetro y qué representa el valor de retorno, y generar un bloque de documentación en el formato estándar del lenguaje (JSDoc, docstring de Python, Godoc, Javadoc).","modo":"Documentación automática de código","pasos":["Recorrer el código fuente y localizar funciones/métodos públicos que no tengan ya un comentario de documentación.","Priorizar aquellas con firmas complejas: tres o más parámetros, tipos genéricos, objetos con propiedades anidadas, o parámetros opcionales con valores por defecto no evidentes.","Leer el cuerpo de cada función priorizada para entender el propósito real de cada parámetro y qué representa lo que devuelve.","Generar el bloque de documentación en el formato nativo del lenguaje del proyecto (JSDoc, docstring, Godoc, Javadoc, etc.), incluyendo una descripción de la función, cada parámetro y el retorno.","Insertar el bloque generado directamente encima de la función correspondiente, sin modificar el código de la función en sí."],"reglas":["No modificar la lógica ni la firma de ninguna función, únicamente añadir el bloque de comentario de documentación encima.","Si el propósito de un parámetro no se puede determinar con confianza razonable a partir del nombre y el uso en el cuerpo, marcarlo con una nota tipo '(propósito no evidente, revisar con el autor original)' en vez de inventar una descripción.","Respetar el formato de documentación ya usado en el resto del proyecto si existe una convención establecida, en vez de introducir un estilo distinto."],"prompt":"Documenta las funciones con tipado complejo de este repositorio que actualmente no tienen comentario de documentación. Recorre el código y prioriza funciones/métodos públicos con tres o más parámetros, tipos genéricos, objetos anidados, o parámetros opcionales cuyo propósito no sea obvio por el nombre. Para cada una, lee su cuerpo completo para entender qué hace realmente cada parámetro y qué representa el valor de retorno, y genera un bloque de documentación en el formato nativo del lenguaje del proyecto (JSDoc para JavaScript/TypeScript, docstring para Python, Godoc para Go, Javadoc para Java, etc.), respetando el estilo de documentación que ya se use en otras partes del proyecto si existe uno. Inserta el bloque generado directamente encima de cada función, sin modificar su código ni su firma. Si el propósito de algún parámetro no se puede inferir con confianza razonable del nombre y el uso, escribe en su descripción '(propósito no evidente, revisar con el autor original)' en vez de inventar una explicación. Al final, dame la lista de archivos modificados y cuántas funciones documentaste en cada uno."}},
  {"id":"sw18","catalogo":"software","grupo":"Auditoría de tu software","tema":"Documentación Automatizada de Código","titulo":"Convierte tu lógica más compleja en un diagrama que cualquiera entiende","beneficio":"Los procesos más enredados de tu software (una función con muchas condiciones anidadas, un flujo de aprobación con varios pasos) se traducen a un diagrama visual que puedes enseñarle a alguien sin conocimientos técnicos, o usar para explicarle a un nuevo desarrollador cómo funciona esa parte del sistema.","alcance":"Traduce la lógica ya existente en el código a un diagrama (formato de texto tipo Mermaid, editable después); no simplifica ni corrige la lógica compleja subyacente, solo la representa visualmente tal como está escrita, incluidos sus posibles enredos.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede leer una función o módulo con lógica condicional compleja (múltiples if/else anidados, switch con muchos casos, una máquina de estados implícita) y traducir su flujo de control a un diagrama en sintaxis Mermaid (flowchart o diagrama de secuencia) que represente cada rama y decisión.","modo":"Generación automática de diagramas","pasos":["Recibir el nombre de la función, módulo o flujo de negocio a diagramar.","Leer el código completo de esa función/módulo, incluyendo las funciones que llama directamente si son necesarias para entender el flujo completo.","Identificar cada punto de decisión (condicionales, bucles, cambios de estado) y cada resultado posible de esa decisión.","Traducir la secuencia de decisiones y acciones a sintaxis de diagrama Mermaid (flowchart para lógica condicional, diagrama de secuencia para interacción entre componentes).","Acompañar el diagrama de una leyenda breve que explique cualquier abreviatura o nodo que no sea autoexplicativo."],"reglas":["El diagrama debe representar fielmente la lógica tal como existe en el código, incluidas rutas redundantes o inconsistentes, no una versión idealizada o simplificada de cómo debería funcionar.","Si la función es tan extensa que un solo diagrama resulta ilegible, dividirla en varios diagramas por sub-flujo en vez de forzar un único diagrama saturado.","No modificar el código analizado; el entregable es únicamente el diagrama y su leyenda."],"prompt":"Genera un diagrama de flujo en sintaxis Mermaid para la función/módulo [NOMBRE] ubicado en [RUTA_DEL_ARCHIVO] de este repositorio. Lee el código completo de esa función, incluyendo las funciones que llama directamente si son necesarias para entender el flujo, e identifica cada punto de decisión (condicionales, bucles, cambios de estado) y sus resultados posibles. Traduce esa lógica a un diagrama Mermaid (usa 'flowchart TD' si es lógica condicional, o 'sequenceDiagram' si es interacción entre varios componentes/servicios). El diagrama debe reflejar fielmente la lógica real del código, incluidas rutas redundantes, casos raros o inconsistencias que existan, sin idealizar ni simplificar el comportamiento actual. Si la función es demasiado extensa para un solo diagrama legible, divídela en 2-3 diagramas por sub-flujo, cada uno con su propio título. Acompaña cada diagrama de una leyenda breve en texto explicando cualquier nodo o abreviatura que no sea autoexplicativo. No modifiques el código, solo genera el diagrama."}},
  {"id":"sw19","catalogo":"software","grupo":"Auditoría de tu software","tema":"Documentación Automatizada de Código","titulo":"Un diccionario de los términos propios de tu negocio, extraído del código","beneficio":"Cualquier persona nueva que entre al equipo (técnica o no) podrá entender rápido qué significan los términos específicos de tu negocio tal como los usa tu software, en vez de tener que preguntarle a cada rato a un compañero o adivinar por contexto.","alcance":"Extrae y define términos a partir de los nombres usados de forma recurrente en el código (clases, variables, funciones, tablas); no sustituye un glosario de negocio validado por las personas del área, ya que el código puede usar un término de forma distinta a como lo entiende el negocio, y eso debe verificarse con el equipo.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede recorrer el código en busca de nombres de clases, funciones, variables y tablas que se repiten con frecuencia y no son términos técnicos genéricos (como 'usuario', 'pedido', 'ordenTrabajo', 'planPremium'), agrupar sus apariciones, y construir una definición de cada uno basada en cómo se usa realmente en el código.","modo":"Extracción automática de glosario","pasos":["Recorrer nombres de clases, interfaces, funciones y tablas de base de datos de todo el proyecto.","Filtrar los nombres puramente técnicos y genéricos (get, set, handler, config, util) para quedarse con los términos propios del negocio.","Agrupar las apariciones de cada término candidato y localizar los archivos donde se define o se usa con más contexto (comentarios, validaciones, nombres de campos relacionados).","Redactar una definición breve de cada término basada en cómo el código lo trata (qué propiedades tiene, qué reglas se le aplican, con qué otros términos se relaciona).","Ordenar el glosario alfabéticamente y agrupar términos claramente relacionados bajo una misma entrada cuando aplique (por ejemplo, 'Pedido' y 'EstadoDePedido')."],"reglas":["Marcar cada definición como derivada del uso en el código, no como una definición de negocio validada; recomendar su revisión por alguien del área funcional antes de darla por oficial.","No incluir términos genéricos de programación que no aporten valor de negocio (variables técnicas de infraestructura, utilidades genéricas).","Si un mismo término parece usarse con dos significados distintos en distintas partes del código, señalarlo como una inconsistencia a resolver en vez de fusionar ambos significados en una sola definición."],"prompt":"Construye un glosario de términos de negocio a partir del código de este repositorio. Recorre los nombres de clases, interfaces, funciones y tablas de base de datos de todo el proyecto, y filtra los que sean puramente técnicos o genéricos (get, set, handler, config, util, dto, service sin más contexto) para quedarte solo con los términos propios del negocio (por ejemplo: Pedido, PlanPremium, OrdenDeTrabajo, ClienteMoroso). Para cada término candidato, localiza dónde se define y se usa con más contexto en el código, y redacta una definición breve basada en cómo el código lo trata realmente (qué propiedades tiene, qué reglas o validaciones se le aplican, con qué otros términos se relaciona). Ordena el resultado alfabéticamente en un glosario Markdown. Si detectas que un mismo término parece tener dos significados distintos en distintas partes del código, no los fusiones: señálalo como una inconsistencia a resolver, con ambos usos y sus archivos. Añade una nota al inicio del documento aclarando que estas definiciones están derivadas del uso en el código y deberían ser revisadas por alguien del área de negocio antes de considerarse oficiales."}},
  {"id":"sw20","catalogo":"software","grupo":"Auditoría de tu software","tema":"Documentación Automatizada de Código","titulo":"Un listado de todo lo que tu sistema hace en segundo plano, sin que nadie lo mire","beneficio":"Sabrás qué procesos automáticos corren en tu sistema sin intervención humana (limpiar datos antiguos, enviar recordatorios, sincronizar con un proveedor) y con qué frecuencia, algo que suele perderse de vista con el tiempo y que puede generar sorpresas si nadie sabe que existen.","alcance":"Localiza tareas programadas declaradas en el código o en configuración del proyecto (cron jobs, tareas programadas de un framework, workers periódicos); no detecta tareas programadas configuradas fuera del repositorio (por ejemplo, directamente en el crontab de un servidor o en un panel de un proveedor cloud) salvo que su configuración esté versionada en el propio código.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede buscar en el código las declaraciones de tareas programadas propias del framework o librería usada (node-cron, un decorador @Cron, un archivo crontab versionado, un scheduler de un framework como Laravel o Django), extraer su expresión de frecuencia y traducirla a lenguaje llano, junto con qué función ejecuta cada una.","modo":"Documentación automática de tareas programadas","pasos":["Identificar el mecanismo de tareas programadas usado en el proyecto (librería de cron en el código, archivo crontab versionado, scheduler de un framework, configuración de un servicio cloud declarada como código).","Buscar en el código todas las declaraciones de tareas programadas y extraer su expresión de frecuencia (cron expression o equivalente).","Traducir cada expresión de frecuencia a lenguaje llano (por ejemplo, '0 3 * * *' -> 'todos los días a las 3:00 de la madrugada').","Para cada tarea, identificar la función que ejecuta y resumir en una frase qué hace esa función.","Consolidar todo en una tabla ordenada por frecuencia, de las que corren más seguido a las más esporádicas."],"reglas":["Aclarar explícitamente que el listado cubre solo tareas programadas declaradas en el código del repositorio, y que puede haber tareas configuradas fuera de él (en un servidor o panel de proveedor) que este análisis no puede ver.","No ejecutar ninguna de las tareas encontradas durante el análisis.","Si una tarea llama a una función muy compleja, resumir su propósito en una frase sin necesidad de documentar toda su lógica interna (para eso existe el blueprint de documentación de tipado complejo)."],"prompt":"Documenta todas las tareas programadas (cron jobs / scheduled tasks) declaradas en este repositorio. Identifica el mecanismo usado (una librería de cron en el código como node-cron, un archivo crontab versionado en el repositorio, el scheduler de un framework como Laravel, Django o Spring, o configuración de tareas periódicas de un servicio cloud declarada como código). Busca todas las declaraciones de tareas programadas, extrae su expresión de frecuencia y tradúcela a lenguaje llano (por ejemplo, '0 3 * * *' se traduce como 'todos los días a las 3:00 de la madrugada'). Para cada tarea, identifica qué función ejecuta y resume en una frase qué hace esa función. Entrega el resultado como una tabla: Tarea | Frecuencia (expresión + lenguaje llano) | Función que ejecuta | Qué hace (resumen) | Archivo. Ordena la tabla de las tareas más frecuentes a las más esporádicas. Incluye al final una nota aclarando que este listado cubre solo lo declarado en el código del repositorio, y que pueden existir tareas configuradas directamente en un servidor o en el panel de un proveedor cloud que no son visibles desde aquí. No ejecutes ninguna tarea."}},
  {"id":"sw21","catalogo":"software","grupo":"Auditoría de tu software","tema":"Seguridad y Cumplimiento Estático","titulo":"Encuentra contraseñas y llaves olvidadas dentro de tu propio código","beneficio":"Detectarás si alguna contraseña, token de API o llave privada quedó escrita directamente en el código fuente en algún momento, en vez de estar en un lugar seguro (variables de entorno, gestor de secretos). Es una de las revisiones de seguridad más básicas y más rentables que puedes hacer.","alcance":"Detecta patrones de texto que suelen corresponder a secretos (formato de claves conocidas, asignaciones sospechosas de tipo password=, api_key=, etc.) en el código fuente actual; no garantiza encontrar el 100% de los secretos (algunos pueden estar ofuscados o en formatos no reconocidos) ni revisa el historial completo de git, donde un secreto ya eliminado del código actual puede seguir existiendo en commits antiguos.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede escanear todo el código fuente en busca de patrones característicos de secretos (formato de claves de AWS, tokens con prefijos reconocibles como los de Stripe o GitHub, asignaciones de variables con nombres como password/secret/api_key/token seguidas de una cadena literal) y listar cada coincidencia con su ubicación exacta, sin exponer el valor completo del secreto encontrado.","modo":"Escaneo estático de secretos","pasos":["Definir los patrones a buscar: formatos de claves conocidas de proveedores comunes (AWS, Stripe, GitHub, Google), y patrones genéricos de asignación (password/secret/token/api_key/private_key seguido de un valor literal entre comillas).","Recorrer todo el código fuente del repositorio (excluyendo dependencias de terceros como node_modules o vendor) aplicando esos patrones.","Excluir del resultado los casos que claramente son ejemplos o placeholders (valores como 'YOUR_API_KEY_HERE', 'xxxxx', o referencias a variables de entorno en vez de valores literales).","Para cada coincidencia real, registrar el archivo y línea, el tipo de secreto que parece ser, y enmascarar el valor mostrando solo los primeros y últimos caracteres.","Priorizar los hallazgos en archivos que probablemente se suban a un repositorio compartido o público sobre los que estén en archivos claramente ignorados por git."],"reglas":["Nunca mostrar el valor completo de un secreto encontrado en el informe; mostrar como máximo los primeros y últimos 2-3 caracteres, el resto enmascarado.","No revisar el historial de commits de git en este blueprint (eso requiere una herramienta especializada de escaneo de historial); limitarse al estado actual del código.","Distinguir claramente los hallazgos de alta confianza (coinciden con el formato exacto de un proveedor conocido) de los de confianza media (coinciden con un patrón genérico de nombre de variable, pero podrían ser un falso positivo)."],"prompt":"Escanea este repositorio en busca de secretos quemados en el código fuente (contraseñas, tokens de API, llaves privadas). Busca dos tipos de patrones: (1) formatos de clave conocidos de proveedores comunes (por ejemplo, claves de AWS que empiezan con AKIA, tokens de GitHub que empiezan con ghp_, tokens de Stripe que empiezan con sk_live_ o sk_test_), y (2) patrones genéricos de asignación de variables con nombres como password, secret, token, api_key o private_key seguidos de un valor literal entre comillas (no una referencia a process.env o variable de entorno equivalente). Excluye del resultado los valores que sean claramente placeholders o ejemplos (como 'YOUR_API_KEY_HERE', 'xxxx', 'changeme'). Para cada coincidencia real, entrega: archivo y línea, tipo de secreto probable, y el valor enmascarado mostrando solo los primeros y últimos 3 caracteres (por ejemplo 'sk_***************3f2'). Clasifica cada hallazgo como 'alta confianza' (coincide con el formato exacto de un proveedor conocido) o 'confianza media' (coincide con un patrón genérico de nombre, podría ser falso positivo). No revises el historial de git, solo el estado actual de los archivos. No incluyas node_modules, vendor ni carpetas de dependencias de terceros."}},
  {"id":"sw22","catalogo":"software","grupo":"Auditoría de tu software","tema":"Seguridad y Cumplimiento Estático","titulo":"Verifica quién puede acceder realmente a cada función de tu sistema","beneficio":"Sabrás, endpoint por endpoint, qué rol o permiso se requiere para usarlo (y cuáles no requieren ninguno), lo cual es esencial para detectar si, por ejemplo, una función pensada solo para administradores quedó accesible para cualquier usuario autenticado por un descuido.","alcance":"Identifica qué mecanismo de control de acceso protege (o no) cada endpoint según lo declarado en el código (middlewares de auth, decoradores de rol, chequeos explícitos); no evalúa si el diseño de permisos en sí es el correcto para el negocio (eso lo debe decidir el equipo), solo si hay endpoints sensibles sin ninguna protección declarada o con protección inconsistente respecto a similares.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede recorrer cada endpoint de la API, verificar si pasa por algún middleware o decorador de autenticación/autorización conocido, extraer qué rol o permiso específico exige si lo tiene, y comparar endpoints de propósito similar entre sí para detectar inconsistencias (por ejemplo, dos endpoints de borrado con distinto nivel de protección).","modo":"Inspección estática de control de acceso","pasos":["Listar todos los endpoints de la API con su método y ruta.","Para cada uno, verificar si pasa por un middleware/decorador de autenticación (usuario debe estar logueado) y cuál es.","Para cada uno, verificar además si pasa por un chequeo de autorización más específico (rol, permiso, propiedad del recurso) y cuál exige exactamente.","Agrupar los endpoints por recurso (por ejemplo, todos los relacionados con 'pedidos') y comparar el nivel de protección entre operaciones similares (leer vs. crear vs. borrar) para detectar inconsistencias.","Señalar con prioridad alta los endpoints que modifican o eliminan datos (POST/PUT/PATCH/DELETE) y no tienen ninguna verificación de autenticación ni autorización detectada."],"reglas":["Reportar solo lo que el código verifica explícitamente; no asumir que la ausencia de un chequeo visible significa necesariamente una vulnerabilidad si existe otra capa de protección fuera del alcance del análisis (por ejemplo, un API gateway externo) - señalarlo como 'sin protección detectada en este repositorio' en vez de 'vulnerable confirmado'.","No probar ni explotar ningún endpoint; el análisis es de lectura de código, no una prueba de penetración.","Priorizar siempre los hallazgos según el tipo de operación (lectura vs. escritura vs. borrado) y la sensibilidad aparente del recurso (datos de pago, datos personales) sobre hallazgos de bajo impacto."],"prompt":"Inspecciona el control de acceso de la API de este repositorio. Lista todos los endpoints con su método y ruta. Para cada uno, verifica: (a) si pasa por algún middleware o decorador de autenticación (requiere que el usuario esté logueado) y cuál es, y (b) si además exige un rol, permiso o verificación de propiedad del recurso más específico, y cuál exactamente exige el código. Agrupa los endpoints por recurso (por ejemplo, todos los de 'pedidos', todos los de 'usuarios') y compara el nivel de protección entre operaciones similares del mismo recurso (leer vs. crear vs. modificar vs. borrar) para detectar inconsistencias, como un endpoint de borrado con menos protección que su endpoint de lectura equivalente. Entrega una tabla: Endpoint | Requiere autenticación (sí/no + middleware) | Requiere rol/permiso específico (cuál) | Nota de inconsistencia si aplica. Marca con prioridad alta cualquier endpoint que modifique o borre datos (POST/PUT/PATCH/DELETE) sin ninguna verificación de autenticación ni autorización detectada en el código. Si no detectas protección en un endpoint, repórtalo como 'sin protección detectada en este repositorio' (podría estar protegido por una capa externa como un API gateway que este análisis no puede ver), no lo afirmes como una vulnerabilidad confirmada. No pruebes ni intentes acceder a ningún endpoint real, es un análisis de código."}},
  {"id":"sw23","catalogo":"software","grupo":"Auditoría de tu software","tema":"Seguridad y Cumplimiento Estático","titulo":"Encuentra los cifrados anticuados que tu sistema todavía usa","beneficio":"Localizarás si tu software todavía usa funciones criptográficas consideradas débiles según estándares actuales (como MD5 o SHA-1) para tareas sensibles como contraseñas o firmas, y podrás decidir con tu equipo técnico si vale la pena migrar a alternativas modernas.","alcance":"Detecta el uso de funciones criptográficas específicas por su nombre en el código (llamadas a librerías estándar de hashing/cifrado); no evalúa la seguridad completa del sistema criptográfico en su conjunto (gestión de llaves, rotación de secretos, protocolos de transporte), que requiere una auditoría de seguridad más amplia.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede buscar en el código las llamadas a funciones de hashing y cifrado (md5, sha1, DES, RC4) de las librerías estándar y de terceros más comunes, identificar el contexto de uso (¿es para contraseñas? ¿para verificar integridad de un archivo no sensible? ¿para firmar tokens?), y señalar cuáles corresponden a usos donde un algoritmo obsoleto representa mayor riesgo.","modo":"Búsqueda estática de criptografía obsoleta","pasos":["Buscar en el código las llamadas a funciones de hashing/cifrado con nombres reconocidos como obsoletos o débiles: MD5, SHA-1, DES, RC4, y variantes en las librerías estándar del lenguaje del proyecto y librerías de terceros comunes.","Para cada coincidencia, extraer el contexto inmediato de la llamada (qué variable se está hasheando/cifrando, para qué se usa después el resultado).","Clasificar el uso según su propósito aparente: almacenamiento/verificación de contraseñas, generación de tokens de sesión, verificación de integridad de archivos, checksums no sensibles, u otro.","Priorizar como críticos los usos en contraseñas y tokens de sesión/autenticación; marcar como de menor urgencia los usos en checksums de archivos donde la colisión no representa un riesgo de seguridad práctico.","Sugerir, para cada caso crítico, la alternativa moderna estándar equivalente (por ejemplo, bcrypt/argon2/scrypt para contraseñas, SHA-256 o superior para integridad) sin implementar el cambio."],"reglas":["No reemplazar automáticamente ninguna función criptográfica en el código; el entregable es el diagnóstico y la sugerencia, la migración la decide y ejecuta el equipo con cuidado (puede requerir invalidar sesiones o contraseñas existentes).","Distinguir claramente los usos críticos (contraseñas, autenticación) de los usos de bajo riesgo (checksums de archivos no sensibles) para no generar alarma desproporcionada.","Basar la clasificación de 'obsoleto' en el consenso técnico estándar de la industria (por ejemplo, MD5 y SHA-1 son ampliamente reconocidos como no aptos para nuevos usos criptográficos), no en preferencias personales."],"prompt":"Busca en este repositorio el uso de funciones criptográficas consideradas obsoletas o débiles (MD5, SHA-1, DES, RC4 y variantes) en las librerías estándar del lenguaje del proyecto y librerías de terceros comunes de cifrado/hashing. Para cada coincidencia, extrae el contexto inmediato: qué dato se está procesando y para qué se usa el resultado después (¿se compara con una contraseña almacenada? ¿se genera un token de sesión? ¿se verifica la integridad de un archivo subido? ¿es un checksum no sensible?). Clasifica cada hallazgo en 'crítico' (contraseñas, tokens de sesión, autenticación) o 'bajo riesgo' (checksums de archivos no sensibles, deduplicación no relacionada con seguridad). Para cada hallazgo crítico, sugiere la alternativa moderna estándar equivalente (bcrypt, argon2 o scrypt para contraseñas; SHA-256 o superior para integridad) sin implementar el cambio tú mismo. Entrega el resultado como una tabla: Archivo y línea | Función usada | Contexto de uso | Clasificación (crítico/bajo riesgo) | Alternativa sugerida. No modifiques ningún archivo ni reemplaces ninguna función, solo diagnostica y sugiere."}},
  {"id":"sw24","catalogo":"software","grupo":"Auditoría de tu software","tema":"Seguridad y Cumplimiento Estático","titulo":"Comprueba si lo que escriben tus usuarios se filtra antes de usarse","beneficio":"Verificarás si los datos que introducen tus usuarios (en formularios, campos de búsqueda, comentarios) pasan por algún filtro de seguridad antes de guardarse o mostrarse, o si viajan directos hacia la base de datos o la pantalla sin ninguna revisión, lo cual es la puerta de entrada más común para ataques como inyección SQL o XSS.","alcance":"Rastrea si los parámetros de entrada de usuario pasan por funciones de sanitización, validación o consultas parametrizadas conocidas antes de llegar a una consulta de base de datos o a una salida HTML; no ejecuta pruebas de penetración reales ni garantiza que el filtro encontrado sea efectivo contra todas las variantes de ataque conocidas (para eso se necesita una prueba de seguridad activa, no solo lectura de código).","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede identificar los puntos donde el código recibe datos directamente del usuario (parámetros de formulario, query string, cuerpo de petición, cabeceras), rastrear el camino de esa variable hasta que se usa en una consulta a base de datos o se renderiza en una respuesta HTML, y verificar si en algún punto de ese camino pasa por una función de sanitización, validación o si la consulta usa parámetros preparados en vez de concatenación directa de strings.","modo":"Auditoría de trazabilidad de inputs","pasos":["Identificar los puntos de entrada de datos del usuario en el código: parámetros de ruta, query string, cuerpo de petición, cabeceras.","Para cada parámetro de entrada relevante, rastrear su uso posterior en el código hasta encontrar dónde se emplea en una consulta a base de datos o en la construcción de una respuesta HTML.","Verificar si la consulta a base de datos usa parámetros preparados/prepared statements o si concatena el valor del usuario directamente en la cadena SQL.","Verificar si el valor que se renderiza en HTML pasa por una función de escape/sanitización conocida del framework, o si se inserta sin procesar (por ejemplo, con innerHTML directo o renderizado sin escape).","Priorizar los hallazgos donde el input llega sin ningún filtro detectado a una consulta SQL o a una salida HTML, distinguiendo ambos tipos de riesgo (inyección SQL vs. XSS)."],"reglas":["El análisis confirma o descarta la presencia de un mecanismo de sanitización/parametrización conocido; no certifica que el sistema esté libre de estas vulnerabilidades en un sentido absoluto, ya que puede haber lógica de filtrado personalizada no reconocida por los patrones buscados.","No ejecutar ataques de prueba (inyecciones reales) contra la aplicación; el análisis es de lectura de código.","Distinguir con claridad los hallazgos de inyección SQL de los de XSS en el informe, porque requieren mitigaciones distintas."],"prompt":"Audita la sanitización de inputs de usuario en este repositorio. Identifica los puntos donde el código recibe datos directos del usuario (parámetros de ruta, query string, cuerpo de la petición, cabeceras). Para cada parámetro relevante, rastrea su uso posterior hasta el punto donde se emplea en una consulta a base de datos o en la construcción de una respuesta HTML. Verifica dos cosas por separado: (1) si las consultas a base de datos usan parámetros preparados/prepared statements/ORM parametrizado, o si concatenan directamente el valor del usuario en la cadena SQL (riesgo de inyección SQL), y (2) si el valor renderizado en HTML pasa por una función de escape del framework (o el framework escapa por defecto), o se inserta sin procesar mediante mecanismos como innerHTML directo o renderizado marcado explícitamente como 'seguro'/'raw' (riesgo de XSS). Entrega dos listas separadas: 'Posible inyección SQL' y 'Posible XSS', cada una con archivo, línea, el parámetro de entrada implicado y una breve explicación del camino que sigue el dato. No ejecutes ningún ataque de prueba ni pruebes inyecciones reales contra la aplicación, es un análisis de lectura de código. Aclara al final que este análisis confirma la ausencia de mecanismos conocidos de sanitización, pero no sustituye una prueba de penetración activa."}},
  {"id":"sw25","catalogo":"software","grupo":"Auditoría de tu software","tema":"Seguridad y Cumplimiento Estático","titulo":"Revisa la configuración de seguridad de las sesiones de tus usuarios","beneficio":"Comprobarás si las cookies que tu sistema usa para mantener a los usuarios conectados tienen activadas las banderas de seguridad básicas (Secure, HttpOnly, SameSite), una revisión rápida que reduce el riesgo de que la sesión de un usuario pueda ser robada o manipulada por otro sitio.","alcance":"Revisa la configuración declarada en el código donde se crean las cookies de sesión; no verifica el comportamiento real en el navegador del usuario final ni evalúa la seguridad completa del mecanismo de sesión (por ejemplo, cómo se generan o rotan los identificadores de sesión), que puede requerir revisión adicional.","precio":1.99,"blueprint":{"quePuedeHacer":"El agente puede localizar en el código los puntos donde se configura la cookie de sesión (llamadas de configuración de sesión del framework, o creación manual de cookies con res.cookie, Set-Cookie, etc.) y verificar si las banderas Secure, HttpOnly y SameSite están presentes y con qué valor, comparando además con lo esperado según si el sitio sirve tráfico HTTPS.","modo":"Auditoría estática de configuración de sesión","pasos":["Localizar en el código dónde se configura el middleware de sesión del framework (por ejemplo, express-session, configuración de sesión de Django/Rails/Laravel) o donde se crean cookies manualmente.","Extraer la configuración declarada para cada cookie relevante: nombre, si tiene la bandera Secure activada, si tiene HttpOnly activada, y el valor configurado para SameSite (Strict, Lax, None, o ausente).","Verificar si el proyecto sirve tráfico bajo HTTPS (revisando configuración de servidor o certificados referenciados) para contextualizar si la ausencia de Secure es más o menos crítica.","Señalar cualquier cookie de sesión o autenticación que no tenga HttpOnly activado (mayor riesgo, ya que permite acceso desde JavaScript) como hallazgo prioritario.","Documentar cada cookie encontrada con su configuración completa y una comparación contra la configuración recomendada estándar."],"reglas":["Basar el hallazgo únicamente en la configuración explícita en el código; si el framework aplica un valor por defecto seguro sin que el código lo declare explícitamente, indicar cuál es ese valor por defecto según la documentación oficial del framework en vez de reportarlo como 'sin configurar' sin más contexto.","No modificar la configuración de las cookies; el entregable es el diagnóstico, y cambiar SameSite puede afectar flujos existentes (login con terceros, iframes) que el equipo debe evaluar antes de aplicar el cambio.","Distinguir las cookies de sesión/autenticación (las más críticas) de otras cookies no sensibles (preferencias de interfaz, por ejemplo), priorizando el informe según esa distinción."],"prompt":"Audita la configuración de seguridad de las cookies de sesión de este repositorio. Localiza dónde se configura el middleware de sesión (por ejemplo, express-session, configuración de sesión de Django, Rails o Laravel) o donde se crean cookies manualmente (res.cookie, Set-Cookie u otro). Para cada cookie de sesión o autenticación que encuentres, extrae la configuración declarada: nombre, si tiene Secure activado, si tiene HttpOnly activado, y el valor de SameSite (Strict, Lax, None, o ausente). Si el código no declara explícitamente alguna de estas banderas, indica cuál es el valor por defecto del framework según su documentación oficial, en vez de reportarlo simplemente como 'sin configurar'. Verifica también si el proyecto está configurado para servir bajo HTTPS, para contextualizar la severidad de una posible ausencia de Secure. Entrega una tabla: Cookie | Secure | HttpOnly | SameSite | Severidad si falta alguna bandera crítica | Archivo y línea de configuración. Prioriza en el informe las cookies de sesión/autenticación por encima de otras cookies no sensibles (como preferencias de interfaz). No modifiques ninguna configuración: cambiar SameSite u otras banderas puede afectar flujos existentes (login con terceros, contenido en iframes) que el equipo debe evaluar antes de aplicar cualquier cambio."}},
  {"id":"sw26","catalogo":"software","grupo":"Mantenimiento del código","tema":"Refactorización de Patrones de Diseño","titulo":"Añadir un producto o canal nuevo ya no obliga a tocar diez archivos distintos","beneficio":"Cuando el negocio lanza una variante nueva (un método de pago, un tipo de notificación, un formato de documento), el equipo técnico modifica un único punto del código en lugar de perseguir cada lugar donde ese objeto se crea a mano. Menos horas de desarrollo y menos riesgo de que alguien olvide un caso al añadir la variante.","alcance":"Detecta y centraliza construcciones repetidas de objetos de una misma familia (mismo tipo base o interfaz) en una fábrica única. No decide qué patrón de negocio conviene ni rediseña la arquitectura completa; si las clases no comparten un contrato real, esto no aplica y forzarlo sería contraproducente. Los cambios deben pasar por revisión humana y por la suite de tests antes de desplegarse.","precio":1.99,"blueprint":{"quePuedeHacer":"Localiza bloques de código donde se instancian manualmente ('new NombreClase()') objetos que pertenecen a una misma familia (comparten interfaz, clase base o un patrón de nombres consistente), y los reemplaza por un patrón Factory: una clase o función centralizada que decide qué instancia crear según un parámetro de entrada.","modo":"Refactor con commit por cambio","pasos":["Escanear el repositorio buscando instancias 'new' de clases que compartan interfaz o clase base.","Agrupar los casos encontrados y verificar que realmente comparten un contrato común antes de tocar nada.","Crear la clase o función Factory en un archivo nuevo, siguiendo la convención de carpetas del proyecto.","Sustituir cada punto de instanciación directa por una llamada a la fábrica, un archivo a la vez.","Ejecutar la suite de tests después de cada sustitución antes de continuar con el siguiente archivo.","Dejar un commit independiente por cada archivo modificado, con mensaje descriptivo del cambio."],"reglas":["No modificar la lógica interna de las clases instanciadas, solo el punto donde se crean.","No agrupar en una misma fábrica clases que no comparten un contrato real, aunque el nombre se parezca.","Si un constructor tiene efectos secundarios o dependencias ambiguas, detenerse y reportarlo en vez de forzar el cambio."],"prompt":"Analiza el repositorio y localiza todos los puntos donde se instancian con 'new' clases que pertenezcan a la misma familia (mismo tipo base, misma interfaz, o un patrón de nombres claramente relacionado, por ejemplo distintos tipos de notificación o distintos procesadores de pago). Antes de modificar nada, lista en un comentario los archivos y líneas afectadas y confirma que comparten un contrato común. Crea después una clase o función Factory en un archivo nuevo (respetando la convención de carpetas ya usada en el proyecto, por ejemplo 'factories/') que centralice la lógica de selección y creación. Sustituye cada instanciación directa por una llamada a esta fábrica, un archivo a la vez, ejecutando la suite de tests existente después de cada cambio y haciendo un commit individual por archivo con mensaje descriptivo. No alteres la lógica interna de las clases instanciadas ni fusiones clases con contratos distintos. Si encuentras constructores con efectos secundarios o dependencias circulares, detente y repórtalo en vez de forzar el cambio."}},
  {"id":"sw27","catalogo":"software","grupo":"Mantenimiento del código","tema":"Refactorización de Patrones de Diseño","titulo":"Tu código deja de depender de piezas que no puedes reemplazar ni testear","beneficio":"Facilita cambiar un proveedor externo (una pasarela de pago, un servicio de email, una base de datos) sin reescribir la clase que lo usa, y permite probar la lógica de negocio sin depender de servicios reales. Menos bloqueos cuando el negocio decide cambiar de proveedor.","alcance":"Modifica constructores para que reciban las dependencias como parámetro en lugar de crearlas internamente ('new') dentro de la clase. No introduce un contenedor de inyección de dependencias completo si el proyecto no lo tiene ya, ni resuelve problemas de arquitectura más amplios. Requiere revisión humana porque cambia la forma en que se instancian las clases en toda la aplicación.","precio":1.99,"blueprint":{"quePuedeHacer":"Identifica clases que crean sus propias dependencias internamente (bases de datos, clientes HTTP, servicios externos) mediante 'new' dentro del constructor o de sus métodos, y las modifica para que reciban esas dependencias como parámetros del constructor (inyección de dependencias), actualizando los puntos donde se instancia la clase.","modo":"Refactor con commit por cambio","pasos":["Identificar clases donde el constructor o los métodos crean internamente sus dependencias (bases de datos, clientes HTTP, servicios de terceros).","Confirmar qué interfaz o tipo requiere cada dependencia identificada.","Modificar el constructor de la clase para que reciba esas dependencias como parámetros en vez de instanciarlas.","Actualizar todos los puntos donde se crea la clase para que pasen la dependencia correspondiente.","Ejecutar la suite de tests tras cada clase modificada.","Commit independiente por clase modificada."],"reglas":["No introducir un contenedor de inyección de dependencias (framework DI) si el proyecto no usa ya uno.","No cambiar la lógica interna de la dependencia, solo cómo se obtiene.","Cada clase modificada debe compilar y pasar sus tests antes de pasar a la siguiente."],"prompt":"Recorre el repositorio y localiza clases cuyo constructor (u otros métodos) instancian directamente con 'new' sus propias dependencias externas (por ejemplo, un cliente de base de datos, un cliente HTTP, un servicio de terceros). Para cada clase encontrada, modifica el constructor para que reciba esa dependencia como parámetro (inyección por constructor), en vez de crearla internamente. Actualiza todos los puntos del código donde se instancia la clase para que le pasen la dependencia correspondiente. No introduzcas un framework o contenedor de inyección de dependencias si el proyecto no lo usa ya: el objetivo es solo mover la creación del objeto fuera de la clase. Trabaja una clase a la vez, ejecuta la suite de tests después de cada cambio y haz un commit independiente por clase modificada. Si una dependencia se usa en muchos lugares y el cambio afectaría a más de un puñado de archivos, detente y avísame antes de continuar."}},
  {"id":"sw28","catalogo":"software","grupo":"Mantenimiento del código","tema":"Refactorización de Patrones de Diseño","titulo":"Ese if/else interminable deja de crecer cada vez que llega un caso nuevo","beneficio":"Cuando el negocio añade una regla nueva (un descuento, un tipo de cliente, una tarifa), el equipo agrega una pieza aislada en vez de meter otra rama dentro de un condicional gigante que ya nadie entiende del todo. Menos errores al tocar una lógica que afecta a casos que no se querían modificar.","alcance":"Sustituye condicionales extensos (switch largos, if/else anidados) que seleccionan comportamiento por estrategias aisladas y polimórficas. No decide cuál es la regla de negocio correcta en cada rama: solo reorganiza la selección del comportamiento. Los casos con condicionales muy entrelazados con efectos secundarios requieren revisión manual antes de aplicar el cambio.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta bloques 'switch' extensos o cadenas de 'if/else' anidadas que seleccionan un comportamiento distinto según un tipo o valor, y los sustituye por el patrón Strategy: una interfaz común y una clase por cada rama de comportamiento, seleccionadas mediante un mapa o fábrica en vez de un condicional.","modo":"Migración incremental","pasos":["Identificar los condicionales (switch/if-else) más largos o repetidos del repositorio y las ramas de comportamiento que contienen.","Definir una interfaz común que represente el comportamiento variable de esas ramas.","Extraer cada rama del condicional a su propia clase o función que implemente esa interfaz.","Sustituir el condicional original por una selección basada en mapa o registro de estrategias.","Ejecutar los tests existentes y añadir casos para cada rama extraída si no existen.","Migrar un condicional a la vez, con commit independiente por condicional resuelto."],"reglas":["No cambiar el resultado de ninguna rama existente: la extracción debe preservar el comportamiento exacto.","No fusionar ramas distintas en una sola estrategia aunque el código se parezca.","Si una rama del condicional tiene efectos secundarios compartidos con otras ramas, detenerse y reportarlo antes de extraerla."],"prompt":"Busca en el repositorio los bloques 'switch' o cadenas de 'if/else' anidados más largos que seleccionen un comportamiento distinto según un tipo, categoría o valor de entrada. Para el primero que encuentres, define una interfaz común que represente ese comportamiento variable y extrae cada rama del condicional a su propia clase o función que implemente esa interfaz, preservando exactamente el resultado de cada rama. Sustituye el condicional original por una selección basada en un mapa o registro de estrategias (por ejemplo, un objeto que asocie cada tipo con su estrategia). Ejecuta la suite de tests existente y, si no hay cobertura para alguna rama, añade un test que la cubra antes de continuar. Migra un condicional a la vez y haz un commit independiente por cada uno resuelto. Si detectas que dos ramas comparten una variable externa o un efecto secundario cruzado, detente y repórtalo en vez de extraerlas por separado."}},
  {"id":"sw29","catalogo":"software","grupo":"Mantenimiento del código","tema":"Refactorización de Patrones de Diseño","titulo":"Tu código deja de ser una caja negra que solo entiende una persona","beneficio":"Cuando esa persona se va de vacaciones, cambia de proyecto o deja la empresa, el resto del equipo puede seguir trabajando sobre el mismo módulo sin tener que descifrar un archivo de miles de líneas que hace de todo. Reduce el riesgo de dependencia de una sola persona.","alcance":"Divide clases o componentes sobrecargados ('God Objects') que mezclan responsabilidades distintas (por ejemplo, validación, acceso a datos y presentación en un mismo archivo) en archivos especializados, cada uno con una responsabilidad. No resuelve el diseño de negocio detrás de esas responsabilidades ni garantiza que el resultado sea la única forma correcta de dividir el código: el equipo debe validar que la nueva organización tiene sentido para el dominio antes de fusionar.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza clases, componentes o módulos que concentran múltiples responsabilidades no relacionadas (validación, acceso a datos, presentación, notificaciones, etc. en el mismo archivo) y las separa en archivos especializados, cada uno enfocado en una sola responsabilidad, conectados mediante composición en vez de herencia forzada.","modo":"Refactor con commit por cambio","pasos":["Identificar el archivo o clase con mayor número de responsabilidades distintas (mayor cantidad de razones para cambiar).","Listar explícitamente las responsabilidades detectadas dentro de ese archivo antes de tocar el código.","Extraer cada responsabilidad a un archivo o clase propia, con un nombre que refleje su función específica.","Conectar las piezas extraídas mediante composición (una clase que usa a las otras) en lugar de mezclar de nuevo la lógica.","Ejecutar la suite de tests tras cada extracción.","Repetir el proceso con el siguiente archivo sobrecargado, un commit por archivo dividido."],"reglas":["No dividir por dividir: cada archivo nuevo debe tener una responsabilidad clara y nombrable.","No cambiar el comportamiento observable del sistema durante la extracción, solo su organización interna.","Si una responsabilidad no puede aislarse sin tocar otras diez partes del sistema, detenerse y reportarlo como caso que requiere planificación manual."],"prompt":"Revisa el repositorio e identifica la clase, componente o módulo con más responsabilidades mezcladas (por ejemplo, un archivo que valida datos, accede a la base de datos, formatea la respuesta y envía notificaciones, todo junto). Antes de modificar nada, lista explícitamente cada responsabilidad que detectes dentro de ese archivo. Después, extrae cada responsabilidad a su propio archivo o clase, con un nombre que refleje claramente su función, y conecta las piezas resultantes mediante composición (la clase original pasa a usar a las nuevas, no a heredar de ellas). No cambies el comportamiento observable del sistema: el objetivo es solo reorganizar dónde vive cada responsabilidad. Ejecuta la suite de tests después de cada extracción antes de continuar con la siguiente. Trabaja un archivo sobrecargado a la vez y haz un commit independiente por cada división completada. Si una responsabilidad está tan entrelazada con otras que separarla obligaría a tocar más de diez archivos adicionales, detente y repórtalo en vez de forzar la extracción."}},
  {"id":"sw30","catalogo":"software","grupo":"Mantenimiento del código","tema":"Refactorización de Patrones de Diseño","titulo":"Cambiar de base de datos deja de ser un proyecto de meses","beneficio":"Cuando las consultas a la base de datos viven repartidas dentro de los controladores, cualquier cambio de motor de datos, o incluso un ajuste de una consulta, obliga a tocar decenas de archivos. Centralizarlas en una capa de datos permite que el negocio evolucione su base de datos sin reescribir la lógica que la usa.","alcance":"Sustituye consultas directas a base de datos dispersas en controladores por una capa de abstracción (patrón Repositorio) que centraliza el acceso a los datos de una entidad. No migra de motor de base de datos ni optimiza las consultas existentes: solo las reubica y las expone mediante una interfaz consistente. El resultado debe probarse contra datos reales o de staging antes de desplegar, porque una consulta mal trasladada puede alterar resultados.","precio":1.99,"blueprint":{"quePuedeHacer":"Localiza consultas directas a base de datos (SQL embebido, llamadas ORM dispersas) dentro de controladores o capas de presentación, y las extrae a clases 'Repository' dedicadas a una entidad, exponiendo métodos con nombres de negocio (ej. 'buscarClientesActivos') en lugar de consultas crudas repetidas en distintos puntos del código.","modo":"Encapsulamiento con capa de datos","pasos":["Identificar los controladores o archivos con consultas directas a la base de datos (SQL embebido o llamadas ORM sueltas).","Agrupar las consultas por la entidad de datos a la que pertenecen (clientes, pedidos, productos, etc.).","Crear una clase Repository por entidad, con métodos que expongan la intención de negocio de cada consulta.","Mover cada consulta identificada a su método correspondiente en el Repository, preservando exactamente el mismo filtro y resultado.","Sustituir en los controladores la consulta directa por una llamada al método del Repository.","Ejecutar los tests existentes (o pruebas manuales contra datos de staging) tras cada controlador migrado, con un commit independiente por controlador."],"reglas":["No alterar el filtro, orden o forma de los datos que devuelve cada consulta durante la migración.","No mezclar en un mismo Repository consultas de entidades distintas.","Todo el trabajo debe validarse contra una base de datos de prueba o staging antes de considerarse listo para producción."],"prompt":"Analiza el repositorio y localiza los controladores o archivos de presentación que contienen consultas directas a la base de datos (SQL embebido dentro del controlador, o llamadas ORM dispersas fuera de una capa de datos). Agrupa esas consultas por la entidad a la que pertenecen (por ejemplo, clientes, pedidos, productos) y crea una clase Repository por entidad, con métodos cuyo nombre refleje la intención de negocio de la consulta (por ejemplo 'buscarClientesActivos' en vez de una consulta cruda repetida). Mueve cada consulta a su método correspondiente, preservando exactamente el mismo filtro, orden y forma del resultado, y sustituye en el controlador la consulta directa por la llamada al método del Repository. No optimices ni cambies el comportamiento de ninguna consulta durante esta migración: solo reubícala. Trabaja un controlador a la vez, valida el resultado contra una base de datos de prueba o staging, y haz un commit independiente por controlador migrado."}},
  {"id":"sw31","catalogo":"software","grupo":"Mantenimiento del código","tema":"Optimización y Reducción de Deuda Técnica","titulo":"Tu repositorio deja de arrastrar código que nadie usa ni se atreve a borrar","beneficio":"Menos archivos, funciones y variables sin uso significa menos tiempo perdido leyendo código irrelevante al hacer cambios, y menos falsas alarmas sobre dependencias o funciones que ni siquiera se ejecutan. El repositorio se vuelve más fácil de navegar para cualquiera que se incorpore al proyecto.","alcance":"Detecta y elimina funciones, variables, imports y archivos sin referencias activas dentro del repositorio analizado. No detecta código usado dinámicamente (reflexión, imports por string, plugins cargados en tiempo de ejecución) ni código consumido por otros repositorios o servicios externos: esos casos deben confirmarse manualmente antes de borrar. Requiere ejecutar la suite de tests y una revisión humana antes de fusionar, porque una detección de 'código muerto' puede ser un falso positivo.","precio":1.99,"blueprint":{"quePuedeHacer":"Recorre el repositorio buscando funciones, variables, exports e imports que no tienen ninguna referencia activa desde el resto del código, usando análisis estático de referencias, y las elimina (o las marca para revisión si el análisis no puede confirmar con certeza que no se usan).","modo":"Limpieza automática","pasos":["Ejecutar un análisis estático de referencias sobre todo el repositorio para listar funciones, variables e imports sin ninguna referencia activa.","Separar los hallazgos en dos grupos: los que el análisis confirma con certeza que no se usan, y los que dependen de carga dinámica (marcar estos últimos para revisión manual, no borrarlos).","Eliminar primero los imports no utilizados, archivo por archivo.","Eliminar después funciones y variables sin referencias, confirmando que no forman parte de una API pública expuesta a otros proyectos.","Ejecutar la suite de tests completa tras cada lote de eliminaciones.","Hacer un commit por cada carpeta o módulo limpiado, para poder revertir con facilidad si algo se rompe."],"reglas":["No eliminar código marcado como parte de una API pública o exportado explícitamente para consumo externo, salvo confirmación explícita del equipo.","No eliminar nada que se referencie mediante strings dinámicos, reflexión o carga de plugins, sin antes marcarlo para revisión manual.","Ejecutar la suite de tests completa después de cada lote de eliminaciones, no solo al final."],"prompt":"Analiza este repositorio y localiza funciones, variables, exports e imports que no tengan ninguna referencia activa desde el resto del código (usando análisis estático, no solo búsqueda de texto). Antes de borrar nada, sepáralos en dos grupos: los que puedes confirmar con certeza que no se usan en ningún lugar, y los que podrían estar cargados dinámicamente (reflexión, imports por string, plugins) — para este segundo grupo, solo márcalos en un listado para que yo los revise manualmente, no los borres. Elimina primero los imports no utilizados, archivo por archivo, y ejecuta la suite de tests después de cada lote. Después, elimina funciones y variables sin referencias, confirmando antes que no forman parte de una API pública exportada para otros proyectos o servicios. Haz un commit independiente por cada carpeta o módulo limpiado, para poder revertir fácilmente si algo se rompe. No toques ningún archivo de configuración ni nada relacionado con variables de entorno durante esta limpieza."}},
  {"id":"sw32","catalogo":"software","grupo":"Mantenimiento del código","tema":"Optimización y Reducción de Deuda Técnica","titulo":"Esa función de 200 líneas con diez niveles de anidación deja de dar miedo tocarla","beneficio":"Cuando una función tiene demasiadas ramas anidadas, cada cambio nuevo es una apuesta: nadie puede predecir con certeza qué combinación de condiciones se ve afectada. Aplanar la lógica con cláusulas de guarda hace que cada caso se pueda leer y modificar de forma aislada, reduciendo el riesgo de introducir un error al tocar una parte no relacionada.","alcance":"Reescribe algoritmos con anidación profunda de condicionales usando cláusulas de guarda y retornos tempranos, preservando el mismo resultado para cada combinación de entradas. No simplifica la regla de negocio en sí ni decide qué condiciones son innecesarias: solo reorganiza cómo se expresan. Los casos con lógica de negocio ambigua o sin tests que la cubran deben revisarse antes de tocarse.","precio":1.99,"blueprint":{"quePuedeHacer":"Identifica funciones con alta anidación de condicionales (if dentro de if dentro de if) y las reescribe aplicando cláusulas de guarda (early returns) que resuelven primero los casos de salida o error, dejando el camino principal de la función sin anidación, sin alterar el resultado para ninguna combinación de entradas.","modo":"Refactor con commit por cambio","pasos":["Identificar las funciones con mayor nivel de anidación de condicionales en el repositorio.","Para cada función, verificar la cobertura de tests para sus combinaciones de entrada; si no existen, añadir tests que capturen el comportamiento actual antes de tocar nada.","Reescribir la función invirtiendo las condiciones de salida temprana (cláusulas de guarda) para los casos de error o de corte anticipado.","Dejar el camino principal (happy path) de la función al final, sin anidación adicional.","Ejecutar los tests para confirmar que el resultado no cambió para ninguna combinación de entradas.","Commit independiente por función reescrita."],"reglas":["No cambiar el resultado de la función para ninguna combinación de entradas existente; el objetivo es solo la forma, no el comportamiento.","No tocar funciones sin cobertura de tests sin antes añadir tests que capturen su comportamiento actual.","Si la lógica de negocio dentro de la anidación es ambigua o contradictoria, detenerse y reportarlo en lugar de decidir por cuenta propia qué condición prevalece."],"prompt":"Busca en el repositorio las funciones con mayor nivel de anidación de condicionales (if anidados varios niveles de profundidad). Para la función con mayor anidación, primero revisa si existen tests que cubran sus distintas combinaciones de entrada; si no existen, escribe tests que capturen el comportamiento actual antes de modificar el código. Luego reescribe la función aplicando cláusulas de guarda: resuelve primero los casos de error o salida anticipada con retornos tempranos, y deja el camino principal de la función al final, sin anidación adicional. El resultado de la función debe ser exactamente el mismo para cada combinación de entradas que antes del cambio — verifícalo ejecutando los tests. No reinterpretes ni simplifiques la regla de negocio: solo cambia la forma en que se expresa. Si encuentras una condición contradictoria o ambigua dentro de la anidación, detente y repórtala en vez de decidir tú qué comportamiento es el correcto. Trabaja una función a la vez y haz un commit independiente por cada una reescrita."}},
  {"id":"sw33","catalogo":"software","grupo":"Mantenimiento del código","tema":"Optimización y Reducción de Deuda Técnica","titulo":"Cambiar una tarifa o un límite deja de ser una búsqueda de 'a ver dónde puse ese número'","beneficio":"Cuando un número o texto clave (un límite de intentos, una tarifa, un código de estado) está repetido en distintos archivos, cambiarlo implica encontrar cada copia y confiar en no haber dejado ninguna atrás. Centralizarlo en una constante con nombre hace que cambiarlo sea seguro y que cualquiera entienda qué representa ese valor con solo leer su nombre.","alcance":"Reemplaza strings y números literales repetidos o poco explicados ('números mágicos') dispersos en el código por constantes centralizadas y nombradas. No decide cuál es el valor correcto de negocio: solo lo extrae y le da nombre y un único lugar de definición. Valores que aparecen una sola vez y con contexto claro no se tocan, para no añadir indirección innecesaria.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta strings y números literales que se repiten en múltiples archivos o que carecen de contexto claro sobre su significado (códigos de estado, límites, claves de configuración, tasas), y los reemplaza por constantes con nombre descriptivo, centralizadas en un archivo o módulo de constantes.","modo":"Limpieza automática","pasos":["Escanear el repositorio en busca de literales numéricos y de texto que se repitan en más de un archivo, o que aparezcan sin explicación evidente de su significado.","Agrupar los literales encontrados por su significado aparente (límites, tarifas, claves, códigos de estado).","Crear o extender un archivo de constantes con nombres descriptivos para cada grupo.","Sustituir cada aparición del literal por la constante correspondiente, un archivo a la vez.","Ejecutar la suite de tests tras cada archivo modificado.","Commit independiente por archivo migrado a constantes."],"reglas":["No modificar el valor de ningún literal durante la extracción: el número o texto debe seguir siendo exactamente el mismo, solo cambia su forma de referenciarlo.","No extraer literales que aparecen una única vez y con contexto ya claro, para no añadir indirección innecesaria.","Confirmar que dos apariciones del mismo número realmente significan lo mismo antes de unificarlas en una sola constante."],"prompt":"Analiza el repositorio y localiza números y strings literales que se repitan en más de un archivo, o que aparezcan sin ningún contexto claro sobre su significado (por ejemplo, códigos de estado HTTP escritos como número, límites de reintentos, tasas o claves de configuración sueltas en el código). Antes de unificar dos apariciones del mismo valor en una sola constante, confirma que realmente representan el mismo concepto de negocio y no una coincidencia numérica. Crea o extiende un archivo de constantes con nombres descriptivos (por ejemplo 'MAX_INTENTOS_LOGIN' en vez de un '3' suelto) y sustituye cada aparición por la constante correspondiente, sin cambiar el valor. No toques literales que aparecen una sola vez con contexto ya evidente (como un índice de array). Trabaja un archivo a la vez, ejecuta la suite de tests después de cada uno, y haz un commit independiente por archivo migrado."}},
  {"id":"sw34","catalogo":"software","grupo":"Mantenimiento del código","tema":"Optimización y Reducción de Deuda Técnica","titulo":"Los listados que tardan en cargar dejan de depender de bucles escritos a mano","beneficio":"Sustituir bucles imperativos largos por operaciones declarativas del propio lenguaje suele hacer el código más corto y más fácil de leer, y en ciertos casos evita trabajo repetido innecesario. El negocio se beneficia de pantallas y reportes más simples de mantener y, cuando corresponde, de mejor respuesta bajo carga.","alcance":"Transforma bucles imperativos (for, while con acumuladores manuales) en operaciones declarativas equivalentes (map, filter, reduce), cuando el resultado es idéntico. No garantiza una mejora de rendimiento medible en todos los casos: en estructuras muy grandes, el impacto real debe medirse con datos reales, no asumirse. Bucles con efectos secundarios complejos dentro requieren revisión manual antes de tocarse.","precio":1.99,"blueprint":{"quePuedeHacer":"Identifica bucles imperativos que construyen manualmente arrays o acumuladores (for/while con push, contadores, condicionales dentro del bucle) y los reescribe usando operaciones declarativas del lenguaje (map, filter, reduce, find, some/every) cuando esto no cambia el resultado ni introduce efectos secundarios ocultos.","modo":"Refactor con commit por cambio","pasos":["Localizar bucles imperativos que construyen un array, suman un total, o filtran elementos mediante condicionales internos.","Para cada bucle, identificar si tiene efectos secundarios (mutación de variables externas, llamadas asíncronas) que impidan una conversión directa.","Reescribir los bucles sin efectos secundarios usando la operación declarativa equivalente.","Verificar con tests que el resultado es idéntico al del bucle original, incluyendo casos de lista vacía o con un solo elemento.","Medir, si es posible, el comportamiento con datos representativos del entorno real antes de asumir una mejora.","Commit independiente por bucle convertido."],"reglas":["No convertir bucles que contienen efectos secundarios sin antes marcarlos para revisión manual.","Verificar el comportamiento con casos límite (lista vacía, un solo elemento, elementos duplicados) antes de dar por válida la conversión.","No afirmar una mejora de rendimiento sin haberla medido; si no se puede medir, describir el cambio solo como una mejora de legibilidad."],"prompt":"Busca en el repositorio bucles imperativos (for, while) que construyen manualmente un array con 'push', acumulan un total, o filtran elementos con condicionales internos. Para cada bucle encontrado, primero determina si contiene efectos secundarios como mutación de variables externas o llamadas asíncronas dependientes del orden de ejecución — si los tiene, no lo toques y añádelo a una lista de casos para revisión manual. Para los bucles sin efectos secundarios, reescríbelos usando la operación declarativa equivalente del lenguaje (map, filter, reduce, find, some o every, según corresponda), y verifica con tests que el resultado es idéntico al original, incluyendo los casos de lista vacía y de un solo elemento. No afirmes ninguna mejora de rendimiento en el mensaje de commit a menos que la hayas medido con datos representativos; si no la mides, describe el cambio solo como una mejora de legibilidad y mantenibilidad. Trabaja un bucle a la vez y haz un commit independiente por cada conversión."}},
  {"id":"sw35","catalogo":"software","grupo":"Mantenimiento del código","tema":"Optimización y Reducción de Deuda Técnica","titulo":"La lógica de negocio deja de depender de qué hora es o qué hay guardado en otra parte","beneficio":"Una función que solo depende de lo que recibe como argumento (y no de variables externas, del reloj del sistema o de una base de datos) es más fácil de probar, de reutilizar en otro contexto, y de razonar sobre ella sin sorpresas. El negocio gana código que se comporta igual en cada entorno.","alcance":"Extrae lógica algorítmica (cálculos, transformaciones, validaciones) para que dependa únicamente de sus argumentos de entrada, separándola de efectos secundarios (acceso a base de datos, fecha actual, variables globales). No elimina la necesidad de esos efectos secundarios en la aplicación: los mueve a una capa distinta que llama a la función pura con los datos ya obtenidos. No aplica a funciones cuya razón de ser es justamente producir un efecto secundario.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta funciones que mezclan lógica de cálculo o transformación con efectos secundarios (lecturas de base de datos, uso de 'new Date()', variables globales mutables) y separa la parte algorítmica en una función pura que recibe todos los datos necesarios como parámetros, dejando los efectos secundarios en una capa exterior que orquesta la llamada.","modo":"Refactor con commit por cambio","pasos":["Identificar funciones que mezclan cálculo o transformación con efectos secundarios.","Para cada función, listar qué partes son puro cálculo y cuáles son el efecto secundario.","Extraer la parte de cálculo a una nueva función que reciba como parámetros todos los datos que antes obtenía de fuentes externas.","Modificar la función original (o el llamador) para que obtenga esos datos primero y luego invoque a la función pura con ellos.","Añadir o ejecutar tests que verifiquen que la función pura devuelve el mismo resultado para las mismas entradas, sin necesidad de mocks.","Commit independiente por función migrada."],"reglas":["La función resultante no debe leer variables externas, ni el reloj del sistema, ni hacer llamadas de red o de base de datos: solo debe operar sobre sus parámetros.","No aplicar esta extracción a funciones cuya única razón de ser es un efecto secundario (enviar un correo, escribir en disco, registrar un log).","Verificar con tests que la función pura resultante da el mismo resultado que la lógica original antes de reemplazarla en el punto de uso."],"prompt":"Localiza en el repositorio funciones que mezclan lógica de cálculo o transformación de datos con efectos secundarios (por ejemplo, que consultan la base de datos, usan 'new Date()' o 'Date.now()', o leen variables globales mutables dentro del mismo cuerpo de la función). Para cada una, separa la parte de cálculo puro en una nueva función que reciba como parámetros todos los datos que antes obtenía de esas fuentes externas, de forma que su resultado dependa solo de sus argumentos de entrada. Modifica el código que la llama para que obtenga esos datos primero (base de datos, fecha, configuración) y luego invoque a la función pura con ellos. No apliques este cambio a funciones cuya única razón de ser es producir un efecto secundario, como enviar un correo o escribir un archivo. Añade o ejecuta tests que verifiquen que la función pura devuelve el mismo resultado que la lógica original para las mismas entradas, sin necesitar mocks de base de datos ni del reloj del sistema. Trabaja una función a la vez y haz un commit independiente por cada migración."}},
  {"id":"sw36","catalogo":"software","grupo":"Mantenimiento del código","tema":"Migración de Arquitectura de Tipado y Sintaxis","titulo":"Tu editor empieza a avisarte del error antes de que lo vea un cliente","beneficio":"Migrar un archivo de JavaScript a TypeScript permite que el propio editor detecte errores de tipo (pasar un texto donde se espera un número, olvidar un campo obligatorio) antes de que el código llegue a producción. Menos errores de 'undefined is not a function' descubiertos por los usuarios.","alcance":"Migra archivos de JavaScript puro a TypeScript (renombrando a .ts/.tsx), infiriendo interfaces y tipando parámetros y valores de retorno a partir del uso real del código. No garantiza una migración con cero tipos 'any': en código muy dinámico, algunos tipos deben marcarse como pendientes de revisión humana en lugar de forzar un tipo incorrecto. El proyecto debe compilar y pasar sus tests tras cada archivo migrado antes de continuar con el siguiente.","precio":1.99,"blueprint":{"quePuedeHacer":"Convierte archivos '.js/.jsx' a '.ts/.tsx', infiriendo tipos para parámetros de función, valores de retorno y estructuras de datos a partir de cómo se usan en el código, generando interfaces o tipos para las formas de datos detectadas.","modo":"Migración incremental","pasos":["Elegir un archivo JavaScript de bajo riesgo (pocas dependencias, sin lógica crítica) para migrar primero.","Renombrar el archivo a '.ts' o '.tsx' y configurar el proyecto para aceptar ambos formatos durante la transición si aún no lo hace.","Inferir y anotar los tipos de parámetros y retorno de cada función, basándose en cómo se llaman y qué devuelven en el código real.","Crear interfaces o tipos para las estructuras de datos repetidas.","Resolver los errores de compilación que aparezcan, marcando explícitamente como pendiente de revisión cualquier caso donde el tipo correcto no se pueda inferir con certeza.","Ejecutar la suite de tests y confirmar que el archivo compila sin errores antes de pasar al siguiente, con un commit por archivo migrado."],"reglas":["No usar 'any' como solución permanente para evitar un error de compilación: si el tipo no puede inferirse con certeza, usar 'unknown' y dejar un comentario indicando que requiere revisión.","Migrar un archivo a la vez, nunca una carpeta completa de una sola vez, para poder aislar y revertir problemas.","El proyecto debe compilar sin errores y pasar la suite de tests existente después de cada archivo migrado."],"prompt":"Quiero migrar este proyecto de JavaScript a TypeScript de forma incremental. Empieza por identificar un archivo '.js' de bajo riesgo (pocas dependencias externas, sin lógica crítica de negocio) y renómbralo a '.ts' (o '.tsx' si contiene JSX). Infiere y anota los tipos de los parámetros y del valor de retorno de cada función según cómo se usan realmente en el código, y crea interfaces para las estructuras de datos que se repitan con la misma forma en varios lugares. Si en algún punto no puedes inferir el tipo correcto con certeza, usa 'unknown' en vez de 'any' y deja un comentario indicando que ese punto necesita revisión humana — no fuerces un tipo que solo estás adivinando. Resuelve los errores de compilación que surjan tras la migración. Confirma que el proyecto compila sin errores y que la suite de tests existente sigue pasando antes de continuar con el siguiente archivo. Migra un archivo a la vez y haz un commit independiente por cada uno."}},
  {"id":"sw37","catalogo":"software","grupo":"Mantenimiento del código","tema":"Migración de Arquitectura de Tipado y Sintaxis","titulo":"El tipado que promete seguridad deja de tener agujeros donde nadie mira","beneficio":"Cada 'any' en el código es un punto donde el compilador deja de avisar de errores: es tipado que existe solo en apariencia. Reemplazarlo por tipos concretos, uniones o 'unknown' hace que las promesas de seguridad de tipos del proyecto sean reales, no solo nominales.","alcance":"Localiza usos del tipo 'any' en el código TypeScript y los reemplaza por tipos concretos, tipos unión, o 'unknown' cuando el tipo real no puede determinarse con certeza. No elimina 'any' en librerías de terceros sin tipos propios ni fuerza un tipo incorrecto solo para que el compilador no marque error. Requiere que el proyecto compile y pase sus tests tras cada archivo modificado.","precio":1.99,"blueprint":{"quePuedeHacer":"Escanea el código en busca de anotaciones explícitas ':any' y de inferencias implícitas a 'any', determina el tipo real usado en cada caso a partir del código circundante, y lo reemplaza por un tipo concreto, una unión de tipos, o 'unknown' con la validación (type guard) correspondiente.","modo":"Refactor con commit por cambio","pasos":["Buscar en el proyecto todas las anotaciones explícitas ':any' y los parámetros sin tipo que el compilador infiere como 'any' implícito.","Para cada caso, analizar cómo se usa el valor en el resto de la función para determinar su tipo real o el conjunto de tipos posibles.","Reemplazar 'any' por el tipo concreto detectado, o por una unión de tipos si el valor puede ser de más de un tipo.","Cuando el tipo real no pueda determinarse con certeza, usar 'unknown' junto con una validación explícita antes de operar sobre el valor.","Ejecutar el compilador y la suite de tests tras cada archivo modificado, resolviendo los errores de tipo que aparezcan.","Commit independiente por archivo con los 'any' resueltos."],"reglas":["No sustituir 'any' por un tipo adivinado sin evidencia en el código: si no hay certeza, usar 'unknown' con su validación, no un tipo concreto arriesgado.","No modificar los tipos de librerías de terceros sin declaraciones propias; en esos casos, aislar el uso de 'any' en un único punto documentado en vez de propagarlo.","El proyecto debe compilar sin errores de tipo después de cada archivo modificado."],"prompt":"Busca en el proyecto todas las anotaciones explícitas ':any' y los parámetros sin tipo que el compilador de TypeScript trata como 'any' implícito. Para cada uso encontrado, analiza cómo se utiliza ese valor en el resto de la función (qué propiedades se leen, qué operaciones se hacen sobre él) para determinar su tipo real o el conjunto de tipos posibles que puede tomar. Reemplaza el 'any' por ese tipo concreto o por una unión de tipos. Si no puedes determinar el tipo real con certeza a partir del código, usa 'unknown' en vez de adivinar, y añade la validación (type guard) necesaria antes de operar sobre el valor. Si el 'any' proviene de una librería de terceros sin tipos propios, no la modifiques: aísla su uso en un único punto documentado en vez de dejar que se propague. Ejecuta el compilador y la suite de tests después de cada archivo modificado, resolviendo cualquier error de tipo que surja. Trabaja un archivo a la vez y haz un commit independiente por cada uno."}},
  {"id":"sw38","catalogo":"software","grupo":"Mantenimiento del código","tema":"Migración de Arquitectura de Tipado y Sintaxis","titulo":"El código de llamadas encadenadas deja de ser un laberinto de paréntesis","beneficio":"El código escrito con callbacks anidados o cadenas largas de '.then()' es difícil de leer y de depurar cuando algo falla a mitad del proceso. Modernizarlo a 'async/await' hace que el flujo se lea de arriba a abajo como código secuencial normal, y que los errores se puedan capturar con un solo 'try/catch' en vez de un manejador por cada eslabón.","alcance":"Convierte código basado en callbacks o cadenas de '.then()/.catch()' a la sintaxis 'async/await', preservando exactamente el mismo orden de ejecución y el mismo manejo de errores. No cambia la librería o API subyacente que se está llamando ni introduce paralelismo donde antes no lo había, salvo que se identifique explícitamente como una mejora aparte. El comportamiento ante errores debe verificarse con tests antes de dar el cambio por bueno.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta funciones que usan callbacks anidados o cadenas de '.then()/.catch()' para manejar operaciones asíncronas, y las reescribe usando 'async/await', envolviendo el manejo de errores en bloques 'try/catch' equivalentes a los '.catch()' originales, preservando el orden de ejecución y de captura de errores.","modo":"Modernización de sintaxis","pasos":["Identificar funciones con callbacks anidados o cadenas largas de '.then()/.catch()'.","Para cada una, marcar la función como 'async' y reemplazar cada '.then()' por una línea con 'await', preservando el orden original de ejecución.","Convertir cada bloque '.catch()' en un 'try/catch' equivalente, asegurando que se capturan los mismos errores que antes.","Revisar si alguna operación estaba pensada para ejecutarse en paralelo y, en ese caso, preservar el paralelismo explícitamente con 'Promise.all'.","Ejecutar los tests existentes (o añadir tests de los casos de error) para confirmar que el comportamiento ante fallos es idéntico al original.","Commit independiente por función migrada."],"reglas":["No convertir operaciones que se ejecutaban en paralelo en secuenciales por error: usar 'Promise.all' cuando corresponda.","El manejo de errores tras la migración debe capturar exactamente los mismos casos que el '.catch()' original, ni más ni menos.","Verificar con tests el comportamiento ante fallos antes de dar la migración por completa."],"prompt":"Busca en el repositorio funciones que usan callbacks anidados o cadenas de '.then()/.catch()' para manejar operaciones asíncronas, y reescríbelas usando 'async/await'. Marca la función como 'async', reemplaza cada '.then()' por una línea con 'await' preservando el orden de ejecución original, y convierte cada '.catch()' en un bloque 'try/catch' equivalente que capture exactamente los mismos errores que antes. Antes de migrar, revisa si alguna de las operaciones estaba pensada para ejecutarse en paralelo (varios '.then()' disparados a la vez sin depender uno del otro); si es así, preserva ese paralelismo explícitamente usando 'Promise.all' en vez de convertirlo por accidente en una secuencia de await uno detrás de otro. Ejecuta los tests existentes tras cada función migrada, y si no hay tests que cubran el caso de error (la promesa rechazada), añádelos antes de dar el cambio por bueno. Trabaja una función a la vez y haz un commit independiente por cada migración."}},
  {"id":"sw39","catalogo":"software","grupo":"Mantenimiento del código","tema":"Migración de Arquitectura de Tipado y Sintaxis","titulo":"Dejar de adivinar si esta función se declara con 'function', flecha o método","beneficio":"Cuando un mismo directorio mezcla distintos estilos de declaración de funciones sin un criterio claro, cada desarrollador nuevo pierde tiempo entendiendo la convención antes de poder seguirla. Unificar el estilo reduce esa fricción y hace que las revisiones de código se centren en la lógica, no en el formato.","alcance":"Estandariza el estilo de declaración de funciones (function declarations vs. arrow functions vs. métodos) dentro de un directorio o módulo, siguiendo una convención definida. No cambia el comportamiento de ninguna función: es un cambio puramente de forma. En los casos donde el tipo de declaración afecta el comportamiento real (binding de 'this', hoisting), el cambio se omite y se marca para revisión manual.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza un directorio o módulo para detectar el estilo de declaración de funciones predominante y convierte las declaraciones que no siguen ese estilo, respetando los casos donde el tipo de declaración tiene un efecto real en el comportamiento (binding de 'this', hoisting).","modo":"Limpieza automática","pasos":["Determinar el estilo de declaración de funciones predominante en el directorio, por convención documentada o por mayoría de uso actual.","Listar las funciones que no siguen ese estilo dentro del directorio objetivo.","Para cada una, verificar que el cambio de estilo no altera el binding de 'this' ni depende de hoisting.","Convertir las funciones seguras al estilo predominante, preservando parámetros, nombre y cuerpo exactamente.","Ejecutar la suite de tests y el linter tras cada archivo modificado.","Commit independiente por archivo unificado."],"reglas":["No convertir funciones donde el cambio de estilo alteraría el binding de 'this'.","No convertir funciones que se usan antes de su declaración en el archivo si el nuevo estilo no soporta hoisting.","El cambio debe ser puramente estético: mismos parámetros, mismo nombre, mismo cuerpo, mismo comportamiento observable."],"prompt":"Analiza el directorio [ruta del directorio] y determina cuál es el estilo de declaración de funciones predominante (function declaration, arrow function o método de clase), según la guía de estilo o el linter ya configurado en el proyecto, o según la mayoría de uso actual si no hay una regla explícita. Lista las funciones de ese directorio que no siguen ese estilo. Para cada una, verifica primero que el cambio no altere el binding de 'this' (por ejemplo, si la función se usa como manejador de eventos que depende de su propio contexto) ni dependa de hoisting (uso antes de su declaración en el archivo). Convierte solo las funciones donde el cambio es seguro, preservando exactamente los mismos parámetros, nombre y cuerpo. Ejecuta la suite de tests y el linter después de cada archivo modificado. Si encuentras un caso donde el cambio de estilo sí afectaría el comportamiento, no lo toques y añádelo a un listado de excepciones documentadas. Trabaja un archivo a la vez y haz un commit independiente por cada uno unificado."}},
  {"id":"sw40","catalogo":"software","grupo":"Mantenimiento del código","tema":"Migración de Arquitectura de Tipado y Sintaxis","titulo":"Ese campo que 'a veces viene y a veces no' deja de generar errores en producción","beneficio":"Un campo marcado como opcional en el tipo de datos, cuando en la práctica siempre está presente, obliga a todo el código que lo usa a comprobar constantemente si existe, y esconde el verdadero contrato de los datos. Hacerlo obligatorio cuando corresponde simplifica el código que lo consume y elimina una fuente típica de errores de 'undefined'.","alcance":"Analiza propiedades opcionales en interfaces y tipos, determina —a partir del uso real en el código— si en la práctica siempre reciben un valor, y las convierte en obligatorias cuando corresponde. No decide por sí solo casos ambiguos: cuando el campo está ausente en una parte legítima del código, la propiedad se deja opcional. Este cambio puede romper código que dependía silenciosamente de la ausencia del campo, por lo que exige revisión y tests antes de desplegar.","precio":1.99,"blueprint":{"quePuedeHacer":"Examina interfaces y tipos con propiedades opcionales, rastrea todos los puntos del código donde se crea un objeto de ese tipo para determinar si el campo se proporciona siempre, y en ese caso elimina el modificador opcional, actualizando el código consumidor que hacía comprobaciones de existencia innecesarias.","modo":"Refactorización de tipos","pasos":["Listar las interfaces o tipos del proyecto con propiedades opcionales.","Para cada propiedad opcional, rastrear todos los puntos donde se construye un objeto de ese tipo y verificar si el campo se incluye siempre.","Si el campo está presente en el cien por ciento de los casos rastreados, quitar el modificador opcional del tipo.","Actualizar el código consumidor que comprobaba la existencia del campo innecesariamente, simplificándolo donde ya no aplica.","Ejecutar el compilador para detectar los puntos donde el campo sí faltaba y decidir, caso por caso, si corresponde añadir el valor faltante o revertir el campo a opcional.","Ejecutar la suite de tests y hacer un commit independiente por tipo endurecido."],"reglas":["Solo eliminar el modificador opcional cuando el rastreo confirme que el campo está presente en absolutamente todos los puntos de construcción del objeto encontrados en el repositorio.","Si el compilador señala un punto donde el campo faltaba tras el cambio, no forzar un valor por defecto inventado: revisar el caso con el equipo o revertir esa propiedad a opcional.","Cualquier tipo endurecido que afecte a datos que cruzan un límite externo requiere revisión humana antes de desplegar."],"prompt":"Analiza las interfaces y tipos de este proyecto que tienen propiedades opcionales (declaradas como 'campo?: tipo'). Para cada una, rastrea en el código todos los puntos donde se construye un objeto de ese tipo y determina si el campo se proporciona siempre o si hay casos legítimos donde falta. Cuando confirmes que el campo está presente en absolutamente todos los casos encontrados, elimina el modificador opcional del tipo y simplifica el código consumidor que hacía comprobaciones de existencia innecesarias ('?.', 'if (obj.campo)') que ya no tienen sentido. Ejecuta el compilador después de cada cambio: si aparece un error de tipo en un punto donde el campo sí faltaba, no inventes un valor por defecto para forzar que compile — repórtalo para que decidamos juntos si hay que completar ese dato o revertir la propiedad a opcional. Presta especial atención a los tipos que representan datos que cruzan un límite externo (una API pública o la respuesta de un servicio de terceros): en esos casos, deja explícito en el commit que el cambio requiere validación adicional porque el emisor externo podría seguir sin enviar el campo. Trabaja un tipo a la vez, ejecuta la suite de tests, y haz un commit independiente por cada tipo endurecido."}},
  {"id":"sw41","catalogo":"software","grupo":"Mantenimiento del código","tema":"Modularización y Componentización","titulo":"Esa pantalla de 800 líneas deja de ser el único lugar donde nadie quiere entrar a modificar","beneficio":"Cuando un componente de frontend concentra toda la lógica visual de una pantalla completa, cualquier ajuste pequeño implica leer y entender cientos de líneas ajenas al cambio. Dividirlo en subcomponentes más pequeños permite tocar una parte de la interfaz sin arriesgar el resto.","alcance":"Desglosa vistas de frontend extensas en subcomponentes más pequeños y reutilizables, agrupados por su función visual. No rediseña la interfaz ni cambia el comportamiento visual o funcional de la pantalla: el resultado debe verse y comportarse exactamente igual, solo organizado en archivos distintos. Debe validarse visualmente tras la división, porque un límite de componente mal trazado puede romper el paso de datos entre partes.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza un componente de frontend extenso, identifica bloques visuales con una responsabilidad propia (una sección de formulario, una tabla, un encabezado, un pie), y los extrae a subcomponentes independientes que reciben los datos y funciones necesarias como props, manteniendo el árbol de renderizado y el resultado visual idénticos.","modo":"Refactor con commit por cambio","pasos":["Identificar el componente de frontend con mayor número de líneas o de responsabilidades visuales distintas.","Marcar dentro del archivo los bloques que representan secciones visuales independientes.","Extraer el primer bloque a un subcomponente nuevo, definiendo las props necesarias para que reciba los datos y funciones que antes usaba directamente.","Sustituir el bloque original por el nuevo subcomponente dentro del componente padre.","Verificar visualmente que el resultado no cambió.","Repetir con el siguiente bloque, un commit por subcomponente extraído."],"reglas":["El resultado visual y funcional de la pantalla debe ser idéntico antes y después de cada extracción.","No extraer un bloque como subcomponente si eso obliga a pasar más de un puñado de props sin relación entre sí: en ese caso el límite del componente probablemente está mal trazado.","Verificar el resultado después de cada subcomponente extraído, no solo al final de todo el proceso."],"prompt":"Identifica en este proyecto el componente de frontend con más líneas de código o con más secciones visuales mezcladas en un mismo archivo (por ejemplo, una pantalla que incluye encabezado, formulario, tabla de resultados y pie, todo junto). Marca los bloques que representan secciones visuales independientes y extrae el primero a un subcomponente nuevo, definiendo props claras para los datos y funciones que necesita recibir del componente padre. Sustituye el bloque original por el nuevo subcomponente. El resultado visual y funcional de la pantalla debe quedar exactamente igual que antes — verifícalo con una captura de pantalla, un snapshot test si el proyecto los usa, o describiendo explícitamente qué revisar manualmente. Si extraer un bloque te obliga a pasar muchas props sin relación clara entre sí, detente: probablemente el límite del componente está mal trazado, y prefiero decidir ese límite contigo antes de continuar. Repite el proceso con el siguiente bloque, verificando el resultado después de cada extracción, y haz un commit independiente por cada subcomponente creado."}},
  {"id":"sw42","catalogo":"software","grupo":"Mantenimiento del código","tema":"Modularización y Componentización","titulo":"La pantalla deja de mezclar 'qué se ve' con 'de dónde vienen los datos'","beneficio":"Cuando la lógica de llamadas a la API, temporizadores o suscripciones vive mezclada dentro del componente visual, es difícil reutilizarla en otra pantalla o probarla sin renderizar toda la interfaz. Aislarla en un hook propio permite reutilizar esa lógica en más de un lugar y probarla de forma independiente de la interfaz.","alcance":"Extrae la lógica de estado, efectos secundarios y llamadas a API de un componente de frontend hacia un custom hook dedicado, dejando el componente enfocado solo en el renderizado visual. No cambia el comportamiento observable de la pantalla ni introduce una librería de manejo de estado nueva si el proyecto no la tiene. Los efectos con dependencias delicadas requieren verificación manual de que la limpieza ('cleanup') se preserva correctamente tras la extracción.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta lógica de estado, efectos secundarios y llamadas a API mezclada dentro de un componente de frontend, y la extrae a un custom hook (por ejemplo 'useNombreDelDato') que expone los datos y funciones necesarias, dejando el componente original limitado a consumir el hook y renderizar el resultado.","modo":"Refactor con commit por cambio","pasos":["Identificar en el componente los bloques de estado, efectos secundarios y llamadas a API que no están directamente relacionados con el renderizado visual.","Diseñar la interfaz del custom hook: qué recibe como parámetros y qué expone.","Mover esos bloques de estado, efectos y llamadas a un archivo nuevo que define el custom hook.","Sustituir en el componente original la lógica extraída por una llamada al nuevo hook.","Verificar que cualquier limpieza de efectos se preserva exactamente igual dentro del hook.","Ejecutar los tests existentes y hacer un commit por hook extraído."],"reglas":["El componente resultante no debe contener llamadas directas a API ni efectos secundarios propios de datos: esa lógica vive únicamente en el hook.","Preservar exactamente la limpieza de efectos que existía antes de la extracción; no omitirla ni simplificarla.","No introducir una librería de manejo de estado global nueva como parte de esta extracción si el proyecto no la usa ya."],"prompt":"Analiza este componente de frontend e identifica la lógica de estado, efectos secundarios (useEffect) y llamadas a API que están mezcladas con el código de renderizado visual. Diseña un custom hook (por ejemplo 'useNombreDelDato') que reciba los parámetros necesarios y exponga los datos, el estado de carga, el error y las funciones que el componente necesita. Mueve la lógica de estado, los efectos y las llamadas a API a ese hook, en un archivo nuevo, preservando exactamente cualquier limpieza de efectos (la función de retorno de un useEffect que cancela un temporizador o una suscripción) tal como estaba. Sustituye en el componente original esa lógica por una llamada al nuevo hook, dejando el componente enfocado solo en renderizar la interfaz a partir de lo que el hook expone. No introduzcas ninguna librería de manejo de estado global nueva como parte de este cambio. Verifica que el comportamiento de la pantalla es idéntico al anterior (mediante los tests existentes o una revisión manual de la pantalla) y haz un commit independiente por cada hook extraído."}},
  {"id":"sw43","catalogo":"software","grupo":"Mantenimiento del código","tema":"Modularización y Componentización","titulo":"Formatear una fecha o una moneda deja de dar un resultado distinto según qué archivo lo haga","beneficio":"Cuando varias partes del código formatean fechas, moneda o texto cada una a su manera, el negocio corre el riesgo de mostrar el mismo dato de forma distinta en dos pantallas. Centralizar esas funciones en un único módulo de utilidades garantiza consistencia visual y de negocio en toda la aplicación.","alcance":"Localiza funciones de utilidad duplicadas o casi idénticas repartidas por el código, y las fusiona en un módulo único de helpers, actualizando los puntos de uso para que importen la versión centralizada. No decide cuál de los formatos duplicados es el 'correcto' de negocio si difieren en el resultado: esos casos deben confirmarse con el equipo antes de unificar, para no cambiar silenciosamente lo que ve el usuario.","precio":1.99,"blueprint":{"quePuedeHacer":"Escanea el repositorio en busca de funciones de utilidad con lógica equivalente o casi idéntica definidas en más de un archivo, compara su comportamiento exacto, y las fusiona en un módulo centralizado de helpers, sustituyendo cada definición duplicada por un import a la versión única.","modo":"Limpieza automática","pasos":["Buscar en el repositorio funciones de utilidad con nombres o propósitos similares definidas en más de un archivo.","Comparar el comportamiento exacto de cada versión duplicada con casos de prueba concretos.","Si las versiones difieren en el resultado para algún caso, marcarlas como conflicto y no fusionarlas sin antes confirmar con el equipo.","Para las versiones que son equivalentes, crear o extender un módulo central de helpers con una única implementación.","Sustituir cada definición duplicada por un import a la versión centralizada, archivo por archivo.","Ejecutar la suite de tests tras cada archivo migrado, con un commit independiente por archivo."],"reglas":["No fusionar dos funciones con el mismo propósito aparente si producen resultados distintos para las mismas entradas, sin antes confirmar con el equipo cuál es el comportamiento correcto de negocio.","La función centralizada debe conservar el comportamiento validado, no una mezcla arbitraria de las versiones duplicadas.","Ejecutar la suite de tests después de cada archivo migrado a la versión centralizada."],"prompt":"Busca en este repositorio funciones de utilidad con el mismo propósito aparente (formatear fechas, formatear moneda, capitalizar texto, validar un email, etc.) que estén definidas en más de un archivo. Para cada grupo de duplicados, compara su comportamiento exacto probando las mismas entradas de ejemplo en cada versión. Si todas las versiones producen el mismo resultado, muévelas a un único módulo central de helpers (o al que ya exista en el proyecto) y sustituye cada definición duplicada por un import a esa versión única, archivo por archivo. Si detectas que dos versiones producen resultados distintos para el mismo caso (por ejemplo, un formato de fecha DD/MM/AAAA contra otro MM/DD/AAAA), no las fusiones: repórtalo como un conflicto para que el equipo decida cuál es el comportamiento correcto antes de unificar, porque unificarlo a ciegas cambiaría lo que ve el usuario en alguna pantalla. Ejecuta la suite de tests después de cada archivo migrado y haz un commit independiente por cada uno."}},
  {"id":"sw44","catalogo":"software","grupo":"Mantenimiento del código","tema":"Modularización y Componentización","titulo":"Importar algo de otra carpeta deja de requerir conocer su estructura interna","beneficio":"Cuando cada archivo importa directamente desde rutas profundas de otra carpeta, cualquier reorganización interna de esa carpeta rompe medio proyecto. Un archivo de exportación limpio (fachada) permite reorganizar el interior de un módulo sin afectar a quien lo consume desde fuera.","alcance":"Crea archivos de exportación centralizada ('index.ts' o equivalente) que exponen la interfaz pública de una carpeta, ocultando su estructura interna, y actualiza las importaciones externas para que usen esa fachada en vez de rutas profundas. No reorganiza ni renombra los archivos internos del módulo como parte de este cambio. No aplica a módulos que ya exponen intencionalmente su estructura interna a consumidores específicos por buenas razones documentadas.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza una carpeta o módulo del proyecto que se importa desde múltiples rutas internas distintas, determina cuáles de esos elementos son parte de la interfaz pública real que otras partes del código necesitan, y crea un archivo 'index.ts' que los re-exporta, actualizando los imports externos para que apunten a la carpeta en vez de a la ruta interna.","modo":"Creación de fachada","pasos":["Elegir una carpeta o módulo del proyecto que se importa desde fuera usando rutas internas profundas.","Listar, revisando los usos externos existentes, qué funciones, clases o tipos de esa carpeta se consumen realmente desde fuera.","Crear un archivo 'index.ts' que re-exporte únicamente esos elementos.","Actualizar los imports externos, uno por archivo consumidor, para que apunten a la carpeta (la fachada) en vez de a la ruta interna profunda.","Ejecutar el compilador y la suite de tests tras cada archivo consumidor actualizado.","Commit independiente por módulo con fachada creada, y otro por cada archivo consumidor migrado."],"reglas":["No reorganizar ni renombrar los archivos internos del módulo como parte de este cambio; el objetivo es solo exponer una fachada limpia.","La fachada debe exportar únicamente lo que otras partes del código consumen realmente hoy, no todo el contenido interno del módulo.","Verificar que el compilador no reporta errores tras actualizar cada archivo consumidor antes de continuar con el siguiente."],"prompt":"Analiza la carpeta [ruta de la carpeta] de este proyecto, que actualmente se importa desde fuera usando rutas internas profundas (por ejemplo 'from carpeta/subcarpeta/archivo'). Revisa los usos externos existentes y lista qué funciones, clases o tipos de esa carpeta se consumen realmente desde otras partes del código. Crea un archivo 'index.ts' en la raíz de la carpeta que re-exporte únicamente esos elementos identificados como parte de la interfaz pública real — no reexportes todo el contenido interno del módulo. No reorganices ni renombres ningún archivo dentro de la carpeta como parte de este cambio. Después, actualiza los imports externos, un archivo consumidor a la vez, para que apunten a la carpeta (la nueva fachada) en vez de a la ruta interna profunda, ejecutando el compilador después de cada uno. Haz un commit para la creación de la fachada y un commit independiente por cada archivo consumidor migrado."}},
  {"id":"sw45","catalogo":"software","grupo":"Mantenimiento del código","tema":"Modularización y Componentización","titulo":"La aplicación deja de cargar código que el usuario quizá nunca visite en esa sesión","beneficio":"Cuando toda la aplicación se descarga de una sola vez, el usuario espera a que cargue código de pantallas que tal vez no visitará en esa sesión. Cargar esos módulos solo cuando se necesitan reduce lo que hay que descargar al entrar por primera vez.","alcance":"Modifica el enrutamiento de la aplicación para importar de forma dinámica (lazy loading) los módulos de rutas que no son necesarias en la carga inicial, usando el mecanismo de import dinámico del framework. No decide cuáles son las rutas 'críticas' de negocio que deben cargar siempre de inmediato: esa priorización debe validarla el equipo. El impacto real en tiempos de carga debe medirse en el entorno real, no darse por hecho solo por aplicar el patrón.","precio":1.99,"blueprint":{"quePuedeHacer":"Identifica rutas o módulos grandes que actualmente se importan de forma estática en el punto de entrada del enrutador, y los convierte a importación dinámica (lazy loading) usando el mecanismo del framework correspondiente, añadiendo el estado de carga necesario mientras el módulo se descarga.","modo":"Migración incremental","pasos":["Identificar en el archivo de enrutamiento las rutas que importan módulos de mayor tamaño o que no son necesarias en la primera pantalla que ve la mayoría de los usuarios.","Confirmar con el equipo que esas rutas no son parte del flujo crítico de la carga inicial.","Convertir el import estático de cada ruta seleccionada a import dinámico, usando el mecanismo de lazy loading del framework.","Añadir el componente de carga que se muestra mientras el módulo se descarga.","Verificar manualmente que la ruta sigue funcionando igual una vez cargada, y que el estado de carga se ve razonable.","Commit independiente por ruta convertida a carga perezosa."],"reglas":["No convertir a carga perezosa las rutas que forman parte del flujo crítico de primera carga sin confirmación explícita de que es una decisión de negocio aceptable.","Toda ruta convertida a lazy loading debe tener un estado de carga visible, nunca una pantalla en blanco mientras se descarga.","No afirmar una mejora de tiempo de carga sin haberla medido en el entorno real: describir el cambio como una optimización pendiente de medición si no se dispone de esos datos."],"prompt":"Revisa el archivo de enrutamiento de esta aplicación e identifica las rutas que importan módulos de mayor tamaño o que corresponden a secciones que no forman parte del flujo que ve la mayoría de los usuarios justo al entrar (por ejemplo, un panel de administración, una sección de configuración avanzada, un reporte poco usado). Antes de convertir ninguna, confirma conmigo cuáles de esas rutas realmente no son críticas para la carga inicial. Para las rutas confirmadas, convierte el import estático a import dinámico usando el mecanismo de carga perezosa del framework de este proyecto, y añade un estado de carga visible (spinner o esqueleto) mientras el módulo se descarga — nunca dejes una pantalla en blanco durante la carga. Verifica manualmente que cada ruta sigue funcionando igual una vez cargada. No afirmes ninguna mejora de tiempo de carga en el mensaje de commit a menos que la hayamos medido con datos reales del entorno de producción o staging; si no la medimos, describe el cambio solo como una optimización de carga inicial pendiente de medición. Trabaja una ruta a la vez y haz un commit independiente por cada una convertida."}},
  {"id":"sw46","catalogo":"software","grupo":"Mantenimiento del código","tema":"Hardening de Seguridad Directo en Código","titulo":"Un formulario mal pensado deja de poder vaciar tu base de datos","beneficio":"Concatenar directamente lo que escribe un usuario dentro de una consulta SQL abre la puerta a que alguien inserte comandos maliciosos y acceda o borre datos que no debería. Parametrizar las consultas cierra esa puerta sin cambiar lo que la consulta hace para un usuario legítimo.","alcance":"Localiza consultas SQL construidas por concatenación de strings (incluyendo datos de entrada del usuario) y las sustituye por consultas parametrizadas usando el mecanismo del driver o ORM del proyecto. No audita el resto de la superficie de seguridad de la aplicación: se enfoca solo en la construcción de la consulta. El cambio debe probarse contra una base de datos de prueba antes de desplegar, porque una sustitución mal hecha puede alterar el resultado de la consulta.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta consultas SQL construidas mediante concatenación de strings (especialmente aquellas que incorporan datos de entrada de usuario) y las reescribe usando consultas parametrizadas o prepared statements del driver de base de datos o del ORM ya utilizado en el proyecto, eliminando la concatenación directa de valores dentro del texto SQL.","modo":"Endurecimiento de seguridad","pasos":["Buscar en el repositorio consultas SQL construidas por concatenación de strings, prestando especial atención a las que incorporan datos que vienen de un formulario, parámetro de URL o cuerpo de petición.","Priorizar las consultas que reciben datos de entrada de usuario directo, por ser el riesgo más alto.","Reescribir cada consulta priorizada usando el mecanismo de parámetros del driver ya utilizado por el proyecto.","Verificar que el resultado de la consulta parametrizada es idéntico al de la consulta original para los mismos valores de entrada, probando contra una base de datos de prueba.","Ejecutar la suite de tests tras cada consulta migrada.","Commit independiente por archivo o consulta migrada, priorizando primero las de mayor exposición a datos externos."],"reglas":["Ninguna consulta parametrizada debe seguir concatenando directamente un valor proveniente de entrada de usuario dentro del texto SQL.","No cambiar la lógica de la consulta (filtros, joins, orden): el objetivo es solo la forma en que se incorporan los valores, no el resultado.","Probar cada consulta migrada contra una base de datos de prueba o staging antes de dar el cambio por completo, comparando resultados con la consulta original."],"prompt":"Analiza el repositorio y localiza todas las consultas SQL construidas por concatenación de strings, especialmente las que incorporan datos que vienen de un formulario, un parámetro de URL o el cuerpo de una petición HTTP. Prioriza primero las que reciben datos de entrada de usuario directo, por ser el mayor riesgo de inyección SQL. Para cada una, reescríbela usando el mecanismo de parámetros del driver de base de datos o del ORM ya usado en este proyecto (placeholders o prepared statements), de forma que ningún valor externo se concatene directamente dentro del texto de la consulta. No cambies los filtros, joins ni el orden de la consulta: el resultado debe ser idéntico al original para los mismos valores de entrada — verifícalo contra una base de datos de prueba o de staging. Ejecuta la suite de tests después de cada consulta migrada. Trabaja priorizando primero los archivos con mayor exposición a datos externos, y haz un commit independiente por cada consulta o archivo migrado."}},
  {"id":"sw47","catalogo":"software","grupo":"Mantenimiento del código","tema":"Hardening de Seguridad Directo en Código","titulo":"Una llave de API pegada en el código deja de viajar a cada copia del repositorio","beneficio":"Una clave privada, token o contraseña escrita directamente en el código queda expuesta a cualquiera con acceso al repositorio, incluyendo su historial de cambios. Moverla a variables de entorno reduce quién puede verla y permite rotarla sin tocar el código.","alcance":"Localiza credenciales, llaves de API, tokens y contraseñas escritas directamente en el código fuente, y las reemplaza por lecturas de variables de entorno, dejando el valor real fuera del repositorio. No rota ni invalida automáticamente las credenciales que ya estuvieron expuestas en el historial de git: eso requiere una acción manual separada del equipo, porque el secreto expuesto en commits anteriores sigue siendo visible en el historial aunque se borre del código actual.","precio":1.99,"blueprint":{"quePuedeHacer":"Escanea el código en busca de patrones de credenciales quemadas y las sustituye por lecturas de variables de entorno (por ejemplo 'process.env.NOMBRE_VARIABLE'), añadiendo la variable correspondiente a un archivo de ejemplo de entorno sin el valor real.","modo":"Endurecimiento de seguridad","pasos":["Buscar en el código patrones que parezcan credenciales (cadenas alfanuméricas asignadas a variables con nombres como 'apiKey', 'secret', 'token', 'password', o cadenas de conexión con usuario y contraseña incluidos).","Confirmar cuáles son efectivamente secretos reales y no valores de prueba o placeholders ya inocuos.","Para cada secreto confirmado, reemplazar su uso en el código por una lectura de variable de entorno con un nombre descriptivo.","Añadir la variable, sin el valor real, a un archivo de ejemplo de entorno para documentar que existe.","Verificar que el archivo real de entorno con los valores está incluido en '.gitignore' y no se sube al repositorio.","Marcar explícitamente para el equipo qué secretos aparecían también en commits anteriores del historial de git, ya que ese historial requiere una rotación manual de esas credenciales."],"reglas":["No borrar del historial de git ni reescribir commits anteriores: esa es una operación destructiva que el equipo debe decidir y ejecutar de forma explícita y separada.","Todo secreto movido a variable de entorno debe quedar documentado (sin su valor) en el archivo de ejemplo de entorno del proyecto.","Marcar como acción pendiente y urgente para el equipo la rotación de cualquier credencial que se confirme expuesta en el historial de commits."],"prompt":"Analiza este repositorio en busca de credenciales quemadas directamente en el código: llaves de API, tokens, contraseñas o cadenas de conexión con usuario y contraseña incluidos (busca patrones como variables llamadas 'apiKey', 'secret', 'token', 'password' asignadas a strings largos, y cadenas de conexión con credenciales). Confirma cuáles son secretos reales y no valores de prueba o placeholders ya inocuos. Para cada secreto real, reemplaza su uso en el código por una lectura de variable de entorno con un nombre descriptivo (por ejemplo 'process.env.STRIPE_SECRET_KEY'), y añade esa variable, sin su valor real, al archivo de ejemplo de entorno del proyecto ('.env.example' o el que ya use). Verifica que el archivo real con los valores de entorno está incluido en '.gitignore'. No intentes reescribir ni borrar el historial de git: eso es una decisión que debe tomar el equipo de forma explícita. En cambio, entrégame al final un listado separado de qué secretos aparecían también en commits anteriores del historial (revisando con git log/grep sobre el historial), marcado como urgente, porque esas credenciales deben rotarse manualmente ya que siguen expuestas en el historial aunque el código actual ya no las muestre."}},
  {"id":"sw48","catalogo":"software","grupo":"Mantenimiento del código","tema":"Hardening de Seguridad Directo en Código","titulo":"Un comentario de usuario deja de poder ejecutar código dentro de tu propia web","beneficio":"Cuando la aplicación inserta contenido escrito por un usuario directamente como HTML, alguien puede insertar un script que se ejecute en el navegador de otros usuarios que vean esa página. Sanitizar o evitar el renderizado crudo elimina esa vía de ataque sin cambiar cómo se ve el contenido legítimo.","alcance":"Localiza puntos del código donde se inserta contenido dinámico como HTML crudo sin sanitizar, y los sustituye por renderizado como texto plano (cuando el HTML no es necesario) o por HTML sanitizado con una librería de sanitización reconocida (cuando el HTML enriquecido sí es un requisito del producto). No decide si el producto necesita o no permitir formato enriquecido en ese campo: esa es una decisión de negocio que debe confirmarse antes de aplicar la sanitización en vez de eliminar el HTML directamente.","precio":1.99,"blueprint":{"quePuedeHacer":"Escanea el código en busca de puntos donde se renderiza contenido dinámico como HTML sin pasar por sanitización (uso de 'dangerouslySetInnerHTML', 'v-html', 'innerHTML' o construcción de HTML por concatenación de strings en el servidor), y evalúa si el contenido puede mostrarse como texto plano o si requiere sanitización con una librería reconocida antes de insertarse como HTML.","modo":"Endurecimiento de seguridad","pasos":["Buscar en el código todos los puntos donde se inserta contenido dinámico como HTML sin sanitizar.","Para cada punto, determinar si el contenido proviene de una fuente de confianza o de entrada de usuario/terceros.","Para los puntos con contenido de usuario que no necesita formato enriquecido, cambiar el renderizado a texto plano.","Para los puntos donde el formato enriquecido sí es un requisito confirmado del producto, introducir una librería de sanitización HTML reconocida y aplicarla antes de la inserción.","Verificar manualmente que el contenido legítimo se sigue viendo correctamente tras la sanitización.","Commit independiente por punto de renderizado corregido, priorizando los que reciben contenido de usuarios externos."],"reglas":["No dejar ningún punto que inserte contenido de entrada de usuario como HTML crudo sin sanitizar, salvo que se confirme explícitamente que la fuente es de total confianza.","No decidir unilateralmente eliminar el soporte de formato enriquecido de un campo si el producto lo requiere: en ese caso, sanitizar, no eliminar.","Verificar visualmente que el contenido legítimo se sigue mostrando correctamente después de aplicar la sanitización."],"prompt":"Busca en este proyecto todos los puntos donde se inserta contenido dinámico como HTML sin pasar por sanitización: uso de 'dangerouslySetInnerHTML' en React, 'v-html' en Vue, asignaciones a 'innerHTML', o construcción de HTML por concatenación de strings en el backend con datos que vienen de un usuario o de un tercero. Para cada punto encontrado, determina si el contenido proviene de una fuente de confianza (texto fijo del propio equipo) o de entrada externa. Para los puntos con contenido externo que no necesitan formato enriquecido, cambia el renderizado para mostrar el contenido como texto plano, evitando el HTML crudo por completo. Para los puntos donde el formato enriquecido sí es un requisito confirmado del producto (como un editor de texto enriquecido), introduce una librería de sanitización HTML reconocida y aplícala al contenido antes de insertarlo, en vez de eliminar el soporte de formato. Verifica manualmente que el contenido legítimo (negritas, enlaces, saltos de línea esperados) se sigue mostrando bien después del cambio. Prioriza primero los puntos que reciben contenido de usuarios externos, y haz un commit independiente por cada punto corregido."}},
  {"id":"sw49","catalogo":"software","grupo":"Mantenimiento del código","tema":"Hardening de Seguridad Directo en Código","titulo":"Una fuga de la base de datos deja de significar que todas las contraseñas quedan al descubierto","beneficio":"Si las contraseñas se guardan con un algoritmo débil o desactualizado, una fuga de la base de datos expone las contraseñas reales de los usuarios con relativa facilidad usando herramientas ya disponibles. Migrar a un algoritmo de hashing diseñado para contraseñas hace que esa misma fuga sea mucho más costosa de explotar para un atacante.","alcance":"Sustituye el algoritmo de hashing de contraseñas actual (si es obsoleto: MD5, SHA1, o cualquiera sin función de derivación de clave adaptativa) por una implementación robusta y reconocida (Bcrypt o Argon2), tanto en el punto donde se crea o cambia una contraseña como en el punto donde se verifica el login. No migra automáticamente las contraseñas ya almacenadas con el algoritmo antiguo: eso requiere una estrategia de migración progresiva que debe implementarse y probarse con cuidado, porque un error aquí puede dejar a usuarios legítimos sin poder entrar.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta el algoritmo de hashing usado actualmente para contraseñas, lo reemplaza por Bcrypt o Argon2 en los puntos de creación y verificación de contraseña, e implementa una migración progresiva que re-hashea la contraseña de cada usuario con el algoritmo nuevo la próxima vez que inicie sesión correctamente con la contraseña antigua.","modo":"Migración incremental","pasos":["Localizar en el código los puntos donde se genera el hash de una contraseña y donde se verifica en el login.","Identificar el algoritmo actualmente en uso y confirmar si es obsoleto.","Introducir la librería de Bcrypt o Argon2 y usarla para el hash de cualquier contraseña nueva o cambiada a partir de ahora.","En el punto de verificación de login, detectar si el hash almacenado corresponde al algoritmo antiguo o al nuevo, y verificar con el algoritmo correspondiente.","Si el login es exitoso usando el algoritmo antiguo, volver a hashear la contraseña con el algoritmo nuevo y guardar ese nuevo hash de inmediato.","Probar exhaustivamente el flujo de login con usuarios que tengan el hash antiguo y con usuarios nuevos, con un commit separado por etapa."],"reglas":["No forzar a todos los usuarios existentes a restablecer su contraseña como única vía de migración: la migración progresiva en el próximo login exitoso es el camino que no interrumpe al usuario.","El algoritmo nuevo debe aplicarse con un costo o factor de trabajo acorde a las recomendaciones vigentes de la librería usada, no un valor mínimo elegido al azar.","Probar el flujo completo de login en un entorno de prueba antes de desplegar a producción, porque un error aquí bloquea el acceso de usuarios reales."],"prompt":"Analiza el código de autenticación de este proyecto y localiza los puntos donde se genera y se verifica el hash de las contraseñas de los usuarios (registro, cambio de contraseña, login). Identifica qué algoritmo se usa actualmente y confirma si es obsoleto para contraseñas (MD5, SHA1, o cualquier hash genérico sin función de derivación de clave adaptativa). Introduce una librería de Bcrypt o Argon2 apropiada para el lenguaje de este proyecto, y úsala para hashear cualquier contraseña nueva o modificada a partir de ahora, con un factor de costo acorde a las recomendaciones actuales de esa librería. En el punto de verificación de login, detecta si el hash almacenado del usuario corresponde al algoritmo antiguo o al nuevo, verifica con el algoritmo que corresponda, y si el login es exitoso usando el algoritmo antiguo, re-hashea la contraseña con el algoritmo nuevo y guarda ese hash de inmediato, de forma transparente para el usuario (migración progresiva). No fuerces un restablecimiento de contraseña masivo como estrategia de migración. Antes de dar el cambio por terminado, prueba exhaustivamente el flujo de login tanto para usuarios con el hash antiguo como para usuarios nuevos en un entorno de prueba, y haz un commit separado por cada etapa: creación de hash, verificación, y migración progresiva."}},
  {"id":"sw50","catalogo":"software","grupo":"Mantenimiento del código","tema":"Hardening de Seguridad Directo en Código","titulo":"Tu servidor deja de dejar la puerta entreabierta con la configuración por defecto","beneficio":"Un servidor sin cabeceras de seguridad configuradas facilita ataques conocidos y bien documentados que se evitan con configuración, sin tocar la lógica de negocio de la aplicación. Configurarlas es una de las mejoras de seguridad con menor esfuerzo de implementación frente al riesgo que cubren.","alcance":"Configura las cabeceras de respuesta HTTP de seguridad más relevantes (Content-Security-Policy, X-Frame-Options, X-Content-Type-Options, Strict-Transport-Security, Referrer-Policy) en el servidor de la aplicación, usando una librería reconocida (como Helmet en Node.js) o la configuración nativa del framework. No garantiza protección contra todas las clases de ataque: las cabeceras son una capa adicional, no un sustituto de la validación de entrada, la autenticación o la sanitización de datos. Una política de Content-Security-Policy mal calibrada puede bloquear recursos legítimos, por lo que debe probarse en staging antes de producción.","precio":1.99,"blueprint":{"quePuedeHacer":"Configura en el servidor de la aplicación las cabeceras de seguridad HTTP estándar usando una librería reconocida para el stack del proyecto o los mecanismos de configuración del framework, ajustando la política de Content-Security-Policy a los recursos externos que la aplicación realmente utiliza.","modo":"Endurecimiento de seguridad","pasos":["Identificar el framework y servidor HTTP usado por el proyecto, y comprobar si ya existe una librería de cabeceras de seguridad instalada sin usar o mal configurada.","Listar los recursos externos legítimos que la aplicación carga actualmente para poder calibrar la política de Content-Security-Policy sin bloquearlos.","Configurar las cabeceras de seguridad estándar usando la librería o mecanismo nativo del framework.","Desplegar la configuración primero en un entorno de staging y navegar por las páginas principales verificando en la consola del navegador que ningún recurso legítimo queda bloqueado.","Ajustar la política de Content-Security-Policy según los bloqueos detectados, añadiendo únicamente los orígenes que realmente correspondan a recursos legítimos ya en uso.","Commit único con la configuración de cabeceras, documentando en el mensaje qué cabeceras se activaron y con qué política."],"reglas":["No copiar una política de Content-Security-Policy genérica de internet sin ajustarla a los recursos externos reales que usa la aplicación.","Probar la configuración completa en un entorno de staging, navegando las páginas principales, antes de aplicarla en producción.","Las cabeceras de seguridad son una capa adicional: no deben presentarse como sustituto de la validación de entrada, la sanitización o la autenticación ya existentes en el proyecto."],"prompt":"Identifica el framework y el servidor HTTP que usa este proyecto, y revisa si ya existe una librería de cabeceras de seguridad (como Helmet, si es un proyecto Node/Express) instalada pero sin usar o mal configurada. Antes de configurar nada, lista los recursos externos legítimos que la aplicación carga actualmente: scripts de terceros, fuentes web, imágenes de otros dominios, iframes embebidos. Con esa lista, configura las cabeceras de seguridad HTTP estándar (Content-Security-Policy, X-Frame-Options, X-Content-Type-Options, Strict-Transport-Security, Referrer-Policy) usando la librería o el mecanismo nativo del framework, calibrando la política de Content-Security-Policy para permitir explícitamente esos recursos legítimos y ningún otro origen. No copies una política genérica de internet sin ajustarla a este proyecto. Despliega la configuración en un entorno de staging primero, navega por las páginas principales de la aplicación y revisa la consola del navegador en busca de recursos bloqueados; ajusta la política según lo que encuentres. Cuando esté verificado que no se bloquea nada legítimo, entrégame la configuración lista para producción en un solo commit, documentando en el mensaje qué cabeceras se activaron y con qué política exacta."}},
  {"id":"sw51","catalogo":"software","grupo":"Calidad y pruebas","tema":"Corrección Autónoma de Errores","titulo":"Detecta y corrige errores de tu software basándose en pruebas reales, no en suposiciones","beneficio":"Cuando un cliente o QA reporta un fallo, el equipo deja de perder horas intentando reproducirlo a ojo: el agente lo aísla con una prueba automatizada, corrige el código y confirma el arreglo antes de darlo por cerrado.","alcance":"Sirve para errores reproducibles mediante una prueba automatizada (funciones, servicios, reglas de negocio). No resuelve fallos intermitentes sin causa reproducible ni decide si un comportamiento discutido es \"correcto\" desde el punto de vista de producto: eso sigue siendo decisión humana.","precio":1.99,"blueprint":{"quePuedeHacer":"Ejecuta la suite de pruebas del proyecto, aísla el test que falla, interpreta el traceback para localizar la función origen, aplica un cambio mínimo en el código fuente (no en el test) y vuelve a ejecutar toda la suite para confirmar que el fallo se corrigió sin romper otras pruebas.","modo":"Ciclo de prueba y corrección","pasos":["Ejecutar la suite completa de pruebas y capturar la salida.","Aislar el test en fallo y extraer el mensaje de error y la traza.","Localizar el archivo y la función origen del fallo.","Aplicar el cambio mínimo en el código fuente para que el comportamiento coincida con lo esperado.","Reejecutar toda la suite, no solo el test corregido, para descartar regresiones.","Si el fallo persiste, repetir el ciclo con la información del nuevo traceback."],"reglas":["Nunca modificar el test para que pase artificialmente, salvo que el propio test contenga un error demostrable.","No declarar la tarea resuelta hasta que la suite completa pase, no solo el test aislado.","Detenerse y reportar si tras varios ciclos el error no se reduce, en vez de seguir aplicando cambios especulativos."],"prompt":"Ejecuta la suite de tests del proyecto con el comando definido en package.json (o equivalente). Identifica el o los tests que fallan y copia el mensaje de error y la traza completa. A partir del traceback, localiza el archivo y la función responsables del fallo y explica en una frase la causa raíz antes de tocar nada. Aplica el cambio mínimo en el código fuente (nunca en el archivo de test) que corrija esa causa. Vuelve a ejecutar la suite completa y confirma que el test que fallaba ahora pasa y que ningún otro test se rompió. Si sigue fallando, repite el análisis con el nuevo error antes de intentar otro cambio. No des la tarea por terminada hasta que toda la suite esté en verde."}},
  {"id":"sw52","catalogo":"software","grupo":"Calidad y pruebas","tema":"Corrección Autónoma de Errores","titulo":"Elimina los errores de tipos que bloquean cada build antes de que lleguen a producción","beneficio":"Evita que el equipo pierda tiempo desenredando errores de compilación manualmente cada vez que se toca una interfaz compartida; el agente corrige las inconsistencias de tipos de forma sistemática, empezando por el origen del problema.","alcance":"Aplica a proyectos con tipado estático (TypeScript u otro lenguaje con linter de tipos equivalente). No corrige errores de lógica de negocio que compilan sin problemas pero producen resultados incorrectos, ni sustituye la revisión de si el modelo de datos elegido es el adecuado.","precio":1.99,"blueprint":{"quePuedeHacer":"Ejecuta el compilador o el linter de tipos (por ejemplo tsc --noEmit), interpreta la lista de errores, identifica si el origen es la definición del tipo/interfaz o los usos que la violan, y corrige en el punto correcto en lugar de silenciar el error con \"any\" o aserciones forzadas.","modo":"Diagnóstico de tipos y corrección en cascada","pasos":["Ejecutar el compilador de tipos en modo estricto y capturar la lista completa de errores.","Agrupar los errores por archivo/interfaz de origen para detectar causas comunes.","Determinar si el error nace en la definición del tipo o en un uso incorrecto del mismo.","Corregir en el punto de origen, propagando el ajuste a los usos afectados.","Recompilar y confirmar que el número de errores baja a cero (o solo quedan los preexistentes fuera de alcance).","Repetir si la corrección de un tipo revela nuevos errores en cascada."],"reglas":["No usar \"any\", aserciones forzadas de tipo, para silenciar un error sin justificar por qué el tipo real no se puede expresar.","Corregir el error en su origen (la definición) antes que en cada uno de sus usos, cuando ambos sean posibles.","No dejar el build en un estado con más errores de tipos de los que había al empezar."],"prompt":"Ejecuta el compilador de TypeScript en modo estricto sin emitir archivos (tsc --noEmit) y muestra la lista completa de errores. Agrupa los errores por la interfaz o tipo de origen. Para cada grupo, indica si el problema nace en la definición del tipo o en cómo se está usando, y corrige el código en el punto de origen (no con \"any\" ni con aserciones forzadas de tipo), propagando el ajuste a los usos afectados. Vuelve a compilar tras cada corrección y confirma que el número de errores se reduce. Si corregir un tipo genera nuevos errores en otros archivos, continúa el ciclo hasta que la compilación termine sin errores nuevos. Al final, resume qué interfaces cambiaron y por qué."}},
  {"id":"sw53","catalogo":"software","grupo":"Calidad y pruebas","tema":"Corrección Autónoma de Errores","titulo":"Blinda tu aplicación contra las caídas más comunes: datos que llegan vacíos o inesperados","beneficio":"La causa más frecuente de errores en producción son valores nulos o indefinidos que nadie previó; el agente localiza esas zonas frágiles y añade las validaciones necesarias para que la aplicación degrade con elegancia en lugar de romperse.","alcance":"Cubre validaciones defensivas, valores por defecto y encadenamiento opcional en el código existente. No decide qué debe pasar de negocio cuando un dato falta (eso requiere una regla del equipo), y no sustituye validar los datos en el origen (formularios, API) cuando eso es posible.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza el código en busca de accesos a propiedades o funciones sobre valores que pueden ser null o undefined (según el tipado o el flujo de datos), e instala guardas: encadenamiento opcional, operadores de coalescencia nula, valores por defecto o validaciones tempranas con un mensaje de error claro.","modo":"Blindaje defensivo","pasos":["Identificar, mediante el compilador de tipos o análisis del flujo de datos, los puntos donde un valor puede ser null o undefined sin control.","Priorizar las zonas donde ese acceso ya causó errores en logs o reportes, si existen.","Añadir encadenamiento opcional, valores por defecto o validaciones tempranas según el caso.","Verificar que el comportamiento cuando el dato falta sea explícito (mensaje de error o valor por defecto), no un fallo silencioso.","Ejecutar la suite de pruebas para confirmar que no se alteró el comportamiento en el camino feliz."],"reglas":["No enmascarar el problema con un try/catch vacío que ignore el error sin registrar ni decidir qué pasa después.","Priorizar la validación en el punto de entrada de los datos sobre parchear cada uso individual, cuando sea posible.","Dejar constancia (comentario o log) cuando un valor por defecto se eligió de forma arbitraria, para que un humano lo revise."],"prompt":"Analiza el código de [carpeta o módulo] y localiza los puntos donde se accede a propiedades o se llama a funciones sobre valores que el compilador marca como potencialmente null o undefined, o que provienen de datos externos sin validar (respuestas de API, inputs de usuario). Para cada punto, añade la protección más adecuada: encadenamiento opcional, operador de coalescencia nula, valor por defecto explícito, o una validación temprana que lance un error claro. No uses try/catch vacíos ni silencies el problema. Si un valor por defecto es una decisión de negocio (no solo técnica), déjalo señalado con un comentario para que el equipo lo confirme. Al final, ejecuta la suite de pruebas y confirma que el comportamiento existente no cambió."}},
  {"id":"sw54","catalogo":"software","grupo":"Calidad y pruebas","tema":"Corrección Autónoma de Errores","titulo":"Evita que una respuesta inesperada de un proveedor externo tumbe tu aplicación","beneficio":"Cuando una API externa (pasarela de pago, CRM, servicio de envío) cambia su respuesta o falla, tu aplicación no debería caerse entera; el agente añade el manejo de errores necesario para que un JSON malformado se detecte y gestione, no que rompa el proceso.","alcance":"Cubre el manejo defensivo al parsear y validar respuestas JSON de servicios externos ya integrados. No puede anticipar cambios futuros no documentados en la API externa, ni sustituye monitorización activa del proveedor en producción.","precio":1.99,"blueprint":{"quePuedeHacer":"Localiza los puntos donde el código parsea JSON proveniente de llamadas a APIs externas (fetch, axios, clientes HTTP), envuelve el parseo en manejo de errores explícito, valida la forma esperada de la respuesta antes de usarla, y define un comportamiento de repliegue (error controlado, reintento o valor por defecto) cuando la respuesta no cumple lo esperado.","modo":"Blindaje de integraciones externas","pasos":["Localizar todas las llamadas a APIs externas y sus puntos de parseo de la respuesta.","Envolver cada deserialización JSON en manejo de errores explícito.","Validar la forma mínima esperada de la respuesta (campos requeridos) antes de usarla en el resto del código.","Definir qué ocurre cuando la validación falla: error controlado hacia el usuario, log y reintento, o valor de repliegue.","Añadir pruebas que simulen respuestas malformadas o incompletas para confirmar que el manejo funciona."],"reglas":["Nunca dejar que un fallo de parseo se propague como una excepción no controlada hasta el usuario final.","Registrar (log) el contenido problemático recibido cuando el parseo falla, para poder diagnosticar con el proveedor.","No asumir campos opcionales como presentes sin validarlos primero."],"prompt":"Localiza en el código todas las llamadas a APIs o servicios externos ([nombrar el servicio si se conoce, por ejemplo la pasarela de pago o el CRM]) y examina cómo se procesa la respuesta. Para cada punto donde se parsea o deserializa JSON de esa respuesta, añade manejo de errores explícito que capture tanto un JSON malformado como una estructura que no cumpla los campos mínimos esperados. Define y aplica un comportamiento de repliegue claro (error controlado con mensaje útil, log del contenido recibido, y si corresponde un reintento) en lugar de dejar que la excepción se propague sin control. Escribe tests que simulen respuestas incompletas, vacías o con tipos incorrectos para esa integración y confirma que la aplicación las maneja sin caerse."}},
  {"id":"sw55","catalogo":"software","grupo":"Calidad y pruebas","tema":"Corrección Autónoma de Errores","titulo":"Corrige las fugas que hacen que tu aplicación se vuelva más lenta cuanto más tiempo lleva encendida","beneficio":"Si tu aplicación se degrada con el uso prolongado (una pestaña abierta todo el día, un proceso en servidor que hay que reiniciar cada cierto tiempo), suele deberse a recursos que nunca se liberan; el agente localiza y corrige esas fugas en el código.","alcance":"Cubre fugas de memoria originadas en el código de la aplicación (temporizadores, listeners de eventos, suscripciones no canceladas). No detecta fugas causadas por librerías de terceros a nivel binario ni sustituye un profiler de memoria en producción para casos complejos.","precio":1.99,"blueprint":{"quePuedeHacer":"Revisa el código en busca de temporizadores (setInterval, setTimeout), listeners de eventos, suscripciones o watchers que se crean pero nunca se limpian (falta de clearInterval, removeEventListener, unsubscribe o equivalente en el ciclo de vida del componente/proceso), y añade la limpieza correspondiente.","modo":"Detección y limpieza de recursos","pasos":["Buscar en el código todas las creaciones de temporizadores, listeners de eventos y suscripciones.","Para cada una, verificar si existe una limpieza correspondiente en el ciclo de vida adecuado (desmontaje de componente, fin de proceso, cierre de conexión).","Añadir la limpieza faltante (clearInterval, removeEventListener, unsubscribe) en el punto correcto del ciclo de vida.","Verificar que la limpieza no se ejecute antes de tiempo (rompiendo funcionalidad que aún necesita el recurso).","Si el framework lo permite, ejecutar o describir una prueba manual que confirme que el recurso se libera al desmontar/cerrar."],"reglas":["No eliminar un temporizador o listener sin verificar que ya no se necesita en algún otro flujo del código.","Priorizar la limpieza en el punto de desmontaje/cierre estándar del framework en uso, en vez de soluciones ad-hoc.","Señalar con un comentario los casos donde la limpieza no se pudo verificar automáticamente, para revisión manual."],"prompt":"Revisa el código de [carpeta o módulo] en busca de temporizadores (setInterval, setTimeout), listeners de eventos (addEventListener, on/emit) y suscripciones (observables, watchers) que se crean pero no tienen una limpieza correspondiente en el ciclo de vida del componente o proceso. Para cada caso, añade la limpieza que falte (clearInterval, removeEventListener, unsubscribe) en el punto correcto (por ejemplo, el hook de desmontaje del componente o el cierre de la conexión). Antes de eliminar o mover cualquier limpieza existente, confirma que el recurso no se usa en otro flujo. Señala con un comentario los casos donde no puedas verificar con certeza que la limpieza es segura, para que alguien del equipo lo revise manualmente."}},
  {"id":"sw56","catalogo":"software","grupo":"Calidad y pruebas","tema":"Creación de Suites de Pruebas Unitarias","titulo":"Genera una red de seguridad de pruebas para las funciones clave de tu negocio","beneficio":"Cuando un servicio central (cálculo de precios, validación de pedidos, reglas de facturación) no tiene pruebas, cualquier cambio futuro es un salto al vacío; el agente escribe una suite que cubre sus caminos lógicos principales para que el equipo pueda modificar el código con confianza.","alcance":"Genera pruebas para la lógica que ya existe y su comportamiento actual documentado en el código. No garantiza que la lógica sea la correcta desde el punto de vista de negocio (eso requiere validación humana) ni sustituye pruebas de extremo a extremo del sistema completo.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza un servicio o módulo, identifica sus funciones públicas y las ramas condicionales dentro de ellas (if/else, switch, early returns), y genera un archivo de pruebas unitarias que ejercite cada camino lógico relevante con casos representativos.","modo":"Generación de tests","pasos":["Leer el código del servicio y listar sus funciones públicas.","Para cada función, identificar las ramas condicionales y los caminos de ejecución posibles.","Diseñar casos de prueba que cubran cada camino, incluyendo el camino feliz y los caminos alternativos.","Escribir el archivo de test siguiendo las convenciones del proyecto (framework de testing, estructura de carpetas).","Ejecutar la nueva suite y confirmar que todos los tests pasan contra el código actual.","Reportar qué caminos, si los hay, no se pudieron cubrir y por qué."],"reglas":["Los tests deben verificar el comportamiento real y documentado del código, no inventarse un comportamiento deseado no implementado.","Cada camino condicional identificado debe tener al menos un caso de prueba asociado.","No duplicar la lógica del servicio dentro del test (por ejemplo, reimplementando el cálculo) para \"validar\" el resultado; usar valores esperados fijos y verificables."],"prompt":"Analiza el servicio [ruta del archivo, por ejemplo src/services/pricing.ts] y lista sus funciones públicas junto con las ramas condicionales (if/else, switch, early returns) que contiene cada una. Genera un archivo de pruebas unitarias en la ubicación y con el framework que ya usa el proyecto (revisa un archivo de test existente como referencia de convenciones). Escribe al menos un caso de prueba por cada camino lógico identificado, incluyendo el camino principal y los casos alternativos o de error. Los valores esperados deben ser fijos y verificables, no recalculados dentro del test. Ejecuta la suite generada y confirma que todos los tests pasan. Al final, indica si algún camino lógico quedó sin cubrir y por qué."}},
  {"id":"sw57","catalogo":"software","grupo":"Calidad y pruebas","tema":"Creación de Suites de Pruebas Unitarias","titulo":"Haz que tus pruebas corran en segundos, no en minutos, sin depender de servidores externos","beneficio":"Si las pruebas del equipo dependen de que un servicio externo esté disponible y responda rápido, se vuelven lentas, frágiles y a veces fallan por causas ajenas al código; el agente sustituye esas llamadas de red por mocks locales para que las pruebas sean rápidas y fiables.","alcance":"Aísla las pruebas unitarias de dependencias de red reales sustituyéndolas por respuestas simuladas. No reemplaza las pruebas de integración que sí necesitan verificar la comunicación real con el servicio externo, ni detecta cambios reales en el contrato de la API si esta cambia.","precio":1.99,"blueprint":{"quePuedeHacer":"Identifica las llamadas de red dentro del código bajo prueba (fetch, axios, clientes HTTP/SDK de terceros), las sustituye en el entorno de test por mocks (usando las herramientas de mocking del framework de testing en uso), y define respuestas simuladas representativas de los casos de éxito y error reales del servicio.","modo":"Aislamiento de dependencias externas","pasos":["Identificar todas las llamadas de red que hace el código bajo prueba.","Determinar el punto de interceptación adecuado (cliente HTTP, módulo del SDK, capa de servicio) para insertar el mock.","Configurar mocks con las herramientas ya disponibles en el proyecto (o las estándar del ecosistema si no hay ninguna).","Definir respuestas simuladas para el caso de éxito y al menos un caso de error realista (timeout, 4xx, 5xx).","Ejecutar la suite de pruebas sin conexión a red y confirmar que pasa de forma determinista."],"reglas":["El mock debe simular la forma real de la respuesta del servicio (basada en su documentación o en respuestas ya observadas), no una estructura inventada sin relación con la realidad.","No mezclar pruebas unitarias con mocks y pruebas de integración reales en el mismo archivo sin distinguirlas claramente.","Dejar documentado en el test qué versión o contrato de la API externa se está simulando, para actualizarlo si esta cambia."],"prompt":"Identifica en [ruta del módulo o servicio] las llamadas de red que hace el código a [nombre del servicio externo, si se conoce]. Configura mocks para esas llamadas usando las herramientas de testing ya presentes en el proyecto (revisa package.json y los tests existentes para saber cuáles). Sustituye la llamada real por el mock en el entorno de test, definiendo una respuesta simulada para el caso de éxito y al menos una para un caso de error real (por ejemplo, un 500 o un timeout). Ejecuta la suite sin conexión a internet y confirma que los tests pasan de forma determinista y rápida. Añade un comentario en el archivo de test indicando qué contrato de la API se está simulando, para que el equipo lo actualice si la API externa cambia."}},
  {"id":"sw58","catalogo":"software","grupo":"Calidad y pruebas","tema":"Creación de Suites de Pruebas Unitarias","titulo":"Descubre antes que tus clientes los casos raros que rompen tu software","beneficio":"Los errores más costosos de soporte suelen venir de los casos que nadie probó: un carrito vacío, una cantidad negativa, un archivo enorme; el agente diseña pruebas específicas para esos extremos antes de que un cliente los encuentre por accidente.","alcance":"Genera pruebas para los casos límite que se pueden inferir del código y su tipado (vacíos, nulos, negativos, límites numéricos, cadenas muy largas). No puede anticipar casos límite que dependen de reglas de negocio no documentadas en el código ni descritas por el equipo.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza las funciones de un módulo y, según el tipo de dato de entrada (arrays, números, cadenas, objetos), genera una batería de pruebas que inyecta valores extremos: colecciones vacías, valores negativos o cero, desbordamientos numéricos, cadenas vacías o muy largas, y objetos con campos faltantes.","modo":"Generación de tests","pasos":["Identificar las funciones del módulo y el tipo de dato que recibe cada parámetro.","Para cada tipo, listar los valores límite relevantes (vacío, nulo, cero, negativo, máximo, cadena vacía o extremadamente larga, según aplique).","Escribir un caso de prueba por cada valor límite identificado, verificando el comportamiento esperado (ya sea un resultado válido o un error controlado).","Ejecutar la suite y registrar qué casos límite el código actual no maneja correctamente.","Reportar los fallos encontrados sin corregirlos automáticamente, salvo que se pida explícitamente."],"reglas":["Un caso límite que revela un fallo real debe reportarse como tal, no descartarse o ajustarse el test para que \"pase\" ocultando el problema.","No inventar límites de negocio (por ejemplo, un máximo de pedido) que no estén ya definidos en el código o la documentación.","Distinguir claramente en el nombre del test qué caso límite se está verificando."],"prompt":"Analiza las funciones del módulo [ruta del archivo] y, para cada parámetro, identifica los valores límite relevantes según su tipo: colecciones vacías, valores nulos o undefined, números negativos o cero, posibles desbordamientos, cadenas vacías o muy largas. Escribe un archivo de pruebas que inyecte cada uno de esos valores límite y verifique el comportamiento resultante (ya sea un resultado correcto o un error controlado y explícito). Ejecuta la suite. Si algún caso límite provoca un comportamiento incorrecto o una excepción no controlada, repórtalo claramente en el resumen final, sin modificar el test para ocultar el fallo ni corregir el código a menos que te lo pida explícitamente."}},
  {"id":"sw59","catalogo":"software","grupo":"Calidad y pruebas","tema":"Creación de Suites de Pruebas Unitarias","titulo":"Confirma que tu interfaz reacciona como debe cuando un usuario hace clic, escribe o navega","beneficio":"Un botón que deja de funcionar tras un cambio de código puede pasar desapercibido hasta que un cliente se queja; el agente escribe pruebas que simulan las interacciones reales del usuario y verifican que la interfaz responde correctamente.","alcance":"Cubre pruebas de integración de componentes de UI dentro de un entorno de test (simulación de eventos, cambios de estado visibles). No sustituye pruebas manuales de diseño visual/estético ni pruebas end-to-end en navegadores reales contra el entorno de producción.","precio":1.99,"blueprint":{"quePuedeHacer":"Identifica los componentes de UI con estado (formularios, listas filtrables, modales, wizards) y escribe pruebas de integración usando la librería de testing de componentes ya presente en el proyecto (por ejemplo Testing Library), simulando eventos de usuario (clic, escritura, envío de formulario) y verificando los cambios de estado visibles resultantes.","modo":"Generación de tests","pasos":["Identificar el componente de UI con estado y los eventos de usuario que puede recibir.","Determinar qué cambio visible o de estado se espera tras cada evento (aparece un mensaje, se habilita un botón, cambia una lista).","Escribir el test simulando el evento con la librería de testing de componentes del proyecto.","Verificar el resultado esperado consultando el DOM renderizado (texto visible, atributos, presencia/ausencia de elementos), no detalles internos de implementación.","Ejecutar la suite y confirmar que los tests son estables (no dependen de temporización arbitraria)."],"reglas":["Verificar el comportamiento observable por el usuario (lo que ve o puede hacer), no detalles internos de implementación del componente.","No usar esperas fijas (temporizadores arbitrarios) para sincronizar el test con la UI; usar las utilidades de espera asíncrona de la librería de testing.","Un test de UI que depende de datos de red debe usar mocks, no llamadas reales."],"prompt":"Identifica en [ruta del componente] los eventos de usuario que maneja (clics, escritura en campos, envío de formulario, selección de opciones) y qué cambio de estado o de interfaz se espera tras cada uno. Usando la librería de testing de componentes ya configurada en el proyecto, escribe pruebas de integración que simulen esos eventos y verifiquen el resultado visible (texto renderizado, elementos que aparecen o desaparecen, estado habilitado/deshabilitado), sin acceder a detalles internos de implementación del componente. Usa las utilidades de espera asíncrona de la librería (no temporizadores fijos) para sincronizar con actualizaciones de estado. Si el componente depende de datos de red, usa un mock en vez de una llamada real. Ejecuta la suite y confirma que los tests son estables al repetirlos."}},
  {"id":"sw60","catalogo":"software","grupo":"Calidad y pruebas","tema":"Creación de Suites de Pruebas Unitarias","titulo":"Blinda el comportamiento de tus funciones críticas para que un cambio futuro no las rompa sin avisar","beneficio":"Cuando se corrige un bug importante o se ajusta una función sensible del negocio, el riesgo es que alguien la rompa de nuevo meses después sin darse cuenta; el agente fija ese comportamiento con pruebas de regresión que actúan como alarma temprana.","alcance":"Fija el comportamiento actual verificado como correcto de funciones ya revisadas. No determina por sí mismo si el comportamiento actual es el deseado (requiere confirmación humana, especialmente tras corregir un bug) ni protege código que aún no tiene ninguna prueba base.","precio":1.99,"blueprint":{"quePuedeHacer":"A partir de una función recientemente modificada o un bug recién corregido, genera un test de regresión que fija el comportamiento correcto verificado, usando el caso específico que causó el bug original como uno de los casos de prueba, además de los casos normales de uso.","modo":"Generación de tests","pasos":["Identificar la función o módulo recientemente modificado (a partir del commit, el bug reportado o la indicación del usuario).","Reconstruir el caso específico que causó el fallo original, si aplica, como un caso de prueba concreto.","Añadir casos de prueba adicionales para el comportamiento normal de la función, no solo el caso del bug.","Confirmar con el resultado actual (ya corregido) que el test pasa, y dejarlo como referencia futura.","Nombrar el test de forma que referencie el bug o el comportamiento que protege, para trazabilidad."],"reglas":["El test de regresión debe fijar un comportamiento ya verificado como correcto por una persona, no una suposición del agente sobre qué \"debería\" pasar.","Incluir el caso específico que causó el bug original siempre que se pueda reconstruir, no solo casos genéricos.","No usar snapshots opacos y masivos como sustituto de una aserción explícita cuando el comportamiento se puede verificar de forma directa."],"prompt":"La función [nombre/ruta de la función] fue modificada recientemente para corregir el bug: [describir el bug, o pegar el reporte/commit]. Escribe un test de regresión que reconstruya exactamente el caso que causaba el fallo original y verifique que ahora produce el resultado correcto. Añade también 2-3 casos de prueba para el comportamiento normal (no relacionado con el bug) de la misma función, para asegurar que la corrección no alteró el resto de su lógica. Nombra los tests de forma que quede claro qué bug o comportamiento protegen (por ejemplo, incluyendo el número de issue si existe). Ejecuta la suite y confirma que todo pasa contra el código actual."}},
  {"id":"sw61","catalogo":"software","grupo":"Calidad y pruebas","tema":"Infraestructura de Pruebas Avanzada","titulo":"Genera datos de prueba realistas al instante, sin depender de copiar información real de clientes","beneficio":"Preparar datos de prueba a mano es lento y a veces implica usar datos reales de clientes, con el riesgo de privacidad que eso conlleva; el agente construye generadores reutilizables que crean entidades ficticias coherentes con el modelo de datos real.","alcance":"Genera datos ficticios estructuralmente válidos según el modelo de datos del proyecto (esquemas, tipos, modelos ORM). No garantiza que los datos generados representen todos los escenarios de negocio relevantes (eso requiere criterio del equipo) ni sustituye datos reales anonimizados cuando se necesita representatividad estadística real.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza los modelos de datos o esquemas del proyecto (tipos, modelos ORM, esquemas de validación) y construye funciones \"factory\" reutilizables que generan entidades ficticias válidas con valores por defecto sensatos y la posibilidad de sobrescribir campos específicos por test.","modo":"Generación de infraestructura de pruebas","pasos":["Identificar los modelos o esquemas de datos principales del dominio (usuario, pedido, producto, etc.).","Para cada modelo, definir una función factory que genere una instancia válida con valores por defecto razonables.","Permitir que cada factory acepte overrides parciales para personalizar campos específicos por test.","Usar una librería de datos aleatorios ya presente en el proyecto, o una estándar del ecosistema, para valores como nombres o fechas si aplica.","Verificar que las entidades generadas pasan la validación del propio modelo (esquema/tipo) del proyecto.","Documentar brevemente cómo usar cada factory en los tests."],"reglas":["Los datos generados deben pasar la validación real del esquema/modelo del proyecto, no ser una aproximación que rompería en producción.","No incluir datos reales de clientes ni información sensible como base de los valores por defecto.","Las factories deben ser deterministas cuando se les pasan los mismos overrides, para no producir tests intermitentes por aleatoriedad no controlada."],"prompt":"Analiza los modelos de datos o esquemas de [ruta, por ejemplo src/models o src/schemas] y crea funciones factory reutilizables para los 2-3 modelos principales del dominio (por ejemplo, usuario y pedido). Cada factory debe generar una instancia válida según el esquema/tipo real del proyecto, con valores por defecto razonables, y aceptar un objeto de overrides parcial para personalizar campos específicos en cada test. Verifica que las entidades generadas pasan la validación del propio esquema. No uses ni referencies datos reales de clientes. Si usas valores aleatorios (nombres, fechas), controla la semilla o el rango para que los tests sean deterministas. Añade un comentario de ejemplo de uso en cada factory."}},
  {"id":"sw62","catalogo":"software","grupo":"Calidad y pruebas","tema":"Infraestructura de Pruebas Avanzada","titulo":"Ejecuta tu suite de pruebas de base de datos en segundos, sin tocar ni un solo dato real","beneficio":"Probar contra una base de datos real es lento y arriesgado si algo falla; el agente configura un entorno de pruebas que redirige las consultas hacia una base de datos volátil en memoria, para pruebas rápidas y sin riesgo de dañar datos reales.","alcance":"Sirve para pruebas unitarias y de integración que no dependen de características muy específicas del motor de base de datos real (extensiones, procedimientos almacenados particulares). No sustituye pruebas contra una réplica del motor real de producción antes de un despliegue crítico, si esas diferencias importan.","precio":1.99,"blueprint":{"quePuedeHacer":"Configura el entorno de test para que las operaciones de base de datos se dirijan a una instancia en memoria o efímera (según el motor: SQLite en memoria, una librería de mocking de ORM, o un contenedor efímero), incluyendo la creación del esquema y su reseteo entre pruebas.","modo":"Configuración de entorno de pruebas","pasos":["Identificar el ORM o cliente de base de datos que usa el proyecto y sus opciones de configuración para entornos de test.","Configurar una instancia en memoria o efímera equivalente (SQLite en memoria u otra opción soportada por el ORM/framework en uso).","Aplicar el esquema o las migraciones necesarias sobre esa instancia antes de ejecutar las pruebas.","Asegurar que el estado se resetea entre pruebas (o entre archivos de test) para evitar dependencia de orden.","Ejecutar la suite de pruebas de base de datos contra este entorno y confirmar que pasa sin conexión a la base real."],"reglas":["Nunca apuntar la suite de pruebas automatizada a la base de datos de producción o de un entorno compartido con datos reales.","Documentar explícitamente las diferencias conocidas entre el motor en memoria y el motor real de producción, si las hay (tipos de datos, funciones específicas).","Resetear el estado entre pruebas para que ninguna dependa del orden de ejecución de las demás."],"prompt":"Configura el entorno de pruebas del proyecto para que las operaciones de base de datos usen una instancia en memoria o efímera en lugar de la base de datos real. Identifica primero el ORM o cliente de base de datos en uso (revisa package.json y la configuración de conexión) y elige la opción de base en memoria compatible (por ejemplo, SQLite en memoria si el proyecto usa un ORM agnóstico de motor, o el modo de test del ORM si lo soporta). Aplica el esquema/migraciones sobre esa instancia antes de las pruebas y asegúrate de que el estado se limpia entre archivos de test para evitar dependencias de orden. Si el motor real de producción usa alguna característica que la base en memoria no soporta (tipos de datos, extensiones), documéntalo claramente en el archivo de configuración de test. Confirma al final que la suite de pruebas de base de datos corre sin necesidad de conexión externa."}},
  {"id":"sw63","catalogo":"software","grupo":"Calidad y pruebas","tema":"Infraestructura de Pruebas Avanzada","titulo":"Prueba en segundos comportamientos que en la realidad tardan días en manifestarse","beneficio":"Verificar que una suscripción caduca a los 30 días, o que un descuento deja de aplicar pasada una fecha, no debería requerir esperar 30 días reales; el agente controla el reloj del sistema en las pruebas para simular el paso del tiempo de forma instantánea y fiable.","alcance":"Cubre lógica de negocio que depende explícitamente de la fecha/hora del sistema dentro del código de la aplicación. No controla el tiempo de sistemas externos (por ejemplo, la caducidad que gestiona un proveedor de pagos externo) ni sustituye pruebas de integración reales antes de un cambio crítico de facturación.","precio":1.99,"blueprint":{"quePuedeHacer":"Localiza la lógica que depende de la fecha/hora actual del sistema, y en el entorno de test la sustituye por un reloj controlado (usando las utilidades de fake timers del framework de testing en uso) que permite fijar una fecha concreta o avanzar el tiempo de forma controlada, sin modificar el reloj real del sistema operativo.","modo":"Control de tiempo en pruebas","pasos":["Identificar en el código las dependencias de la fecha/hora actual relevantes para la lógica a probar (caducidad, periodos de prueba, descuentos con vigencia).","Configurar los fake timers o utilidades de fecha controlada del framework de testing ya presente en el proyecto.","Escribir tests que fijen una fecha concreta antes de ejecutar la lógica bajo prueba (por ejemplo, justo antes de caducar y justo después).","Escribir tests que avancen el tiempo de forma controlada dentro del test, si la lógica depende de la duración transcurrida.","Restaurar el reloj real al finalizar cada test para no afectar otras pruebas de la suite."],"reglas":["Nunca modificar el reloj real del sistema operativo o del entorno CI; el control de tiempo debe limitarse al proceso de test mediante las utilidades del framework.","Restaurar siempre el estado del reloj al finalizar cada test, incluso si el test falla.","Probar explícitamente los límites (justo antes/justo después del umbral de tiempo), no solo un punto intermedio arbitrario."],"prompt":"Localiza en [ruta del módulo] la lógica que depende de la fecha u hora actual (por ejemplo, caducidad de una suscripción, vigencia de un descuento, periodos de prueba). Usando las utilidades de fake timers del framework de testing ya configurado en el proyecto, escribe tests que fijen fechas concretas para verificar el comportamiento justo antes y justo después de cada umbral relevante (por ejemplo, el último día válido y el primer día caducado). Si la lógica depende de tiempo transcurrido en lugar de una fecha fija, usa el avance controlado de tiempo del framework en vez de esperas reales. Asegúrate de restaurar el reloj real al finalizar cada test, incluso si falla, para no afectar el resto de la suite."}},
  {"id":"sw64","catalogo":"software","grupo":"Calidad y pruebas","tema":"Infraestructura de Pruebas Avanzada","titulo":"Detecta antes que tus usuarios los errores que solo aparecen cuando dos acciones ocurren a la vez","beneficio":"Algunos de los bugs más difíciles de reproducir ocurren solo cuando dos procesos compiten por el mismo recurso al mismo tiempo (dos pagos simultáneos, dos actualizaciones al mismo registro); el agente diseña pruebas que fuerzan esa concurrencia para exponer el problema en un entorno controlado.","alcance":"Diseña pruebas que simulan llamadas concurrentes dentro del entorno de test para exponer condiciones de carrera detectables de esta forma. No garantiza encontrar todas las condiciones de carrera posibles (algunas dependen de temporización específica de infraestructura de producción) ni sustituye pruebas de carga en un entorno real.","precio":1.99,"blueprint":{"quePuedeHacer":"Identifica operaciones que acceden o modifican un recurso compartido (contador, saldo, fila de base de datos) y escribe pruebas que disparan varias invocaciones concurrentes de esa operación (usando Promise.all u otro mecanismo de concurrencia del lenguaje/framework), verificando que el resultado final es consistente y no refleja una condición de carrera (pérdida de actualizaciones, valores duplicados).","modo":"Simulación de concurrencia","pasos":["Identificar las operaciones del código que leen y escriben sobre un recurso compartido sin aislamiento explícito.","Diseñar un test que dispare varias invocaciones concurrentes de esa operación sobre el mismo recurso.","Definir el resultado esperado si la operación fuera perfectamente segura ante concurrencia (por ejemplo, un contador que suma exactamente N incrementos).","Ejecutar el test y comparar el resultado real con el esperado para detectar pérdida de actualizaciones o inconsistencias.","Si se detecta una condición de carrera, reportarla con el escenario mínimo que la reproduce, antes de proponer una corrección."],"reglas":["El test debe reflejar un escenario de concurrencia realista para el sistema (mismo recurso, mismo tipo de operación), no una condición artificial imposible en producción.","Reportar la condición de carrera detectada de forma explícita y reproducible, no descartarla como \"ruido\" del test.","No introducir bloqueos o cambios de sincronización en el código de producción sin que se pida explícitamente; primero exponer el problema."],"prompt":"Analiza [ruta del módulo, por ejemplo src/services/inventario.ts] y localiza operaciones que leen y modifican un recurso compartido (por ejemplo, el stock de un producto o el saldo de una cuenta) sin control explícito de concurrencia. Escribe un test que dispare varias invocaciones concurrentes de esa operación sobre el mismo recurso (usando Promise.all o el mecanismo de concurrencia equivalente del lenguaje) y compara el resultado final con el que se obtendría si la operación fuera perfectamente segura (por ejemplo, el stock exacto tras N decrementos simultáneos). Ejecuta el test. Si detectas pérdida de actualizaciones o un resultado inconsistente, documenta el escenario mínimo que reproduce el problema en el reporte final, pero no apliques ninguna corrección al código de producción a menos que te lo pida explícitamente."}},
  {"id":"sw65","catalogo":"software","grupo":"Calidad y pruebas","tema":"Infraestructura de Pruebas Avanzada","titulo":"Confirma que tu aplicación falla de forma controlada, no de cualquier manera, cuando algo sale mal","beneficio":"No basta con que el código funcione cuando todo va bien: el negocio necesita saber que, cuando algo falla (un pago rechazado, un archivo corrupto), la aplicación responde con el error correcto y no con un comportamiento indefinido; el agente escribe pruebas dedicadas a verificar exactamente eso.","alcance":"Verifica que el código lanza o gestiona las excepciones ya previstas en su diseño (documentadas en tipos, comentarios o lógica condicional existente). No decide qué errores debería lanzar el sistema si eso aún no está definido: eso es una decisión de diseño que corresponde al equipo.","precio":1.99,"blueprint":{"quePuedeHacer":"Identifica los puntos del código donde se lanzan o gestionan excepciones de forma explícita (bloques try/catch, validaciones que lanzan errores, tipos de error personalizados) y escribe pruebas que fuercen esas condiciones de fallo para verificar que se lanza exactamente el tipo y mensaje de error esperado, no un error genérico o distinto.","modo":"Generación de tests","pasos":["Localizar en el código los puntos donde se lanzan excepciones o errores personalizados de forma explícita.","Para cada uno, identificar la condición exacta que lo dispara.","Escribir un test que fuerce esa condición y verifique el tipo y contenido específico del error lanzado.","Verificar también que, en el camino correcto (sin la condición de error), no se lanza ninguna excepción.","Ejecutar la suite y confirmar que todos los casos de error previstos están cubiertos con una prueba dedicada."],"reglas":["Verificar el tipo y/o mensaje específico del error, no solo que \"algo\" fue lanzado, para detectar si el error incorrecto se dispara por la razón incorrecta.","No inventar tipos de error nuevos que el código no lanza actualmente; documentar solo el comportamiento existente.","Incluir siempre un test del camino correcto para confirmar que la condición de error no se dispara de forma indebida."],"prompt":"Localiza en [ruta del módulo] los puntos donde el código lanza excepciones o errores personalizados de forma explícita (bloques try/catch con throw, validaciones que lanzan errores, clases de error propias). Para cada uno, escribe un test que fuerce la condición exacta que dispara ese error y verifique que se lanza el tipo y el mensaje específico esperado (no solo que \"lanza un error\"). Añade también un test que confirme que, en el camino correcto, esa excepción no se dispara. Ejecuta la suite y, al final, indica si encontraste puntos del código que deberían manejar un error pero actualmente no lo hacen (sin corregirlos, solo repórtalos)."}},
  {"id":"sw66","catalogo":"software","grupo":"Calidad y pruebas","tema":"Diagnóstico de Logs, Terminal y Trazabilidad","titulo":"Traduce el mensaje de error incomprensible de la consola en una solución concreta","beneficio":"Cuando algo falla y la consola escupe un volcado de error largo y técnico, el equipo pierde tiempo descifrándolo; el agente interpreta esa traza, localiza exactamente la línea de código responsable y aplica la corrección.","alcance":"Funciona sobre errores que dejan una traza de pila legible (stack trace) en consola o logs. No puede diagnosticar fallos que no dejan ningún rastro en consola/logs (por ejemplo, un resultado incorrecto sin excepción) ni errores en dependencias de terceros sin código fuente disponible más allá de lo que la traza indica.","precio":1.99,"blueprint":{"quePuedeHacer":"Recibe o captura un stack trace de un error real (de consola, terminal o logs), identifica el archivo, la función y la línea exacta donde se originó el fallo, distingue entre el punto donde el error se lanzó y el punto donde debería haberse manejado, y aplica la corrección en el lugar correcto.","modo":"Diagnóstico de logs","pasos":["Recibir o capturar el stack trace completo del error.","Leer la traza identificando el punto de origen real, no solo el último frame mostrado.","Localizar el archivo y la línea de código correspondientes al frame relevante.","Determinar si la corrección debe ir en el punto donde se origina el error o en el punto donde debería capturarse/manejarse.","Aplicar la corrección mínima y verificar reproduciendo el escenario que generó el error originalmente."],"reglas":["Identificar el frame de la traza que pertenece al código propio del proyecto, no limitarse al primer frame que puede pertenecer a una librería externa.","No aplicar una corrección genérica (como envolver todo en try/catch) sin antes entender la causa raíz específica indicada por la traza.","Verificar la corrección reproduciendo o simulando el mismo escenario que generó el error original, no solo revisando el código a simple vista."],"prompt":"Aquí tienes el stack trace de un error real: [pegar el stack trace completo]. Analízalo identificando cuál de los frames corresponde al código propio del proyecto (no a una librería de node_modules o equivalente) y cuál es el punto de origen real del fallo, no necesariamente el primer frame. Localiza el archivo y la línea exacta en el repositorio. Explica en una frase la causa raíz antes de tocar nada. Aplica la corrección mínima en el punto correcto (origen o manejo, según corresponda) y, si existe una forma de reproducir el escenario que generó el error (un test, un script, un comando), úsala para confirmar que el error ya no ocurre."}},
  {"id":"sw67","catalogo":"software","grupo":"Calidad y pruebas","tema":"Diagnóstico de Logs, Terminal y Trazabilidad","titulo":"Encuentra la causa raíz de un fallo cruzando pistas dispersas en tus archivos de log","beneficio":"Un error de producción rara vez aparece como una única línea clara: suele estar disperso entre varias advertencias previas en el log; el agente lee los archivos de log locales y conecta esas señales para llegar a la causa raíz más rápido que revisando manualmente cientos de líneas.","alcance":"Analiza archivos de log ya generados y accesibles localmente (o descargados). No tiene acceso en vivo a sistemas de logging remotos o plataformas de observabilidad de terceros salvo que sus datos se exporten a un archivo local, y no sustituye una herramienta de monitorización en producción para alertas en tiempo real.","precio":1.99,"blueprint":{"quePuedeHacer":"Lee uno o varios archivos de log locales, filtra por nivel de severidad, ventana de tiempo o patrón relevante al incidente investigado, identifica advertencias o errores previos al fallo principal que puedan estar relacionados causalmente, y construye una hipótesis de causa raíz conectando esos eventos en orden cronológico.","modo":"Diagnóstico de logs","pasos":["Localizar el/los archivo(s) de log relevantes y la ventana de tiempo aproximada del incidente.","Filtrar las entradas por esa ventana y por niveles de severidad relevantes (warning, error).","Ordenar cronológicamente los eventos y buscar advertencias previas al fallo principal que puedan estar relacionadas.","Construir una hipótesis de causa raíz que conecte los eventos encontrados, no solo el mensaje de error final.","Señalar en el código las zonas correspondientes a los eventos identificados, si aplica, para su corrección."],"reglas":["Basar la hipótesis de causa raíz en evidencia concreta del log (eventos y timestamps citados), no en especulación sin respaldo.","Distinguir claramente entre \"lo que el log confirma\" y \"lo que se infiere\", dejando explícito el nivel de certeza.","No modificar ni truncar los archivos de log originales durante el análisis."],"prompt":"Lee el archivo de log en [ruta del archivo de log] y concéntrate en la ventana de tiempo alrededor de [hora aproximada o descripción del incidente]. Filtra las entradas con nivel warning o superior en esa ventana y ordénalas cronológicamente. Identifica si hay advertencias previas al error principal que puedan estar causalmente relacionadas con él. Construye una hipótesis de causa raíz citando los eventos concretos del log que la respaldan, distinguiendo claramente entre lo que el log confirma directamente y lo que es una inferencia razonable. Si la causa apunta a una zona específica del código, indícala, pero no apliques ninguna corrección todavía: primero presenta el diagnóstico."}},
  {"id":"sw68","catalogo":"software","grupo":"Calidad y pruebas","tema":"Diagnóstico de Logs, Terminal y Trazabilidad","titulo":"Ilumina el código que no se deja depurar, capturando exactamente qué valores tenía en el momento del fallo","beneficio":"Hay errores que solo se explican viendo qué valores tenían las variables en el momento exacto del fallo; el agente añade puntos de registro temporales en el lugar preciso, ejecuta el escenario problemático y analiza los datos capturados para resolver el misterio.","alcance":"Sirve para diagnosticar comportamientos difíciles de reproducir por inspección estática del código. Requiere poder ejecutar el escenario problemático (localmente o en un entorno de prueba) para capturar los datos; los puntos de registro añadidos son temporales y deben retirarse antes de publicar el código.","precio":1.99,"blueprint":{"quePuedeHacer":"Identifica el tramo de código donde ocurre un comportamiento difícil de diagnosticar, inserta instrumentación temporal (logs detallados con las variables relevantes en ese punto), ejecuta el escenario que reproduce el problema, analiza los valores capturados para identificar la causa, y deja preparado el punto donde esos logs temporales deben retirarse.","modo":"Instrumentación y diagnóstico","pasos":["Identificar el tramo de código donde ocurre el comportamiento difícil de explicar.","Insertar logs temporales que capturen el valor de las variables relevantes justo antes y después del punto sospechoso.","Ejecutar o solicitar la ejecución del escenario que reproduce el problema.","Analizar los valores capturados para confirmar o descartar la hipótesis sobre la causa.","Aplicar la corrección basada en la evidencia recogida y retirar explícitamente los logs temporales añadidos."],"reglas":["Marcar claramente los logs de instrumentación temporal (por ejemplo, con un prefijo distintivo) para poder localizarlos y retirarlos después.","No dejar la instrumentación temporal en el código que se entrega o publica; debe retirarse una vez resuelto el diagnóstico.","No registrar en los logs datos sensibles (contraseñas, tokens, datos personales) ni siquiera de forma temporal."],"prompt":"En [ruta del archivo/función], estamos investigando el siguiente comportamiento difícil de explicar: [describir el síntoma]. Inserta logs temporales marcados con el prefijo \"[DEBUG-TEMP]\" que capturen el valor de las variables relevantes justo antes y después del punto donde sospechas que ocurre el problema. No registres información sensible (contraseñas, tokens, datos personales) en estos logs. Después de insertarlos, ejecuta [el comando o escenario que reproduce el problema] y analiza la salida capturada para confirmar o descartar la causa. Una vez identificada la causa raíz y aplicada la corrección, retira todos los logs marcados con \"[DEBUG-TEMP]\" antes de considerar la tarea terminada."}},
  {"id":"sw69","catalogo":"software","grupo":"Calidad y pruebas","tema":"Diagnóstico de Logs, Terminal y Trazabilidad","titulo":"Evita publicar código con anotaciones de depuración olvidadas que un cliente podría llegar a ver","beneficio":"Es fácil olvidar una impresión de depuración antes de publicar, y algunas pueden exponer datos internos o simplemente ensuciar la consola del navegador de un cliente; el agente rastrea y elimina esos restos antes de que lleguen a producción.","alcance":"Detecta y elimina impresiones de depuración explícitas (console.log, print, debugger y equivalentes) dejadas en el código. No decide si un log de nivel producción (usando el sistema de logging oficial del proyecto) es apropiado o no: solo se ocupa de las anotaciones de depuración temporales, no del logging intencional.","precio":1.99,"blueprint":{"quePuedeHacer":"Busca en el código impresiones de depuración temporales (console.log, console.debug, print, sentencias debugger, comentarios tipo \"TODO: quitar esto\") que no formen parte del sistema de logging oficial del proyecto, evalúa si cada una es efectivamente un resto olvidado o un log intencional, y elimina los restos confirmados.","modo":"Limpieza previa a publicación","pasos":["Buscar en el código patrones de depuración temporal (console.log, print, debugger, comentarios de tipo TODO relacionados con depuración).","Para cada resultado, distinguir si pertenece al sistema de logging oficial del proyecto (y por tanto es intencional) o es un resto de depuración.","Eliminar los restos de depuración confirmados.","Verificar que la eliminación no quita un log que en realidad formaba parte de manejo de errores legítimo.","Ejecutar la suite de pruebas para confirmar que la limpieza no alteró el comportamiento del código."],"reglas":["No eliminar llamadas de logging que pertenezcan al sistema de logging oficial del proyecto (por ejemplo, un logger estructurado configurado explícitamente).","Ante la duda sobre si un log es intencional o un resto, señalarlo para revisión humana en vez de eliminarlo silenciosamente.","No eliminar sentencias debugger o logs que estén dentro de bloques claramente marcados como código de test o de desarrollo local, si esos bloques no se publican."],"prompt":"Busca en [carpeta del proyecto, excluyendo tests si aplica] impresiones de depuración temporales: console.log, console.debug, sentencias debugger, print (según el lenguaje), y comentarios del tipo \"TODO: quitar\" relacionados con depuración. Para cada resultado, determina si pertenece al sistema de logging oficial del proyecto (revisa si el proyecto usa un logger estructurado configurado, como winston, pino o similar) o si es un resto olvidado. Elimina los restos confirmados. Si tienes dudas sobre si un log específico es intencional, no lo elimines: lístalo aparte para que el equipo lo revise. Ejecuta la suite de pruebas al final para confirmar que la limpieza no rompió nada."}},
  {"id":"sw70","catalogo":"software","grupo":"Calidad y pruebas","tema":"Diagnóstico de Logs, Terminal y Trazabilidad","titulo":"Comprueba que tu aplicación se recupera con elegancia cuando el servidor le falla, antes de que le pase a un cliente real","beneficio":"Un servidor externo (pago, envío, autenticación) puede caerse en cualquier momento; el agente simula esas caídas de forma controlada para verificar si tu aplicación muestra un mensaje útil y se recupera, o si se queda colgada o rota.","alcance":"Simula respuestas de error de red/servidor dentro del entorno de pruebas o desarrollo (mediante mocks o proxies de intercepción). No provoca caídas reales en servicios de terceros ni sustituye pruebas de resiliencia en un entorno de staging real con tráfico simulado a gran escala.","precio":1.99,"blueprint":{"quePuedeHacer":"Modifica temporalmente, en el entorno de test o desarrollo, las respuestas de una integración externa para simular fallos comunes (timeout, error 500, conexión rechazada, respuesta lenta), y verifica cómo reacciona la aplicación: si muestra un mensaje de error útil, si reintenta, o si el fallo se propaga sin control.","modo":"Ciclo de prueba y corrección","pasos":["Identificar la integración externa a la que se le simulará el fallo.","Configurar, mediante mocking o un proxy de intercepción, una respuesta de error específica (500, timeout, conexión rechazada) para esa integración.","Ejecutar el flujo de la aplicación que depende de esa integración bajo la condición de fallo simulada.","Verificar si la aplicación muestra un mensaje de error controlado, reintenta según lo esperado, o se rompe sin manejo.","Si se detecta manejo insuficiente, corregirlo y repetir la simulación para confirmar la mejora."],"reglas":["La simulación de fallos debe ejecutarse solo en entornos de test o desarrollo, nunca contra servicios reales de producción de terceros.","Probar más de un tipo de fallo (no solo un 500 genérico), ya que timeouts y conexiones rechazadas suelen exponer manejos distintos.","Reportar explícitamente cualquier flujo donde el fallo simulado deje a la aplicación en un estado roto o sin mensaje al usuario."],"prompt":"En el entorno de desarrollo o test, simula que la integración con [nombre del servicio externo, por ejemplo la pasarela de pago] responde con un error 500, después con un timeout, y después con una conexión rechazada (usa mocking o un proxy de intercepción, nunca contra el servicio real). Para cada uno de esos tres escenarios, ejecuta el flujo de la aplicación que depende de esa integración y observa qué ocurre: si se muestra un mensaje de error útil al usuario, si hay un reintento, o si la aplicación queda en un estado roto o sin respuesta. Reporta los resultados de los tres escenarios. Para cualquier escenario donde el manejo sea insuficiente, aplica una corrección y repite la simulación de ese escenario para confirmar que ahora se maneja correctamente."}},
  {"id":"sw71","catalogo":"software","grupo":"Calidad y pruebas","tema":"Pipelines de Integración Continua","titulo":"Haz que cada cambio de código se pruebe solo, antes de llegar a producción","beneficio":"Sin un pipeline automático, la calidad depende de que alguien se acuerde de ejecutar las pruebas antes de fusionar un cambio; el agente configura un flujo de integración continua que ejecuta pruebas y linters automáticamente en cada cambio propuesto.","alcance":"Genera la configuración del pipeline (workflow de CI) para el motor ya elegido por el equipo (GitHub Actions, GitLab CI u otro). No decide la estrategia de despliegue ni sustituye la configuración de infraestructura de producción, y su calidad depende de que la suite de pruebas del proyecto ya sea representativa.","precio":1.99,"blueprint":{"quePuedeHacer":"Redacta el archivo de configuración completo (YAML u equivalente) para el motor de CI en uso, definiendo los disparadores (push, pull request), los pasos de instalación de dependencias, ejecución de linters, ejecución de la suite de pruebas, y la condición de éxito/fallo del pipeline.","modo":"Configuración de pipeline","pasos":["Confirmar el motor de CI en uso o elegido por el equipo (GitHub Actions, GitLab CI, etc.) y la versión del lenguaje/runtime del proyecto.","Definir los disparadores del pipeline (por ejemplo, en cada push y en cada pull request hacia la rama principal).","Configurar los pasos de instalación de dependencias usando el gestor de paquetes ya usado por el proyecto.","Añadir el paso de ejecución de linters/verificación de tipos antes de las pruebas, para fallar rápido en errores baratos.","Añadir el paso de ejecución de la suite de pruebas completa.","Validar la sintaxis del archivo de configuración y, si es posible, ejecutar el pipeline en una rama de prueba para confirmar que funciona."],"reglas":["El pipeline debe fallar (estado rojo) si cualquier paso de linter, tipos o pruebas falla; no debe continuar silenciosamente.","Usar la misma versión de lenguaje/runtime que usa el equipo en desarrollo, no una versión distinta por defecto del motor de CI.","No incluir secretos o credenciales directamente en el archivo de configuración; deben referenciarse desde el gestor de secretos del motor de CI."],"prompt":"Redacta la configuración completa de un pipeline de integración continua para [GitHub Actions / GitLab CI, según corresponda] para este proyecto. El pipeline debe dispararse en cada push y en cada pull request hacia la rama principal. Debe: instalar las dependencias con el gestor de paquetes que usa el proyecto (revisa el lockfile para confirmar cuál es), ejecutar el linter y la verificación de tipos, y ejecutar la suite de pruebas completa, en ese orden, fallando el pipeline si cualquier paso falla. Usa la misma versión del runtime que declara el proyecto (revisa .nvmrc, engines en package.json o equivalente). No incluyas ningún secreto o credencial directamente en el archivo; si se necesita alguno, referencia el mecanismo de secretos del motor de CI. Al final, valida que el YAML generado tiene sintaxis correcta."}},
  {"id":"sw72","catalogo":"software","grupo":"Calidad y pruebas","tema":"Pipelines de Integración Continua","titulo":"Haz que cada ejecución de pruebas en tu pipeline tarde menos, sin sacrificar fiabilidad","beneficio":"Un pipeline de CI lento retrasa cada entrega y desanima al equipo a fusionar cambios pequeños con frecuencia; el agente configura un contenedor especializado y ligero para que las pruebas arranquen y corran más rápido en cada ejecución.","alcance":"Optimiza la imagen de contenedor usada específicamente para ejecutar pruebas en CI (no la imagen de producción). No garantiza una mejora de tiempo concreta y verificable de antemano, el resultado depende del punto de partida, ni sustituye optimizar la propia suite de pruebas si esta es la que es lenta.","precio":1.99,"blueprint":{"quePuedeHacer":"Diseña o ajusta un Dockerfile (o configuración equivalente) especializado para el entorno de CI, usando una imagen base ligera adecuada al runtime del proyecto, aprovechando el cacheo de capas para dependencias, e incluyendo solo las herramientas necesarias para instalar dependencias y ejecutar pruebas (sin herramientas de desarrollo innecesarias en ese contexto).","modo":"Configuración de infraestructura de pruebas","pasos":["Identificar el runtime y la versión exacta que necesita el proyecto para ejecutar sus pruebas.","Elegir una imagen base ligera oficial para ese runtime (por ejemplo, una variante slim o alpine si es compatible con las dependencias del proyecto).","Estructurar el Dockerfile para maximizar el cacheo de capas de dependencias (copiar primero los archivos de manifiesto de dependencias, instalar, y después copiar el resto del código).","Incluir solo las herramientas estrictamente necesarias para instalar dependencias y correr la suite de pruebas.","Probar que la imagen construye correctamente y que la suite de pruebas se ejecuta con éxito dentro de ella."],"reglas":["Verificar que la imagen ligera elegida (alpine u otra) es compatible con todas las dependencias nativas del proyecto antes de adoptarla, ya que algunas librerías no funcionan en variantes minimalistas.","No sacrificar la fiabilidad de las pruebas (por ejemplo, omitiendo pasos de instalación) solo por reducir el tiempo de ejecución.","Mantener esta imagen separada de la imagen usada para producción si sus necesidades son distintas."],"prompt":"Optimiza (o crea si no existe) el Dockerfile usado específicamente para ejecutar las pruebas en el pipeline de CI de este proyecto. Usa una imagen base ligera y oficial adecuada al runtime del proyecto (identifica la versión exacta desde el archivo de configuración correspondiente, como .nvmrc o engines en package.json), verificando primero que esa variante ligera es compatible con las dependencias nativas del proyecto (si las hay). Estructura el Dockerfile para maximizar el cacheo de capas: copia primero los archivos de manifiesto de dependencias, instala, y luego copia el resto del código. Incluye solo lo estrictamente necesario para instalar dependencias y ejecutar la suite de pruebas, sin herramientas de desarrollo innecesarias en este contexto. Construye la imagen localmente y confirma que la suite de pruebas se ejecuta con éxito dentro de ella."}},
  {"id":"sw73","catalogo":"software","grupo":"Calidad y pruebas","tema":"Pipelines de Integración Continua","titulo":"Detecta si tu aplicación ni siquiera arranca, antes de que lo descubra un usuario","beneficio":"El fallo más costoso es el que impide que la aplicación arranque en absoluto tras un despliegue; el agente añade al pipeline un control de humo que levanta la aplicación brevemente y confirma que responde, antes de considerar el despliegue exitoso.","alcance":"Verifica que la aplicación arranca y responde a una petición mínima (health check o página principal) dentro del pipeline. No sustituye pruebas funcionales completas ni garantiza que toda la funcionalidad interna esté correcta: solo confirma que el sistema está \"vivo\".","precio":1.99,"blueprint":{"quePuedeHacer":"Añade al pipeline de CI un paso que construye y levanta la aplicación (o un contenedor equivalente), espera a que esté lista, realiza una petición mínima a un endpoint de salud o a la página principal, verifica una respuesta exitosa (código de estado esperado), y detiene la aplicación al finalizar el control.","modo":"Control de humo automatizado","pasos":["Confirmar si el proyecto ya tiene un endpoint de salud (health check) o, si no, identificar una ruta mínima que sirva para este propósito.","Añadir al pipeline un paso que construya y levante la aplicación (o su contenedor) en segundo plano.","Esperar de forma controlada (con reintentos con límite, no una espera fija arbitraria) a que la aplicación responda.","Realizar la petición al endpoint de salud/página principal y verificar el código de estado esperado.","Detener la aplicación levantada al finalizar el control, y fallar el pipeline si la aplicación nunca respondió dentro del límite de reintentos."],"reglas":["El control de humo debe tener un límite máximo de espera/reintentos definido; no debe colgar el pipeline indefinidamente si la aplicación nunca arranca.","Fallar el pipeline explícitamente si el control de humo no obtiene una respuesta exitosa, no continuar como si nada.","Detener siempre el proceso o contenedor levantado al finalizar el control, tanto si tuvo éxito como si falló, para no dejar procesos huérfanos en el runner de CI."],"prompt":"Añade al pipeline de CI de este proyecto un paso de control de humo (smoke test) que se ejecute después de que el build tenga éxito. El paso debe: levantar la aplicación (o el contenedor que la sirve) en segundo plano, esperar con reintentos limitados (por ejemplo, hasta 30 intentos con una pequeña pausa entre cada uno, no una espera fija) a que responda, hacer una petición al endpoint de salud si existe o a la página principal si no, y verificar que el código de estado de la respuesta es el esperado (200 o el que corresponda). El paso debe fallar el pipeline explícitamente si no se obtiene respuesta dentro del límite de reintentos, y debe detener el proceso/contenedor levantado al finalizar, tanto si el control tuvo éxito como si falló."}},
  {"id":"sw74","catalogo":"software","grupo":"Calidad y pruebas","tema":"Pipelines de Integración Continua","titulo":"Muestra de forma objetiva y visible qué parte de tu código está realmente probado","beneficio":"Sin un reporte de cobertura visible, nadie sabe con certeza qué partes del código carecen de pruebas hasta que fallan; el agente configura la generación de reportes de cobertura compatibles con plataformas externas de calidad, para que el equipo (o un cliente) pueda verlo de forma objetiva.","alcance":"Configura la generación local de reportes de cobertura en un formato estándar exportable (por ejemplo, LCOV) y su integración con la plataforma de análisis externa elegida. No mejora por sí solo el porcentaje de cobertura (eso requiere escribir más pruebas) ni garantiza que un alto porcentaje de cobertura implique ausencia de bugs.","precio":1.99,"blueprint":{"quePuedeHacer":"Configura la herramienta de testing del proyecto para generar un reporte de cobertura en un formato estándar (LCOV u otro compatible), añade el paso correspondiente en el pipeline de CI para generarlo en cada ejecución, y configura la integración (mediante la acción o el paso oficial) con la plataforma externa de análisis de calidad elegida por el equipo.","modo":"Configuración de infraestructura de pruebas","pasos":["Confirmar el framework de testing en uso y su opción para generar reportes de cobertura en formato estándar.","Configurar el proyecto para que genere ese reporte en cada ejecución local de la suite.","Añadir el paso al pipeline de CI para generar el reporte durante cada ejecución automatizada.","Configurar la subida del reporte a la plataforma externa de análisis de calidad elegida, usando su acción o paso oficial.","Verificar que el reporte aparece correctamente en la plataforma externa tras una ejecución del pipeline."],"reglas":["No establecer un umbral mínimo de cobertura arbitrario para bloquear el pipeline sin que el equipo lo haya decidido explícitamente.","El reporte de cobertura debe generarse a partir de una ejecución real y completa de la suite, no de un valor simulado o parcial.","No exponer credenciales de la plataforma externa directamente en el archivo de configuración del pipeline; usar el mecanismo de secretos del motor de CI."],"prompt":"Configura la generación de reportes de cobertura de pruebas para este proyecto en formato LCOV (o el formato estándar que soporte el framework de testing en uso, revisa su documentación de configuración). Añade el paso correspondiente en el pipeline de CI para que el reporte se genere en cada ejecución de la suite completa. Configura la integración con [nombre de la plataforma externa de calidad, por ejemplo Codecov o SonarCloud] usando su acción o paso oficial para el motor de CI en uso, referenciando cualquier token necesario desde el mecanismo de secretos del pipeline, nunca escrito directamente en el archivo. No definas un umbral mínimo de cobertura que bloquee el pipeline a menos que te lo pida explícitamente. Verifica que la configuración es sintácticamente correcta."}},
  {"id":"sw75","catalogo":"software","grupo":"Calidad y pruebas","tema":"Pipelines de Integración Continua","titulo":"Deja que el propio historial de cambios decida el número de versión de tu próxima entrega","beneficio":"Decidir a mano si un cambio es un parche, una mejora o un cambio importante es subjetivo y a veces se olvida actualizar; el agente configura una herramienta que determina automáticamente el siguiente número de versión a partir del historial de commits, siguiendo una convención consistente.","alcance":"Automatiza el cálculo y la aplicación del número de versión según el versionado semántico, a partir de mensajes de commit que sigan una convención reconocible (por ejemplo, Conventional Commits). No corrige historiales de commits pasados que no siguieron ninguna convención, ni decide por sí solo si un cambio de comportamiento es realmente \"incompatible\" si el mensaje de commit no lo refleja con precisión.","precio":1.99,"blueprint":{"quePuedeHacer":"Configura una herramienta de versionado semántico automático (según el ecosistema del proyecto) que analiza los mensajes de commit desde la última versión publicada, determina si el conjunto de cambios corresponde a un incremento de parche, menor o mayor según la convención de commits usada, actualiza el número de versión y genera el registro de cambios correspondiente.","modo":"Automatización de versionado","pasos":["Confirmar si el proyecto ya sigue alguna convención de mensajes de commit (Conventional Commits u otra) y, si no, proponer adoptarla antes de automatizar el versionado.","Elegir e instalar la herramienta de versionado semántico automático adecuada al ecosistema del proyecto.","Configurar la herramienta para que analice los commits desde la última versión publicada.","Configurar la generación automática del registro de cambios a partir de esos mismos commits.","Integrar el paso de versionado en el pipeline de CI, en el punto donde se publica una nueva versión.","Probar el cálculo de versión en un escenario controlado antes de aplicarlo a una publicación real."],"reglas":["El cálculo de versión debe basarse exclusivamente en los mensajes de commit y su convención, no en una estimación subjetiva del agente sobre qué tan importante parece un cambio.","Si el historial de commits no sigue ninguna convención reconocible, señalarlo explícitamente en vez de forzar un cálculo de versión poco fiable.","No publicar automáticamente una versión mayor (que implica cambios incompatibles) sin que exista al menos un commit que lo declare explícitamente según la convención usada."],"prompt":"Revisa el historial de commits de este proyecto y confirma si sigue la convención de Conventional Commits (feat:, fix:, BREAKING CHANGE, etc.) u otra convención reconocible. Si no la sigue de forma consistente, indícalo antes de continuar. Si la sigue, configura una herramienta de versionado semántico automático adecuada al ecosistema del proyecto (por ejemplo, semantic-release si es Node.js) para que, a partir de los commits desde la última versión publicada, determine si corresponde un incremento de parche, menor o mayor, actualice el número de versión, y genere el registro de cambios correspondiente. Integra este paso en el pipeline de CI en el punto donde se publica una nueva versión, usando el mecanismo de secretos del pipeline para cualquier token de publicación necesario. Antes de aplicarlo a una publicación real, muestra qué versión calcularía a partir del historial actual, para validarlo."}},
  {"id":"sw76","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Gestión Avanzada de Git y Flujo de Trabajo","titulo":"Mensajes de commit que cuentan la historia real de cada cambio","beneficio":"Cuando alguien se pregunte seis meses después por qué se cambió algo, el historial de Git responde por sí solo, sin depender de localizar a quien hizo el cambio. Facilita generar changelogs y acelera la incorporación de nuevas personas al equipo.","alcance":"Redacta el mensaje a partir del diff en preparación (git diff --staged) en formato Conventional Commits. No decide qué archivos incluir en el commit ni sustituye la revisión humana: si el diff mezcla dos cambios sin relación, el mensaje también los mezclará.","precio":1.99,"blueprint":{"quePuedeHacer":"Lee la salida de git diff --staged (y git status) para identificar el tipo de cambio dominante (feat, fix, refactor, docs, test, chore, style, perf) y redacta un mensaje en formato Conventional Commits con encabezado imperativo, cuerpo opcional y notas de breaking change si detecta cambios de firma o API.","modo":"Gestión de versiones","pasos":["Ejecutar git status y git diff --staged para ver qué está preparado para el commit.","Clasificar el cambio dominante según el tipo de archivos y la naturaleza del diff.","Redactar el encabezado en formato tipo(alcance): descripción en modo imperativo y minúsculas.","Añadir un cuerpo opcional que explique el motivo del cambio cuando el encabezado no baste.","Marcar BREAKING CHANGE: en el pie si el diff modifica una firma pública, endpoint o esquema de datos."],"reglas":["Nunca inventar contexto que no esté en el diff; si el motivo no es evidente, dejarlo fuera del cuerpo.","Un commit, un mensaje: si el diff mezcla cambios sin relación, advertirlo y proponer dividir el commit.","Respetar siempre el formato tipo(alcance): descripción, sin mayúscula inicial ni punto final en el encabezado."],"prompt":"Actúa como responsable de mantener un historial de Git limpio en este repositorio. Ejecuta `git diff --staged` y `git status` para ver los cambios preparados. Redacta un mensaje de commit en formato Conventional Commits (tipo(alcance): descripción) basado exclusivamente en lo que aparece en el diff, sin inventar motivos que no estén reflejados en el código. Si detectas que el diff mezcla más de un cambio lógico sin relación entre sí, dímelo antes de proponer el mensaje y sugiere cómo dividirlo en commits separados. Si el cambio modifica una firma de función, un endpoint o un esquema de datos existente, añade una línea `BREAKING CHANGE:` explicando el impacto. Entrega el mensaje final listo para usar con `git commit -m`."}},
  {"id":"sw77","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Gestión Avanzada de Git y Flujo de Trabajo","titulo":"Pull requests que explican el impacto real del cambio, no solo el diff","beneficio":"Reduce las idas y vueltas en revisión porque quien revisa entiende de entrada qué cambió, por qué y qué mirar con más atención, en vez de reconstruir el contexto commit por commit.","alcance":"Analiza la rama (commits, diff y archivos tocados) para redactar la descripción y una guía de revisión. No conoce la intención de negocio si no está documentada en el repo, y no sustituye la revisión técnica humana.","precio":1.99,"blueprint":{"quePuedeHacer":"Compara la rama actual contra la rama base (git log base..HEAD, git diff base...HEAD) para agrupar los commits en un resumen coherente y señalar zonas del diff con mayor riesgo (lógica de negocio, migraciones, configuración de despliegue) como puntos de atención.","modo":"Gestión de versiones","pasos":["Identificar la rama base y ejecutar git log base..HEAD --oneline y git diff base...HEAD.","Resumir en una frase el objetivo general del cambio a partir de los commits.","Listar los archivos o módulos afectados agrupados por tipo de impacto.","Señalar zonas que un revisor debería mirar con más cuidado (migraciones, permisos, nuevas dependencias).","Redactar la descripción final con secciones Qué cambia, Por qué y Cómo probarlo."],"reglas":["No afirmar que el cambio soluciona o mejora algo si no puede verificarse en el diff o los tests.","Marcar siempre como punto de atención cualquier archivo de configuración de despliegue, migración o cambio de permisos.","Si no hay tests para una parte relevante del cambio, decirlo explícitamente en vez de omitirlo."],"prompt":"Voy a abrir un pull request desde la rama actual contra la rama principal. Ejecuta `git log main..HEAD --oneline` y `git diff main...HEAD` para analizar todos los commits y cambios de esta rama. Redacta la descripción del PR con estas secciones: 'Qué cambia' (resumen técnico de 3-5 líneas), 'Por qué' (motivo, basado solo en lo que puedas inferir de los commits, sin inventar contexto de negocio), 'Cómo probarlo' (pasos concretos, y si detectas partes del cambio sin cobertura de tests, dilo explícitamente) y 'Puntos de atención para el revisor' (archivos o zonas de riesgo: migraciones, configuración, nuevas dependencias, permisos). No exageres el impacto del cambio ni afirmes beneficios que no se puedan comprobar en el propio diff."}},
  {"id":"sw78","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Gestión Avanzada de Git y Flujo de Trabajo","titulo":"Conflictos de fusión resueltos sin perder ninguna de las dos versiones","beneficio":"Acelera una de las tareas más tediosas de Git —resolver conflictos línea a línea— dejando los archivos limpios y compilables, para que el equipo dedique su atención a decidir qué lógica debe prevalecer.","alcance":"Lee los marcadores de conflicto y propone una reconciliación de la lógica de ambos lados. No decide por sí solo cuál versión es la correcta cuando representan decisiones de producto contrapuestas: en ese caso presenta ambas opciones y la decisión final la toma una persona.","precio":1.99,"blueprint":{"quePuedeHacer":"Localiza los archivos con marcadores de conflicto tras un merge o rebase fallido, interpreta el código a ambos lados, detecta si los cambios son complementarios o contrapuestos, y en el primer caso produce el archivo final limpio; en el segundo, señala el conflicto real y pide una decisión.","modo":"Gestión de versiones","pasos":["Ejecutar git status para listar los archivos con conflictos sin resolver.","Localizar en cada archivo los bloques delimitados por <<<<<<<, ======= y >>>>>>>.","Determinar si ambos lados pueden coexistir o son mutuamente excluyentes.","Reconciliar y escribir la versión final del bloque, eliminando los marcadores.","Ejecutar la suite de tests relevante para confirmar que el archivo resuelto sigue siendo válido.","Marcar el archivo como resuelto con git add solo tras verificar que compila y los tests pasan."],"reglas":["Nunca resolver un conflicto eliminando silenciosamente la lógica de un lado sin señalarlo.","Si el conflicto refleja decisiones de producto o arquitectura distintas, no elegir unilateralmente: presentar ambas versiones y pedir confirmación.","No marcar un archivo como resuelto sin haber verificado antes que el código compila o pasa el linter."],"prompt":"Tengo conflictos de fusión sin resolver tras un `git merge`. Ejecuta `git status` para listar los archivos afectados y abre cada uno para localizar los bloques `<<<<<<<`/`=======`/`>>>>>>>`. Para cada conflicto: si los dos lados son cambios complementarios que pueden combinarse sin perder ninguna lógica, reconcílialos y deja el archivo limpio. Si los dos lados representan decisiones contrapuestas (por ejemplo, dos implementaciones distintas de la misma función), no elijas por tu cuenta: muéstrame ambas versiones lado a lado, explica en qué difieren y pregúntame cuál conservar antes de continuar. Cuando termines cada archivo, ejecuta el linter y los tests relacionados para confirmar que el resultado es válido antes de darlo por resuelto. No hagas `git add` de ningún archivo que no haya pasado esa verificación."}},
  {"id":"sw79","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Gestión Avanzada de Git y Flujo de Trabajo","titulo":"Un .gitignore que se adelanta a los archivos basura antes de que ensucien el repositorio","beneficio":"Evita el ciclo de subir por error carpetas de dependencias o archivos de entorno, manteniendo el historial de Git limpio sin que nadie tenga que acordarse de mantenerlo cada vez que se añade una herramienta nueva.","alcance":"Analiza el stack del proyecto para proponer y mantener un .gitignore adecuado. No puede sacar del historial archivos ya confirmados en commits anteriores ni detecta secretos ya filtrados: solo previene que vuelva a pasar hacia adelante.","precio":1.99,"blueprint":{"quePuedeHacer":"Inspecciona los archivos de configuración del proyecto para identificar qué carpetas y patrones son artefactos generados o locales (dependencias, builds, cachés, variables de entorno, archivos de IDE/SO) y compone o actualiza el .gitignore con esos patrones, evitando reglas genéricas que ya cubran algo distinto.","modo":"Gestión de versiones","pasos":["Detectar el stack del proyecto revisando package.json, lockfiles y configuración de build.","Comparar contra el .gitignore actual para ver qué patrones ya están cubiertos.","Proponer los patrones faltantes agrupados por categoría: dependencias, build, entorno, IDE/SO.","Verificar con git status que no queden archivos de esas categorías ya rastreados por error.","Actualizar el .gitignore y confirmar que git status deja de listar esas rutas."],"reglas":["No añadir patrones que excluyan código fuente o configuración necesaria, aunque coincidan por nombre con un patrón común.","Advertir explícitamente si algún archivo que debería ignorarse ya está rastreado en el historial, sin asumir que añadirlo al .gitignore lo elimina retroactivamente.","Mantener el .gitignore organizado por secciones comentadas en vez de una lista plana sin orden."],"prompt":"Revisa la estructura de este repositorio (package.json, lockfiles, configuración de build y de IDE presentes) y compárala con el archivo `.gitignore` actual. Identifica qué carpetas o patrones de archivos generados, temporales o locales no están cubiertos todavía (dependencias, artefactos de build, cachés, variables de entorno, archivos de sistema operativo o de editor) y propón las líneas que faltan, agrupadas por categoría con comentarios. Antes de aplicar el cambio, ejecuta `git status` y avísame si algún archivo que debería estar ignorado (por ejemplo `.env` o una carpeta de dependencias) ya está siendo rastreado por Git, porque en ese caso añadirlo al `.gitignore` no lo quita del historial y hace falta un paso adicional. No ignores ninguna carpeta que contenga código fuente propio del proyecto aunque su nombre coincida con un patrón habitual de build."}},
  {"id":"sw80","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Gestión Avanzada de Git y Flujo de Trabajo","titulo":"Historial de Git limpio y legible antes de que el equipo lo vea","beneficio":"Convierte una sucesión de commits de trabajo en progreso en una secuencia de cambios con sentido, para que el historial sirva de verdad como documentación del proyecto.","alcance":"Reordena y agrupa (squash) los commits locales que aún no se han compartido. No debe aplicarse sobre commits ya compartidos en una rama remota sin coordinación previa, porque reescribe el historial y puede romper el trabajo de quien ya se basó en esos commits.","precio":1.99,"blueprint":{"quePuedeHacer":"Revisa el historial local de una rama desde el punto donde diverge de la base, agrupa los commits que forman parte de un mismo cambio lógico y prepara un plan de rebase interactivo (squash/fixup) junto con el mensaje final propuesto para cada commit resultante.","modo":"Gestión de versiones","pasos":["Identificar el punto de divergencia con git merge-base y listar los commits desde ahí con git log --oneline.","Agrupar los commits que corresponden al mismo cambio lógico.","Proponer el plan de squash/fixup indicando qué commits combinar y en qué orden.","Redactar el mensaje final de cada commit resultante en formato Conventional Commits.","Confirmar que ninguno de los commits afectados ya fue publicado en una rama remota compartida."],"reglas":["Nunca proponer reescribir historial ya existente en una rama remota compartida sin advertir el riesgo y pedir confirmación.","Conservar la autoría original de los commits agrupados cuando la herramienta lo permita.","No combinar commits que correspondan a cambios lógicos distintos solo por estar próximos en el tiempo."],"prompt":"Estoy a punto de compartir esta rama y quiero limpiar el historial local antes. Ejecuta `git merge-base` contra la rama principal y lista con `git log --oneline` los commits desde el punto de divergencia. Agrupa los commits que pertenezcan al mismo cambio lógico (por ejemplo, un commit seguido de sus propias correcciones) y propón un plan de rebase interactivo indicando qué commits combinar (squash/fixup) y el mensaje final de cada commit resultante en formato Conventional Commits. Antes de tocar nada, confirma si alguno de estos commits ya fue empujado a una rama remota compartida con otras personas; si es así, avísame del riesgo de reescribir historial compartido y espera mi confirmación antes de continuar."}},
  {"id":"sw81","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Automatización de Tareas por Scripts de Terminal","titulo":"Un solo comando para levantar el entorno completo de desarrollo","beneficio":"Elimina la fricción de recordar los pasos de arranque al incorporar a alguien nuevo o al volver a un proyecto tras un tiempo: un único script encadena instalación, migraciones y arranque, con comprobaciones en cada paso.","alcance":"Escribe y mantiene scripts de despliegue local que encadenan pasos ya existentes del proyecto. No sustituye una herramienta de orquestación real para producción, y su fiabilidad depende de que los comandos individuales que encadena ya funcionen correctamente por separado.","precio":1.99,"blueprint":{"quePuedeHacer":"Inspecciona el package.json, los scripts de migración y la documentación existente para identificar la secuencia real de arranque y la convierte en un único script con comprobaciones de error en cada paso (por ejemplo, abortar si falta un archivo .env o si la migración falla).","modo":"Automatización de terminal","pasos":["Revisar package.json, README y scripts existentes para identificar los pasos actuales de arranque manual.","Detectar dependencias entre pasos (por ejemplo, la migración necesita variables de entorno cargadas primero).","Escribir el script encadenando los pasos con manejo de errores explícito en cada uno.","Añadir validaciones previas: archivos de configuración necesarios, puertos libres, versión de runtime esperada.","Probar el script en un entorno limpio para confirmar que falla de forma clara si falta un requisito."],"reglas":["El script debe detenerse y explicar el motivo ante el primer error, nunca continuar silenciosamente tras un paso fallido.","No incluir ningún paso destructivo sin una confirmación explícita o un flag separado para forzarlo.","Documentar en el propio script qué hace cada paso, para que no dependa de memorizar el orden."],"prompt":"Quiero un script de arranque local para este proyecto. Revisa el package.json, el README y cualquier script de migración o seed existente para entender los pasos manuales que hoy hacen falta para levantar el entorno de desarrollo desde cero (instalar dependencias, configurar variables de entorno, migrar la base de datos, arrancar el servidor). Escribe un script de shell (o un script de npm, según lo que use el proyecto) que encadene esos pasos con `set -e` o comprobaciones equivalentes, de modo que se detenga con un mensaje claro en el primer error en lugar de seguir adelante. Añade una validación inicial que compruebe que existen los archivos de configuración necesarios (por ejemplo `.env`) antes de continuar. No incluyas ningún paso que borre datos o sobrescriba configuración existente sin pedírmelo explícitamente aparte."}},
  {"id":"sw82","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Automatización de Tareas por Scripts de Terminal","titulo":"Limpieza de cachés y builds rotos sin adivinar qué carpeta borrar","beneficio":"Resuelve en un paso el clásico borrado y reinstalación completa cuando el entorno local se comporta de forma rara, sin tener que acordarse manualmente de cada carpeta de caché o build corrupta.","alcance":"Crea una rutina de purga que identifica y elimina cachés, carpetas de build y dependencias conocidas del stack. No diagnostica la causa raíz de por qué el entorno se rompió ni sustituye entender el problema si vuelve a repetirse tras cada purga.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta las rutas de caché y artefactos propias del stack del proyecto y compone un script de saneamiento que las elimina de forma segura, con una opción de solo mostrar qué se borraría antes de ejecutar el borrado real.","modo":"Automatización de terminal","pasos":["Identificar el stack y las herramientas usadas para conocer sus rutas de caché habituales.","Listar las carpetas y archivos candidatos a purga.","Escribir el script con un modo dry-run que solo liste lo que se eliminaría.","Añadir el modo de ejecución real, que borra y reinstala dependencias si corresponde.","Verificar tras la purga que el proyecto vuelve a arrancar correctamente."],"reglas":["Nunca borrar archivos fuera de las rutas de caché/build identificadas (nunca código fuente, configuración versionada o datos de base de datos).","Ofrecer siempre un modo de solo lectura antes de ejecutar el borrado real, salvo que se pida explícitamente saltarlo.","Si alguna ruta candidata no está claramente identificada como caché o artefacto generado, preguntar antes de incluirla."],"prompt":"El entorno local de este proyecto se está comportando de forma extraña (errores de módulos no encontrados, builds que no reflejan los cambios). Identifica el stack del proyecto y las rutas típicas de caché y artefactos generados (carpetas de dependencias, cachés de bundler, carpetas de build, cachés de test runner). Escribe un script de saneamiento con dos modos: uno de solo lectura que liste qué se borraría sin tocar nada, y otro que ejecute el borrado real y reinstale las dependencias después. No incluyas en el borrado nada que no sea claramente un artefacto generado o una caché: si tienes dudas sobre si una carpeta es segura de borrar, pregúntame antes de añadirla al script. Ejecuta primero el modo de solo lectura y muéstrame el resultado."}},
  {"id":"sw83","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Automatización de Tareas por Scripts de Terminal","titulo":"Módulos nuevos con toda su estructura lista en segundos, no en media hora","beneficio":"Estandariza cómo se crea cada pieza nueva del código para que todos los módulos sigan la misma convención desde el primer archivo, sin depender de que cada persona copie y adapte un módulo existente a mano.","alcance":"Genera plantillas de scaffolding a partir de un nombre, replicando la convención ya usada en el proyecto. No inventa una arquitectura nueva si el proyecto no tiene ya un patrón consistente que copiar, y el resultado siempre necesita revisión: da estructura y boilerplate, no la lógica de negocio específica.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza uno o varios módulos existentes representativos para inferir la convención de nombres, carpetas y estructura interna, y genera el conjunto equivalente de archivos para un módulo nuevo a partir del nombre proporcionado, sustituyendo referencias y manteniendo el mismo patrón de imports.","modo":"Automatización de terminal","pasos":["Elegir un módulo existente representativo como plantilla de referencia.","Identificar sus archivos (controlador, modelo, test, rutas) y la convención de nombres y carpetas usada.","Recibir el nombre del módulo nuevo a crear.","Generar cada archivo equivalente sustituyendo el nombre y ajustando las referencias internas.","Dejar marcadores o comentarios donde haga falta lógica de negocio específica que el scaffold no puede inferir."],"reglas":["No inventar una convención nueva si el proyecto ya tiene un patrón establecido: seguir siempre el ejemplo existente como fuente de verdad.","Dejar explícitamente señalado con un comentario o TODO cualquier punto donde el scaffold generó una plantilla vacía en vez de lógica real.","No sobrescribir archivos existentes si el nombre del módulo nuevo coincide por error con uno ya presente; avisar en ese caso."],"prompt":"Quiero crear un nuevo módulo llamado '[nombre del recurso]' siguiendo exactamente la misma estructura que el módulo existente '[nombre del módulo de referencia]' (mismo patrón de controlador, modelo, rutas y test). Analiza los archivos de ese módulo de referencia para entender la convención de nombres, carpetas e imports usada en este proyecto, y genera el conjunto equivalente de archivos para '[nombre del recurso]', sustituyendo los nombres y ajustando las referencias internas. Deja un comentario TODO en cada punto donde haga falta lógica de negocio específica que no puedas inferir del ejemplo. Si ya existe un archivo con ese nombre, dímelo antes de sobrescribir nada."}},
  {"id":"sw84","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Automatización de Tareas por Scripts de Terminal","titulo":"Copias de seguridad automáticas antes de cada migración arriesgada","beneficio":"Da una red de seguridad real antes de tocar el esquema de la base de datos local, para poder deshacer una migración fallida en minutos en vez de reconstruir los datos de prueba desde cero.","alcance":"Crea una tarea que extrae una copia rápida de la base de datos local antes de operaciones destructivas. No es una estrategia de backup de producción (sin retención, cifrado ni almacenamiento externo) y no verifica por sí sola que la copia sea restaurable: conviene probarlo al menos una vez de forma manual.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta el motor de base de datos usado en desarrollo y compone un comando de volcado que se ejecuta automáticamente antes de operaciones marcadas como destructivas, guardando la copia con marca de tiempo en una carpeta local excluida del control de versiones.","modo":"Automatización de terminal","pasos":["Identificar el motor y la cadena de conexión de la base de datos local a partir de la configuración del proyecto.","Componer el comando de volcado apropiado para ese motor.","Integrar el volcado como paso previo automático en los scripts que ejecutan migraciones o seeds destructivos.","Guardar cada copia con marca de tiempo en una carpeta dedicada, añadida al .gitignore.","Documentar el comando de restauración correspondiente junto a la copia."],"reglas":["La copia de seguridad debe ejecutarse siempre antes de la operación destructiva, nunca en paralelo ni después.","Nunca subir estas copias al control de versiones ni a ningún destino remoto sin que se pida explícitamente.","Si el comando de volcado falla, la operación destructiva que dependía de él debe detenerse en vez de continuar sin copia de respaldo."],"prompt":"Antes de ejecutar migraciones o seeds destructivos en mi base de datos local de desarrollo, quiero una copia de seguridad automática. Identifica el motor de base de datos y la configuración de conexión que usa este proyecto en desarrollo, y escribe un comando de volcado (dump) adecuado para ese motor. Intégralo como paso previo automático en el script que ejecuta las migraciones o seeds destructivos, guardando cada copia con marca de tiempo en una carpeta local que añadas al `.gitignore`. Si el volcado falla por cualquier motivo, el script debe detenerse ahí y no continuar con la operación destructiva. Documenta también el comando exacto para restaurar una de estas copias."}},
  {"id":"sw85","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Automatización de Tareas por Scripts de Terminal","titulo":"Código que no puede confirmarse si no pasa antes por linter y tests","beneficio":"Evita que errores evidentes lleguen siquiera a un commit, detectándolos en el momento local en vez de en la revisión de código o, peor, en producción.","alcance":"Configura hooks de pre-commit que ejecutan linter y un subconjunto rápido de tests antes de permitir el commit. No sustituye la suite completa de tests en CI y puede saltarse deliberadamente con flags del propio Git, así que es una primera línea de defensa, no una garantía.","precio":1.99,"blueprint":{"quePuedeHacer":"Instala y configura una herramienta de gestión de hooks de Git (como Husky) para ejecutar automáticamente el linter y un subconjunto acotado de tests relacionados con los archivos modificados en el hook pre-commit, bloqueando el commit si alguno falla.","modo":"Automatización de terminal","pasos":["Instalar la herramienta de gestión de hooks apropiada para el gestor de paquetes del proyecto.","Configurar el hook pre-commit para ejecutar el linter sobre los archivos en preparación.","Añadir la ejecución de un subconjunto rápido de tests relacionados con los archivos modificados.","Configurar el hook para bloquear el commit con un mensaje claro si el linter o los tests fallan.","Documentar cómo saltarse el hook de forma explícita para casos excepcionales."],"reglas":["El hook debe ejecutarse solo sobre los archivos en preparación (staged), no sobre todo el repositorio, para mantenerlo rápido.","Nunca desactivar el hook de forma permanente ni silenciosa: cualquier bypass debe quedar visible y ser decisión explícita de quien hace el commit.","Si el linter o los tests configurados tardan más de lo razonable, priorizar reducir el alcance del chequeo antes que eliminarlo."],"prompt":"Configura hooks de pre-commit en este repositorio para que no se pueda confirmar código que no pase el linter o los tests relacionados con los archivos modificados. Instala la herramienta de gestión de hooks adecuada para el gestor de paquetes que usa este proyecto y configura el hook `pre-commit` para: 1) ejecutar el linter solo sobre los archivos en preparación (staged), y 2) ejecutar únicamente los tests relacionados con esos archivos, no la suite completa. El hook debe bloquear el commit con un mensaje claro si algo falla. Documenta en un comentario o en el README cómo saltarse el hook con `--no-verify` para casos excepcionales, dejando claro que es una excepción puntual y no el flujo normal de trabajo."}},
  {"id":"sw86","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Control de Dependencias, Paquetes y Vulnerabilidades","titulo":"Actualizar dependencias sin sorpresas: verificación inmediata con tus propios tests","beneficio":"Permite mantener las dependencias al día sin el miedo habitual a romper algo desconocido, porque cada actualización se verifica de inmediato contra la suite de tests existente antes de darla por buena.","alcance":"Actualiza paquetes específicos (no todo el árbol a la vez) y ejecuta los tests tras cada actualización. La fiabilidad depende directamente de qué tan buena sea la cobertura de tests: una dependencia sin ningún test que la ejercite puede romperse sin que nada lo detecte.","precio":1.99,"blueprint":{"quePuedeHacer":"Actualiza uno o varios paquetes concretos a una versión objetivo, revisa el changelog disponible para identificar cambios de ruptura, ejecuta la suite de tests inmediatamente después de cada actualización y reporta el resultado antes de continuar con el siguiente paquete.","modo":"Control de dependencias","pasos":["Identificar la versión actual y la versión objetivo de cada paquete a actualizar.","Revisar el changelog o las notas de versión disponibles para detectar cambios de ruptura conocidos.","Actualizar el paquete de forma aislada, uno por vez.","Ejecutar la suite de tests completa y revisar el resultado.","Si los tests fallan, decidir entre revertir o corregir el uso de la API afectada, documentando la decisión.","Repetir con el siguiente paquete solo tras confirmar que el anterior quedó estable."],"reglas":["Nunca actualizar varios paquetes a la vez sin verificar cada uno por separado.","Si los tests fallan tras una actualización y no es evidente cómo corregirlo, revertir el paquete en vez de dejar el proyecto en un estado roto.","No dar por segura una actualización solo porque los tests pasan si el código que usa ese paquete no tiene cobertura: señalar ese riesgo explícitamente."],"prompt":"Quiero actualizar el paquete '[nombre del paquete]' a su [última versión menor / última versión disponible] en este proyecto. Antes de actualizar, revisa el changelog o las notas de versión del paquete entre la versión actual y la objetivo para identificar cambios que puedan romper compatibilidad. Actualiza solo ese paquete (no otros a la vez) y ejecuta inmediatamente después la suite de tests completa. Si algún test falla, analiza si el fallo está relacionado con la actualización; si lo está y la corrección es sencilla, propónmela, y si no es evidente, revierte el paquete a la versión anterior y explícame por qué. Si detectas que el código que usa este paquete no tiene tests que lo cubran, dímelo explícitamente aunque el resto de la suite pase."}},
  {"id":"sw87","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Control de Dependencias, Paquetes y Vulnerabilidades","titulo":"Vulnerabilidades de seguridad detectadas y priorizadas antes de que sean un incidente","beneficio":"Convierte la auditoría de seguridad de dependencias en un proceso recurrente y priorizado, atacando primero las vulnerabilidades críticas realmente explotables en vez de tratar todas las alertas por igual.","alcance":"Ejecuta las herramientas de auditoría del propio gestor de paquetes y prioriza qué actualizar según la severidad reportada. No sustituye un análisis de seguridad profesional ni garantiza ausencia de vulnerabilidades no reportadas todavía en las bases de datos públicas usadas.","precio":1.99,"blueprint":{"quePuedeHacer":"Ejecuta la herramienta de auditoría de vulnerabilidades del gestor de paquetes, interpreta el reporte agrupando los hallazgos por severidad y por si el paquete es dependencia directa o transitiva, y propone un plan de actualización empezando por las vulnerabilidades críticas en dependencias directas, verificando con tests tras cada cambio.","modo":"Control de dependencias","pasos":["Ejecutar la herramienta de auditoría de seguridad del gestor de paquetes del proyecto.","Agrupar los hallazgos por severidad y por si afectan a una dependencia directa o transitiva.","Priorizar las vulnerabilidades críticas y altas en dependencias directas como primer bloque de trabajo.","Comprobar si existe una actualización que resuelva la vulnerabilidad sin cambios de versión mayor incompatibles.","Aplicar la actualización y ejecutar los tests antes de pasar a la siguiente vulnerabilidad.","Documentar las vulnerabilidades que no se pudieron resolver para seguimiento posterior."],"reglas":["Priorizar siempre severidad crítica/alta en dependencias directas antes que severidad baja en dependencias transitivas.","No forzar una actualización a una versión mayor solo para resolver una vulnerabilidad sin verificar antes con tests.","Si una vulnerabilidad no tiene parche disponible todavía, documentarla como riesgo aceptado en vez de ignorarla silenciosamente."],"prompt":"Ejecuta la herramienta de auditoría de vulnerabilidades del gestor de paquetes de este proyecto (por ejemplo `npm audit` o el equivalente). Agrupa los resultados por severidad (crítica, alta, moderada, baja) y por si el paquete afectado es una dependencia directa o transitiva del proyecto. Propón un plan de actualización priorizando primero las vulnerabilidades críticas y altas en dependencias directas. Para cada una, comprueba si existe una actualización de parche o versión menor que la resuelva sin romper compatibilidad; aplícala y ejecuta la suite de tests antes de continuar con la siguiente. Si alguna vulnerabilidad solo se resuelve con un cambio de versión mayor que podría romper el proyecto, no la apliques automáticamente: dímelo y espera confirmación. Al final, dame una lista de las vulnerabilidades que quedaron sin resolver y por qué."}},
  {"id":"sw88","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Control de Dependencias, Paquetes y Vulnerabilidades","titulo":"Dependencias que pagas y ya no usa nadie, detectadas y fuera","beneficio":"Reduce la superficie de mantenimiento y el riesgo de seguridad del proyecto eliminando paquetes que siguen instalados pero que ningún archivo del código importa realmente.","alcance":"Compara los paquetes declarados contra los imports reales del código para señalar candidatos a huérfanos. Puede dar falsos positivos con paquetes usados de forma indirecta (plugins, imports dinámicos, scripts de CI), por lo que cada candidato debe confirmarse antes de eliminarlo.","precio":1.99,"blueprint":{"quePuedeHacer":"Recorre el árbol de imports del código fuente y lo compara contra la lista de dependencias declaradas en el manifiesto de paquetes, identificando paquetes sin ningún import directo detectado y distinguiendo cuando es posible las dependencias de código de las usadas solo en configuración o scripts de build.","modo":"Control de dependencias","pasos":["Extraer la lista completa de dependencias declaradas en el archivo de manifiesto de paquetes.","Recorrer el código fuente buscando todos los imports/requires reales.","Cruzar ambas listas para identificar paquetes declarados sin ningún import directo detectado.","Revisar manualmente cada candidato para descartar falsos positivos (configuración, CI, imports dinámicos, plugins).","Eliminar del manifiesto solo los paquetes confirmados y reinstalar para verificar que el proyecto sigue arrancando y pasando los tests."],"reglas":["No eliminar automáticamente ningún paquete solo por no aparecer en un import directo: siempre confirmar el uso indirecto antes.","Tratar por separado las dependencias de desarrollo de las de producción, porque su patrón de uso normal no siempre pasa por un import en el código de la aplicación.","Tras eliminar cualquier paquete, ejecutar la suite de tests y un arranque del proyecto para confirmar que nada dependía de él de forma no detectada."],"prompt":"Analiza este proyecto para encontrar dependencias declaradas en el archivo de manifiesto de paquetes que ya no se usan en el código. Extrae la lista completa de dependencias declaradas y recórrelas contra todos los imports/requires reales del código fuente. Para cada paquete que no aparezca en ningún import directo, revisa también si se usa en archivos de configuración, scripts de build/CI o mediante imports dinámicos antes de marcarlo como candidato a huérfano — no lo des por seguro solo con el cruce automático. Preséntame la lista final de candidatos confirmados, separando dependencias de producción y de desarrollo. Solo tras mi confirmación, elimínalos del manifiesto, reinstala dependencias y ejecuta la suite de tests para comprobar que el proyecto sigue funcionando."}},
  {"id":"sw89","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Control de Dependencias, Paquetes y Vulnerabilidades","titulo":"Lockfiles rotos tras una fusión, reparados sin apostar a ciegas","beneficio":"Resuelve uno de los conflictos de Git más frustrantes de reparar a mano —un lockfile inconsistente tras una mala fusión— sin recurrir a borrarlo y reinstalar todo a ciegas, que puede arrastrar cambios de versión no deseados.","alcance":"Repara y regenera la consistencia del lockfile tras un conflicto de fusión, alineándolo con el manifiesto de paquetes real. No decide qué versión de una dependencia debería usarse cuando dos ramas la fijaron en versiones distintas de forma deliberada: eso requiere confirmación humana.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta si el lockfile tiene marcadores de conflicto sin resolver o inconsistencias respecto al manifiesto, y lo regenera ejecutando la instalación con el gestor de paquetes correspondiente, comparando antes y después las versiones resultantes para señalar cualquier cambio de versión inesperado.","modo":"Control de dependencias","pasos":["Comprobar si el lockfile tiene marcadores de conflicto de Git sin resolver.","Si los tiene, eliminar el lockfile y regenerarlo desde cero con el gestor de paquetes correspondiente a partir del manifiesto ya fusionado.","Comparar las versiones resultantes contra las que tenía cada rama antes de la fusión.","Señalar cualquier dependencia que haya cambiado de versión mayor como resultado de la regeneración, para confirmación explícita.","Ejecutar la instalación limpia y la suite de tests para verificar que el resultado es funcional."],"reglas":["Nunca regenerar el lockfile a partir de un manifiesto que todavía tenga conflictos sin resolver: primero se resuelve el manifiesto, luego el lockfile.","Señalar explícitamente cualquier cambio de versión mayor que resulte de la regeneración antes de darla por buena.","No mezclar lockfiles de gestores de paquetes distintos tras la reparación."],"prompt":"El lockfile de este proyecto quedó con conflictos o inconsistencias tras una fusión de ramas. Primero confirma que el archivo de manifiesto de paquetes (package.json u equivalente) ya está resuelto sin marcadores de conflicto. Después, elimina el lockfile actual y regenéralo desde cero con el gestor de paquetes que usa este proyecto. Compara las versiones resultantes en el nuevo lockfile contra las que tenían ambas ramas antes de la fusión, y avísame explícitamente si alguna dependencia terminó en una versión mayor distinta a la que tenía cualquiera de las dos ramas. Ejecuta después una instalación limpia y la suite de tests para confirmar que todo funciona, y no dejes coexistir lockfiles de más de un gestor de paquetes en el repositorio."}},
  {"id":"sw90","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Control de Dependencias, Paquetes y Vulnerabilidades","titulo":"Cambiar de gestor de paquetes sin perder ni una versión por el camino","beneficio":"Permite adoptar un gestor de paquetes más rápido o más adecuado al equipo sin el riesgo de que las versiones instaladas cambien silenciosamente durante la migración, algo que de otro modo obligaría a volver a probar todo el proyecto a ciegas.","alcance":"Automatiza la migración del lockfile y la configuración entre gestores de paquetes compatibles, verificando que las versiones resueltas antes y después coincidan. No decide cuál gestor conviene adoptar, y no cubre configuración específica de cada herramienta (workspaces, scripts, hooks propios) sin intervención manual adicional.","precio":1.99,"blueprint":{"quePuedeHacer":"Toma el lockfile y manifiesto del gestor de origen, extrae las versiones exactas resueltas para cada dependencia, instala el gestor destino generando su propio lockfile, y compara las versiones resultantes contra las originales para confirmar equivalencia antes de eliminar los archivos del gestor anterior.","modo":"Control de dependencias","pasos":["Extraer del lockfile actual las versiones exactas resueltas de todas las dependencias directas.","Instalar el gestor de paquetes destino y generar su lockfile a partir del mismo manifiesto de paquetes.","Comparar las versiones resultantes en el nuevo lockfile contra las originales, dependencia por dependencia.","Señalar cualquier discrepancia de versión antes de continuar.","Migrar configuración específica del gestor anterior que no se traduzca automáticamente (scripts, workspaces, hooks).","Ejecutar la suite de tests completa con el nuevo gestor antes de eliminar los archivos del gestor anterior."],"reglas":["No eliminar el lockfile ni la configuración del gestor anterior hasta confirmar que la suite de tests pasa igual con el nuevo gestor.","Cualquier discrepancia de versión entre lockfiles debe reportarse explícitamente, nunca resolverse en silencio aceptando la versión que proponga el nuevo gestor.","Migrar la configuración específica del gestor anterior de forma explícita, sin asumir que el nuevo gestor la interpreta igual por defecto."],"prompt":"Quiero migrar este proyecto de [gestor de paquetes actual, p. ej. npm] a [gestor de paquetes destino, p. ej. pnpm]. Extrae del lockfile actual las versiones exactas resueltas de todas las dependencias directas. Instala el nuevo gestor de paquetes y genera su lockfile a partir del mismo package.json. Compara dependencia por dependencia las versiones del lockfile nuevo contra las del original y avísame de cualquier discrepancia antes de continuar. Revisa también si hay configuración específica del gestor actual (workspaces, scripts, hooks) que no se traduzca automáticamente al nuevo gestor, y migra esa configuración de forma explícita. Solo después de que la suite de tests completa pase igual con el nuevo gestor, elimina el lockfile y los archivos de configuración del gestor anterior."}},
  {"id":"sw91","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Extensibilidad Avanzada y Conectividad","titulo":"El esquema real de tu base de datos, consultado en vivo, no adivinado desde el código","beneficio":"Evita el desfase entre lo que el código cree que es el esquema de la base de datos y lo que realmente hay en el motor, algo que suele causar bugs difíciles de rastrear cuando las migraciones no se aplicaron por igual en todos los entornos.","alcance":"Se conecta directamente a un motor de base de datos accesible (típicamente local o de desarrollo) para inspeccionar tablas, columnas, índices y relaciones reales. Requiere credenciales con permisos de solo lectura como mínimo, y no debe apuntarse contra producción sin las mismas precauciones de acceso que cualquier otra herramienta con acceso directo a esos datos.","precio":1.99,"blueprint":{"quePuedeHacer":"Usa un cliente o conector del motor de base de datos correspondiente para ejecutar consultas de introspección de esquema directamente contra la instancia real, en lugar de inferir el esquema leyendo archivos de migración que podrían no reflejar el estado actual aplicado.","modo":"Conectividad MCP","pasos":["Confirmar la cadena de conexión y el nivel de permisos disponibles (idealmente solo lectura) para el entorno objetivo.","Conectarse al motor de base de datos mediante el cliente o conector configurado.","Ejecutar las consultas de introspección de esquema propias del motor (tablas, columnas, tipos, claves foráneas, índices).","Contrastar el esquema real obtenido contra lo que reflejan los archivos de migración o modelos del código.","Señalar cualquier discrepancia encontrada entre el esquema real y lo que el código asume."],"reglas":["Nunca ejecutar sentencias de escritura o modificación de esquema durante una tarea de inspección: solo consultas de lectura.","No conectarse a una base de datos de producción salvo que se indique explícitamente y con credenciales de acceso restringido.","Si se detecta una discrepancia entre el esquema real y las migraciones del código, reportarla en vez de asumir cuál versión es la correcta."],"prompt":"Conéctate a la base de datos de desarrollo de este proyecto usando la configuración de conexión ya definida (solo lectura) y ejecuta consultas de introspección de esquema para listar todas las tablas, sus columnas y tipos, las claves foráneas y los índices existentes. Compara ese esquema real contra lo que reflejan los archivos de migración y los modelos definidos en el código de este repositorio. Repórtame cualquier diferencia que encuentres (columnas que existen en la base de datos pero no en el código, o al revés, migraciones que parecen no haberse aplicado). No ejecutes ninguna sentencia que modifique datos o esquema, solo consultas de lectura."}},
  {"id":"sw92","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Extensibilidad Avanzada y Conectividad","titulo":"Tipos de frontend que se actualizan solos cuando cambia el backend","beneficio":"Elimina la clase de bugs donde el frontend sigue asumiendo una forma de datos que el backend ya cambió, generando automáticamente los tipos del cliente a partir del esquema real y vivo del backend en vez de mantenerlos escritos a mano y desincronizados.","alcance":"Genera o actualiza tipos en el frontend leyendo el esquema expuesto por el backend en tiempo real. Depende de que el backend exponga ese esquema de forma fiable y actualizada; si la documentación de la API está desactualizada respecto al código real, los tipos generados heredarán ese mismo desfase.","precio":1.99,"blueprint":{"quePuedeHacer":"Consulta la fuente de esquema en vivo del backend (endpoint de introspección GraphQL, especificación OpenAPI, o esquema de base de datos si aplica) y genera o regenera los tipos correspondientes en el frontend, señalando qué tipos cambiaron respecto a la versión anterior para que el equipo revise el impacto en el código que los consume.","modo":"Sincronización backend-frontend","pasos":["Identificar la fuente de esquema en vivo del backend ya disponible en el proyecto.","Consultar esa fuente para obtener el esquema actual.","Generar los tipos correspondientes en el frontend con la herramienta ya establecida para ello.","Comparar los tipos generados contra la versión anterior para identificar qué cambió.","Señalar en el código del frontend los puntos donde se usan los tipos que cambiaron, para revisión."],"reglas":["No sobrescribir tipos escritos manualmente en el frontend que no provengan de generación automática sin advertirlo primero.","Si la fuente de esquema del backend no responde o da un resultado inconsistente, no generar tipos a partir de una respuesta parcial: reportar el fallo en vez de continuar.","Señalar siempre los cambios de tipo que puedan romper compilación en el frontend antes de darlos por aplicados silenciosamente."],"prompt":"Este proyecto de frontend consume la API del backend cuyo esquema se expone en [endpoint de introspección GraphQL / especificación OpenAPI / ruta del esquema]. Consulta esa fuente de esquema en vivo y genera o actualiza los tipos correspondientes en el frontend usando la herramienta que ya esté configurada para ello en este proyecto. Compara los tipos generados contra la versión anterior y dime explícitamente qué campos se añadieron, se eliminaron o cambiaron de tipo. Para los cambios que puedan romper la compilación (campos eliminados o de tipo distinto), señala en qué archivos del frontend se usan esos tipos para que pueda revisarlos antes de dar la actualización por terminada."}},
  {"id":"sw93","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Extensibilidad Avanzada y Conectividad","titulo":"Cómo se comporta tu interfaz cuando el cliente tiene mala conexión, probado antes de que lo sufra él","beneficio":"Detecta a tiempo pantallas de carga que se quedan colgadas o formularios sin feedback, simulando condiciones de red lentas o inestables en desarrollo en vez de descubrirlo por la queja de un cliente con mala cobertura.","alcance":"Inyecta retrasos y condiciones de red degradadas controladas en el cliente local para observar el comportamiento de la interfaz. No reproduce todas las condiciones de red reales posibles y es una prueba exploratoria, no un reemplazo de monitoreo real de rendimiento en producción.","precio":1.99,"blueprint":{"quePuedeHacer":"Configura una simulación de red degradada (limitación de ancho de banda, latencia, fallos intermitentes) usando las herramientas de desarrollo del navegador o un proxy local, ejecuta los flujos críticos de la interfaz bajo esas condiciones y documenta los puntos donde falta feedback adecuado al usuario.","modo":"Simulación de red","pasos":["Definir los flujos críticos de la interfaz a probar.","Configurar la simulación de red degradada con las herramientas de desarrollo disponibles.","Ejecutar cada flujo bajo esas condiciones y observar el comportamiento de la interfaz.","Registrar los puntos donde falta feedback visual o donde la interfaz queda en un estado inconsistente.","Proponer mejoras concretas para cada punto detectado."],"reglas":["Las pruebas deben ejecutarse contra un entorno de desarrollo o pruebas, nunca simular condiciones degradadas contra la aplicación en producción real.","Reportar los hallazgos como observaciones concretas ligadas a un flujo y una condición de red específica, no como una valoración genérica.","No asumir que una interfaz que se comporta bien bajo una condición de red se comportará igual bajo todas las demás: documentar cada condición por separado."],"prompt":"Quiero evaluar cómo se comporta la interfaz de este proyecto bajo condiciones de red degradadas. Configura una simulación de red con latencia alta y ancho de banda limitado usando las herramientas de desarrollo del navegador (o un proxy local si es más adecuado para este proyecto). Ejecuta estos flujos críticos bajo esa simulación: [listar flujos, por ejemplo: envío del formulario de contacto, carga del listado principal, inicio de sesión]. Para cada flujo, documenta si la interfaz muestra un indicador de carga adecuado, si maneja bien un timeout, y si ofrece alguna forma de reintento cuando la petición falla o tarda demasiado. Preséntame los hallazgos flujo por flujo, indicando la condición de red exacta bajo la que se detectó cada problema, y propón una mejora concreta para cada uno."}},
  {"id":"sw94","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Extensibilidad Avanzada y Conectividad","titulo":"Entornos de prueba poblados con datos realistas en un solo paso","beneficio":"Permite probar el software con datos que se parecen a los reales desde el primer minuto tras clonar el proyecto o limpiar la base de datos, en vez de trabajar contra una base vacía que no revela cómo se comporta la interfaz con volumen o relaciones reales.","alcance":"Genera y ejecuta un script de seeding que puebla el entorno local con registros de prueba consistentes entre sí. No debe usarse jamás para poblar producción ni para generar datos que se hagan pasar por reales fuera de un contexto de desarrollo, y el realismo es solo apariencia superficial, no anonimización de datos reales.","precio":1.99,"blueprint":{"quePuedeHacer":"Inspecciona el esquema de datos del proyecto y genera un script de seeding que crea registros de prueba coherentes entre sí, respetando claves foráneas y restricciones, con valores variados y realistas en apariencia, ejecutable de forma repetible sin duplicar datos en ejecuciones sucesivas.","modo":"Automatización de terminal","pasos":["Revisar el esquema de datos para entender qué entidades necesitan poblarse y en qué orden por sus dependencias.","Definir la cantidad y variedad de registros de prueba necesarios para cada entidad.","Escribir el script de seeding respetando el orden de dependencias.","Hacer el script idempotente: que pueda ejecutarse varias veces sin duplicar registros ni violar restricciones de unicidad.","Ejecutar el script contra el entorno local y verificar que los datos generados respetan las relaciones esperadas."],"reglas":["El script debe ejecutarse únicamente contra entornos locales o de pruebas, y debe fallar de forma explícita si detecta que apunta a un entorno marcado como producción.","Los datos generados deben ser claramente ficticios, nunca datos reales enmascarados ni extraídos de ningún sistema con información real de clientes.","El script debe ser idempotente: ejecutarlo dos veces no debe duplicar registros ni romper restricciones de unicidad del esquema."],"prompt":"Necesito un script de seeding para poblar el entorno de desarrollo local de este proyecto con datos de prueba realistas. Revisa el esquema de datos (modelos, relaciones y restricciones) para identificar qué entidades hacen falta y en qué orden deben crearse según sus dependencias (por ejemplo, usuarios antes que sus pedidos). Genera un script que cree una cantidad razonable de registros variados y coherentes entre sí, usando datos claramente ficticios (nunca información real de clientes). Haz el script idempotente, de modo que ejecutarlo varias veces no duplique registros ni rompa restricciones de unicidad. Añade al inicio del script una comprobación que impida ejecutarlo si la conexión apunta a una base de datos marcada como producción."}},
  {"id":"sw95","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Extensibilidad Avanzada y Conectividad","titulo":"Barreras de accesibilidad detectadas en el código antes de que las encuentre un usuario","beneficio":"Reduce el riesgo de excluir a usuarios con discapacidad (y de incumplimiento normativo en mercados que lo exigen) detectando problemas de accesibilidad directamente en el código de la interfaz, antes de que lleguen a producción.","alcance":"Ejecuta linters y analizadores estáticos de accesibilidad sobre el código HTML/JSX para detectar incumplimientos verificables automáticamente. No sustituye una auditoría completa con usuarios reales o lector de pantalla: los análisis estáticos detectan una parte de los criterios WCAG, no todos, especialmente los que dependen del comportamiento dinámico o del contexto de uso real.","precio":1.99,"blueprint":{"quePuedeHacer":"Configura y ejecuta herramientas de análisis estático de accesibilidad sobre el código de la interfaz, agrupa los hallazgos por nivel de conformidad (A, AA, AAA) y por tipo de problema (semántica, contraste, foco, formularios), y prioriza las correcciones según severidad y facilidad de arreglo.","modo":"Auditoría de accesibilidad","pasos":["Configurar el linter o analizador estático de accesibilidad adecuado para el stack del proyecto.","Ejecutar el análisis sobre el código de la interfaz.","Agrupar los hallazgos por nivel de conformidad WCAG y por categoría.","Priorizar primero los incumplimientos de nivel A sobre los de AA o AAA.","Proponer la corrección concreta para cada hallazgo."],"reglas":["No afirmar que el proyecto cumple WCAG a partir solo de un análisis estático: reportar únicamente lo que la herramienta puede verificar y dejar explícito qué requiere verificación manual.","Priorizar siempre los incumplimientos de nivel A antes que los de AA o AAA, salvo que se indique otra prioridad.","No aplicar correcciones automáticas sin mostrar antes el cambio propuesto, porque algunas requieren criterio humano sobre el contenido real."],"prompt":"Configura y ejecuta un análisis estático de accesibilidad sobre el código de la interfaz de este proyecto (HTML/JSX), usando el linter o analizador de accesibilidad adecuado para el stack que usamos. Agrupa los resultados por nivel de conformidad WCAG (A, AA, AAA) y por tipo de problema (semántica, contraste, foco, formularios, roles ARIA). Empieza priorizando los incumplimientos de nivel A. Para cada hallazgo, propón la corrección concreta pero no la apliques directamente si requiere criterio sobre el contenido (por ejemplo, el texto de un atributo `alt`): en esos casos, muéstrame el punto exacto en el código y pídeme el contenido correcto. Al final, déjame claro qué aspectos de accesibilidad NO puede verificar este análisis estático y que requerirían una prueba manual o con lector de pantalla."}},
  {"id":"sw96","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Automatización Avanzada y Buenas Prácticas","titulo":"Notas de versión que tus usuarios entienden, generadas desde los commits técnicos","beneficio":"Convierte el historial técnico de commits en una lista de novedades que un usuario final puede leer y entender, sin que alguien del equipo tenga que traducir manualmente cada release a lenguaje no técnico.","alcance":"Genera un borrador de changelog orientado a usuario a partir del historial de commits entre dos versiones o tags. La calidad depende de qué tan descriptivos sean los commits originales; si el historial no sigue ninguna convención, el borrador necesitará más edición humana antes de publicarse.","precio":1.99,"blueprint":{"quePuedeHacer":"Compara dos tags o versiones del repositorio, agrupa los commits por tipo (funcionalidades nuevas, correcciones, cambios que rompen compatibilidad) y traduce cada entrada técnica a una frase en lenguaje de usuario final, omitiendo cambios puramente internos que no afectan la experiencia de quien usa el producto.","modo":"Automatización de terminal","pasos":["Identificar el rango de commits entre la versión anterior y la nueva.","Agrupar los commits por tipo según su prefijo de Conventional Commits o por inspección del mensaje.","Descartar del changelog de usuario los commits puramente internos que no cambian nada visible.","Traducir cada commit relevante a una frase breve en lenguaje no técnico.","Ordenar el resultado en secciones (Novedades, Correcciones, Cambios importantes) y presentarlo como borrador para revisión antes de publicar."],"reglas":["Nunca incluir en el changelog de usuario cambios puramente internos sin ningún efecto observable.","No traducir un commit técnico a una afirmación de beneficio que el commit no respalde.","Presentar siempre el resultado como borrador para revisión humana antes de publicarlo, nunca como changelog final listo para enviar."],"prompt":"Genera un borrador de changelog para usuarios finales comparando los commits entre las versiones [versión anterior] y [versión nueva] de este repositorio (`git log versión_anterior..versión_nueva`). Agrupa los commits relevantes en tres secciones: Novedades, Correcciones y Cambios importantes (breaking changes si los hay). Descarta cualquier commit que sea puramente interno (refactors, tests, cambios de configuración de CI) y no tenga ningún efecto visible para quien usa el producto. Traduce cada commit relevante a una frase breve en lenguaje no técnico, ciñéndote a lo que el commit realmente indica, sin inventar beneficios que no estén respaldados por el cambio. Entrégamelo como borrador: dejaré claro que necesita mi revisión antes de publicarlo."}},
  {"id":"sw97","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Automatización Avanzada y Buenas Prácticas","titulo":"Código que no se rompe en el Node o navegador que de verdad usan tus clientes","beneficio":"Evita el descubrimiento tardío en producción de que una característica no es compatible con la versión de Node o los navegadores que realmente usa la base de usuarios, revisándolo antes de publicar.","alcance":"Escanea el código y las dependencias contra el rango de versiones objetivo declarado. Depende de que el proyecto tenga declarado explícitamente su rango de compatibilidad; si no existe esa declaración, el primer paso es definirla junto con el equipo, no adivinarla.","precio":1.99,"blueprint":{"quePuedeHacer":"Lee la configuración de compatibilidad objetivo del proyecto, analiza el código fuente y las dependencias en busca de sintaxis o APIs no soportadas en ese rango, y reporta cada incompatibilidad encontrada junto con la alternativa compatible.","modo":"Control de dependencias","pasos":["Verificar que el proyecto declara explícitamente su rango de compatibilidad objetivo; si no lo declara, proponerlo antes de continuar.","Analizar el código fuente en busca de sintaxis o APIs del lenguaje no soportadas en ese rango.","Revisar las dependencias directas para verificar que también declaran compatibilidad con el mismo rango objetivo.","Reportar cada incompatibilidad encontrada junto con una alternativa compatible o un polyfill conocido.","Priorizar las incompatibilidades que afecten a rutas de código críticas sobre las de código raramente ejecutado."],"reglas":["No asumir un rango de compatibilidad objetivo si el proyecto no lo declara explícitamente: confirmarlo antes de analizar, no adivinarlo.","Reportar cada incompatibilidad con su ubicación exacta en el código, no como una advertencia genérica.","No aplicar automáticamente un polyfill o cambio de sintaxis sin mostrar antes el cambio propuesto."],"prompt":"Quiero verificar que este proyecto es compatible con el rango de versiones que declaramos soportar. Revisa primero si existe una declaración explícita de compatibilidad (el campo `engines` en package.json para Node, o la configuración de browserslist para navegadores); si no existe, dímelo antes de seguir. Con esa referencia, analiza el código fuente en busca de sintaxis o APIs no soportadas en ese rango, y revisa también si las dependencias directas declaran compatibilidad con el mismo rango. Repórtame cada incompatibilidad con el archivo y la línea exacta donde aparece, junto con una alternativa compatible o un polyfill conocido, sin aplicar el cambio automáticamente: quiero revisar cada propuesta antes de aceptarla."}},
  {"id":"sw98","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Automatización Avanzada y Buenas Prácticas","titulo":"Una revisión de código inflexible antes de subir nada, aunque nadie más lo mire","beneficio":"Actúa como un segundo par de ojos crítico sobre el propio trabajo antes de subirlo, detectando descuidos que son fáciles de pasar por alto cuando quien revisa es la misma persona que escribió el cambio.","alcance":"Revisa el conjunto acumulado de cambios de la sesión buscando problemas concretos y verificables. No sustituye la revisión de otra persona del equipo ni evalúa decisiones de diseño o arquitectura que requieren contexto de negocio que no está en el propio diff.","precio":1.99,"blueprint":{"quePuedeHacer":"Revisa el diff acumulado de toda la sesión de trabajo buscando patrones concretos de descuido —código de depuración, TODOs sin resolver, código comentado, archivos de configuración local o credenciales incluidos por error, inconsistencias de estilo— y presenta cada hallazgo con su ubicación exacta antes de dar el trabajo por listo para subir.","modo":"Auto-revisión","pasos":["Obtener el diff completo de la sesión respecto al punto de partida, no solo el último commit.","Buscar restos de depuración: logs temporales, código comentado, breakpoints.","Buscar comentarios TODO/FIXME añadidos en esta sesión que quedaron sin resolver.","Verificar que no se incluyeron archivos de configuración local, credenciales o datos sensibles por error.","Revisar consistencia de estilo y convenciones con el resto del código existente.","Presentar cada hallazgo con archivo y línea exacta, sin corregir nada automáticamente hasta recibir confirmación."],"reglas":["Revisar siempre el diff acumulado completo de la sesión, no solo el commit más reciente.","Nunca eliminar automáticamente algo que parezca código de depuración o un TODO sin mostrarlo antes.","Señalar con prioridad máxima cualquier posible credencial, clave o dato sensible detectado en el diff."],"prompt":"Antes de subir los cambios de esta sesión de trabajo, actúa como un revisor de código exigente y ajeno al cambio. Obtén el diff completo acumulado desde el inicio de la sesión (no solo el último commit) y revísalo buscando: restos de código de depuración (logs temporales, código comentado, breakpoints), comentarios TODO o FIXME que quedaron sin resolver, archivos de configuración local, claves o credenciales incluidos por error, e inconsistencias de estilo con el resto del código del proyecto. Preséntame cada hallazgo con el archivo y la línea exacta, sin corregir nada automáticamente. Si encuentras algo que parezca una credencial o dato sensible, señálalo como prioridad máxima al principio del reporte."}},
  {"id":"sw99","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Automatización Avanzada y Buenas Prácticas","titulo":"Los cuellos de botella reales de tu aplicación, medidos y no supuestos","beneficio":"Reemplaza la intuición sobre qué parte del código es lenta por mediciones concretas de tiempo de ejecución, evitando optimizar la parte equivocada mientras el cuello de botella real sigue sin tocarse.","alcance":"Instrumenta el código con marcas de tiempo de alta precisión alrededor de las funciones señaladas para medir su duración real. No optimiza el código por sí solo ni identifica cuellos de botella fuera del alcance instrumentado; da datos de partida, la decisión de qué optimizar sigue siendo del equipo.","precio":1.99,"blueprint":{"quePuedeHacer":"Añade marcas de tiempo de alta precisión alrededor de las funciones o bloques señalados como sospechosos, ejecuta el flujo relevante bajo condiciones representativas y reporta la duración medida de cada bloque instrumentado, señalando cuál consume la mayor proporción del tiempo total.","modo":"Instrumentación de rendimiento","pasos":["Identificar junto con el equipo qué funciones o bloques son sospechosos de ser el cuello de botella.","Instrumentar esos puntos con marcas de tiempo de alta precisión al inicio y al final de cada bloque.","Ejecutar el flujo relevante bajo condiciones representativas de uso real.","Recopilar las duraciones medidas de cada bloque instrumentado.","Reportar qué bloque consume la mayor proporción del tiempo total, con cifras concretas de esa ejecución.","Eliminar o desactivar la instrumentación temporal una vez recogidos los datos, si no está pensada para quedarse en producción."],"reglas":["Reportar únicamente las cifras medidas en la ejecución realizada, nunca extrapolar tiempos que no se hayan medido directamente.","Dejar explícito bajo qué condiciones se hizo la medición, porque el mismo código puede comportarse distinto bajo otras condiciones.","Si la instrumentación es solo temporal para el diagnóstico, retirarla del código antes de darlo por terminado, salvo que se pida dejarla como permanente."],"prompt":"Sospechamos que [nombre de la función o flujo] es lento, pero no tenemos datos concretos de dónde está el cuello de botella. Instrumenta con marcas de tiempo de alta precisión los bloques internos de [función/flujo] que consideres más probables (usa las APIs de medición de rendimiento disponibles en este entorno). Ejecuta el flujo con datos de un volumen representativo del uso real y recoge las duraciones medidas de cada bloque instrumentado. Repórtame qué bloque concreto consume la mayor proporción del tiempo total, con las cifras exactas de esta ejecución (no estimaciones), y bajo qué condiciones se hizo la medición. Al terminar, retira la instrumentación temporal del código a menos que te pida dejarla."}},
  {"id":"sw100","catalogo":"software","grupo":"Operaciones y seguridad","tema":"Automatización Avanzada y Buenas Prácticas","titulo":"Un resumen técnico del día: qué cambió, qué se probó y cómo seguir mañana","beneficio":"Evita perder tiempo cada mañana reconstruyendo mentalmente dónde se quedó el trabajo del día anterior, y facilita retomar (o traspasar a otra persona) una tarea a medio terminar con contexto real.","alcance":"Genera un resumen de cierre de sesión a partir de los cambios reales realizados. No puede documentar decisiones o razonamientos que no hayan quedado reflejados en el código, los commits o la propia conversación: si algo importante solo existió como pensamiento no verbalizado, el resumen no lo recogerá.","precio":1.99,"blueprint":{"quePuedeHacer":"Recopila el estado real de la sesión de trabajo (diff acumulado, resultado de la última ejecución de tests, commits realizados, tareas mencionadas como pendientes durante la conversación) y lo estructura en un resumen de traspaso con secciones claras: qué se modificó, qué se verificó, qué quedó pendiente y una sugerencia concreta de por dónde continuar.","modo":"Cierre de sesión","pasos":["Recopilar el diff acumulado de la sesión y los commits realizados.","Revisar el resultado de la última ejecución de tests disponible, o ejecutarla si no se ha corrido recientemente.","Identificar las tareas mencionadas como pendientes o inconclusas durante la sesión.","Redactar el resumen con secciones: Qué se modificó, Qué se verificó, Pendiente y Cómo continuar mañana.","Guardar el resumen en un lugar accesible para la siguiente sesión."],"reglas":["No afirmar que algo quedó probado o funciona si no hay una ejecución real de tests o una verificación concreta que lo respalde.","No inventar decisiones de diseño o razones que no se hayan discutido explícitamente durante la sesión.","La sección Cómo continuar mañana debe basarse en tareas realmente identificadas como pendientes, no en una lista genérica de buenas prácticas."],"prompt":"Cierra la sesión de trabajo de hoy con un resumen de traspaso. Recopila el diff acumulado de todos los cambios de esta sesión y los commits realizados. Ejecuta (o revisa el resultado más reciente de) la suite de tests y usa el resultado real, no una suposición. Repasa la conversación de esta sesión para identificar qué quedó explícitamente pendiente o a medio terminar. Redacta el resumen con estas secciones: 'Qué se modificó' (archivos y cambios concretos), 'Qué se verificó' (tests ejecutados y su resultado real), 'Pendiente' (tareas identificadas como inconclusas) y 'Cómo continuar mañana' (siguiente paso concreto basado en lo pendiente real, no en recomendaciones genéricas). Guarda este resumen en un archivo de notas del proyecto para que esté disponible al retomar el trabajo."}},
];
